	public bool TryGetFixtureWriteDiagnosticsForTesting(out FixtureWriteDiagnosticsSnapshot snapshot)
	{
		int expectedBeautyPixels = Math.Max(0, _filmWidth) * Math.Max(0, _filmHeight);
		int writtenOnce = 0;
		int unwritten = 0;
		int multiWritten = 0;
		int auditCount = Math.Min(expectedBeautyPixels, _beautyWriteCountsThisRun?.Length ?? 0);
		for (int i = 0; i < auditCount; i++)
		{
			int count = _beautyWriteCountsThisRun[i];
			if (count == 0) unwritten++;
			else if (count == 1) writtenOnce++;
			else multiWritten++;
		}
		if (auditCount < expectedBeautyPixels)
			unwritten += expectedBeautyPixels - auditCount;

		snapshot = new FixtureWriteDiagnosticsSnapshot(
			CountMarkedRows(_fixtureRowsStarted),
			CountMarkedRows(_fixtureRowsCompleted),
			CountMarkedRows(_fixtureRowsPartiallyWritten),
			CountMarkedRows(_fixtureRowsEarlyTerminated),
			_fixtureFinalHitPixelCountThisRun,
			_fixtureTraversalWritePixelCountThisRun,
			expectedBeautyPixels,
			writtenOnce,
			unwritten,
			multiWritten);
		return snapshot.RowsStarted > 0 ||
			snapshot.RowsCompleted > 0 ||
			snapshot.RowsPartiallyWritten > 0 ||
			snapshot.RowsEarlyTerminated > 0 ||
			snapshot.FinalHitPixelCount > 0 ||
			snapshot.TraversalWritePixelCount > 0 ||
			snapshot.BeautyPixelsWrittenOnce > 0 ||
			snapshot.BeautyPixelsUnwritten > 0 ||
			snapshot.BeautyPixelsMultiWritten > 0;
	}

	public bool TryGetFixtureTransportCoverageForTesting(out FixtureTransportCoverageSnapshot snapshot)
	{
		snapshot = default;
		if (!FixtureTransportClassificationEnabled ||
			_fixtureTransportClassificationImg == null ||
			_filmWidth <= 0 ||
			_filmHeight <= 0)
		{
			return false;
		}

		long geomHitPixels = 0;
		long portalHitPixels = 0;
		long throatEventPixels = 0;
		long throatEntryPixels = 0;
		long throatExitPixels = 0;
		long throatShellTransformPixels = 0;
		long throatInnerAbsorbPixels = 0;
		long backgroundHitPixels = 0;
		long escapedNoHitPixels = 0;
		long budgetExhaustedPixels = 0;
		long unclassifiedPixels = 0;
		long totalPixels = (long)_filmWidth * _filmHeight;

		for (int y = 0; y < _filmHeight; y++)
		{
			for (int x = 0; x < _filmWidth; x++)
			{
				string transportKind = ResolveFixtureTransportKindFromPixel(
					NormalizeFixtureTransportClassificationPixel(_fixtureTransportClassificationImg.GetPixel(x, y)));
				switch (transportKind)
				{
					case "geom_hit":
						geomHitPixels++;
						break;
					case "portal_hit":
						portalHitPixels++;
						break;
					case "throat_event":
						throatEventPixels++;
						break;
					case "throat_entry":
						throatEventPixels++;
						throatEntryPixels++;
						break;
					case "throat_exit":
						throatEventPixels++;
						throatExitPixels++;
						break;
					case "throat_shell_transform":
						throatEventPixels++;
						throatShellTransformPixels++;
						break;
					case "throat_inner_absorb":
						throatEventPixels++;
						throatInnerAbsorbPixels++;
						break;
					case "background_hit":
						backgroundHitPixels++;
						break;
					case "escaped_no_hit":
						escapedNoHitPixels++;
						break;
					case "budget_exhausted":
						budgetExhaustedPixels++;
						break;
					default:
						unclassifiedPixels++;
						break;
				}
			}
		}

		long classifiedPixels = totalPixels - unclassifiedPixels;
		double classifiedCoverageRatio = totalPixels > 0
			? (double)classifiedPixels / totalPixels
			: 0.0;
		bool hermeticRuleSatisfied =
			classifiedPixels == totalPixels &&
			escapedNoHitPixels == 0 &&
			budgetExhaustedPixels == 0 &&
			unclassifiedPixels == 0;
		string summary =
			$"geom={geomHitPixels}|portal={portalHitPixels}|throat={throatEventPixels}|" +
			$"t_entry={throatEntryPixels}|t_exit={throatExitPixels}|t_xform={throatShellTransformPixels}|t_absorb={throatInnerAbsorbPixels}|" +
			$"background={backgroundHitPixels}|escaped={escapedNoHitPixels}|budget={budgetExhaustedPixels}|" +
			$"cov={classifiedCoverageRatio.ToString("0.###", CultureInfo.InvariantCulture)}";

		snapshot = new FixtureTransportCoverageSnapshot(
			totalPixels,
			classifiedPixels,
			classifiedCoverageRatio,
			geomHitPixels,
			portalHitPixels,
			throatEventPixels,
			throatEntryPixels,
			throatExitPixels,
			throatShellTransformPixels,
			throatInnerAbsorbPixels,
			backgroundHitPixels,
			escapedNoHitPixels,
			budgetExhaustedPixels,
			unclassifiedPixels,
			hermeticRuleSatisfied,
			summary);
		return totalPixels > 0;
	}

	public bool TryGetFixtureThroatDepthForTesting(out FixtureThroatDepthSnapshot snapshot)
	{
		snapshot = default;
		if (_fixtureThroatInteractionCounts == null || _fixtureThroatInteractionCounts.Length == 0)
		{
			return false;
		}

		long throatPixels = 0;
		long interactionSum = 0;
		int maxInteractionCount = 0;
		long totalPixels = _fixtureThroatInteractionCounts.LongLength;
		for (int i = 0; i < _fixtureThroatInteractionCounts.Length; i++)
		{
			int count = _fixtureThroatInteractionCounts[i];
			if (count <= 0)
			{
				continue;
			}

			throatPixels++;
			interactionSum += count;
			if (count > maxInteractionCount)
			{
				maxInteractionCount = count;
			}
		}

		double meanInteractionCount = throatPixels > 0
			? (double)interactionSum / throatPixels
			: 0.0;
		string summary =
			$"throatPx={throatPixels}|max={maxInteractionCount}|mean={meanInteractionCount.ToString("0.###", CultureInfo.InvariantCulture)}";

		snapshot = new FixtureThroatDepthSnapshot(
			totalPixels,
			throatPixels,
			maxInteractionCount,
			meanInteractionCount,
			summary);
		return totalPixels > 0;
	}

	public bool TryGetFixtureCausalLedgerForTesting(out FixtureCausalLedgerSnapshot snapshot)
	{
		string observerCameraPath = string.Empty;
		ulong observerCameraInstanceId = 0;
		if (_cam != null && GodotObject.IsInstanceValid(_cam))
		{
			observerCameraPath = _cam.GetPath().ToString();
			observerCameraInstanceId = _cam.GetInstanceId();
		}

		double pathLengthMean = _fixtureCausalObservedPixelsThisRun > 0
			? _fixtureCausalPathLengthSumThisRun / _fixtureCausalObservedPixelsThisRun
			: 0.0;
		bool opticalPathTracked = _fixtureCausalObservedPixelsThisRun > 0;
		double? opticalPathLengthMean = opticalPathTracked
			? _fixtureCausalOpticalPathLengthSumThisRun / _fixtureCausalObservedPixelsThisRun
			: null;
		double? opticalPathLengthMax = opticalPathTracked
			? _fixtureCausalOpticalPathLengthMaxThisRun
			: null;
		long totalFaceHitPixels = _fixtureCausalFrontfaceHitPixelsThisRun + _fixtureCausalBackfaceHitPixelsThisRun;
		double frontfaceRatio = totalFaceHitPixels > 0
			? (double)_fixtureCausalFrontfaceHitPixelsThisRun / totalFaceHitPixels
			: 0.0;
		string summary =
			$"obs={_fixtureCausalObservedPixelsThisRun}|cross={_fixtureCausalBoundaryCrossingsTotalThisRun}|" +
			$"xform={_fixtureCausalSceneTransformEventsTotalThisRun}|entry={_fixtureCausalEntryEventsTotalThisRun}|exit={_fixtureCausalExitEventsTotalThisRun}|" +
			$"ambig={_fixtureCausalAmbiguousOrderingPixelsThisRun}|infer={_fixtureCausalThroatClassificationInferredPixelsThisRun}|" +
			$"contAttempt={_fixtureCausalContinuationAttemptedPixelsThisRun}|contSuccess={_fixtureCausalContinuationSuccessPixelsThisRun}|contFail={_fixtureCausalContinuationFailedPixelsThisRun}|" +
			$"front={_fixtureCausalFrontfaceHitPixelsThisRun}|back={_fixtureCausalBackfaceHitPixelsThisRun}|backOnly={_fixtureCausalBackfaceOnlyPixelsThisRun}|frontRatio={frontfaceRatio.ToString("0.######", CultureInfo.InvariantCulture)}|" +
			$"pathMean={pathLengthMean.ToString("0.###", CultureInfo.InvariantCulture)}|pathMax={_fixtureCausalPathLengthMaxThisRun.ToString("0.###", CultureInfo.InvariantCulture)}|" +
			$"oplMean={(opticalPathLengthMean.HasValue ? opticalPathLengthMean.Value.ToString("0.###", CultureInfo.InvariantCulture) : "na")}|oplMax={(opticalPathLengthMax.HasValue ? opticalPathLengthMax.Value.ToString("0.###", CultureInfo.InvariantCulture) : "na")}";

		snapshot = new FixtureCausalLedgerSnapshot(
			_fixtureCausalObservedPixelsThisRun,
			_fixtureCausalBoundaryCrossingsTotalThisRun,
			_fixtureCausalSceneTransformEventsTotalThisRun,
			_fixtureCausalEntryEventsTotalThisRun,
			_fixtureCausalExitEventsTotalThisRun,
			_fixtureCausalMaxTransformCountSeenThisRun,
			_fixtureCausalAmbiguousOrderingPixelsThisRun,
			_fixtureCausalThroatClassificationInferredPixelsThisRun,
			_fixtureCausalContinuationAttemptedPixelsThisRun,
			_fixtureCausalContinuationSuccessPixelsThisRun,
			_fixtureCausalContinuationFailedPixelsThisRun,
			_fixtureCausalFrontfaceHitPixelsThisRun,
			_fixtureCausalBackfaceHitPixelsThisRun,
			_fixtureCausalBackfaceOnlyPixelsThisRun,
			frontfaceRatio,
			pathLengthMean,
			_fixtureCausalPathLengthMaxThisRun,
			opticalPathLengthMean,
			opticalPathLengthMax,
			opticalPathTracked,
			phaseTracked: false,
			observerCameraPath,
			observerCameraInstanceId,
			summary);
		return _fixtureCausalObservedPixelsThisRun > 0 ||
			_fixtureCausalBoundaryCrossingsTotalThisRun > 0 ||
			_fixtureCausalSceneTransformEventsTotalThisRun > 0;
	}

