	private bool AdaptiveTelemetryEnvelopeScalingEnabledForCurrentRun()
	{
		return AdaptiveTelemetryEnvelopeScalingEnabled
			&& TelemetryHeatmapsEnabledForCurrentRun()
			&& _adaptiveEnvelopeMismatchPrior.Length == _filmWidth * _filmHeight;
	}

	private string ResolveAdaptiveEnvelopeThresholdStatisticToken()
	{
		string token = string.IsNullOrWhiteSpace(AdaptiveEnvelopeThresholdStatistic)
			? "mean"
			: AdaptiveEnvelopeThresholdStatistic.Trim().ToLowerInvariant();
		return token switch
		{
			"mean" => "mean",
			"p90" => "p90",
			"max" => "max",
			_ => "mean"
		};
	}

	private string ResolveAdaptiveEnvelopeControllerModeToken()
	{
		string token = string.IsNullOrWhiteSpace(AdaptiveEnvelopeControllerMode)
			? "three_state"
			: AdaptiveEnvelopeControllerMode.Trim().ToLowerInvariant();
		return token switch
		{
			"four_state_warm" => "four_state_warm",
			"four_state" => "four_state_warm",
			_ => "three_state"
		};
	}

	private string ResolveAdaptiveEnvelopePriorSourceToken()
	{
		string token = string.IsNullOrWhiteSpace(AdaptiveEnvelopePriorSource)
			? "same_pass"
			: AdaptiveEnvelopePriorSource.Trim().ToLowerInvariant();
		return token switch
		{
			"previous_pass" => "previous_pass",
			_ => "same_pass"
		};
	}

	private static bool ResolveBoolEnvOverride(string envName, bool fallback)
	{
		string env = System.Environment.GetEnvironmentVariable(envName) ?? string.Empty;
		if (string.IsNullOrWhiteSpace(env))
			return fallback;

		string token = env.Trim().ToLowerInvariant();
		return token switch
		{
			"1" or "true" or "on" or "yes" => true,
			"0" or "false" or "off" or "no" => false,
			_ => fallback
		};
	}

	private static int ResolveIntEnvOverride(string envName, int fallback, int min, int max)
	{
		string env = System.Environment.GetEnvironmentVariable(envName) ?? string.Empty;
		if (!int.TryParse(env, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsed))
			return Math.Clamp(fallback, min, max);

		return Math.Clamp(parsed, min, max);
	}

	private static float NormalizeAdaptiveEnvelopePercentileSetting(float percentile)
	{
		return Mathf.Clamp(percentile, 0f, 100f) / 100f;
	}

	private bool TryPopulateAdaptiveEnvelopeTelemetrySnapshot(
		float[] mismatchTarget,
		byte[] activeMaskTarget,
		out float globalP50,
		out float globalP90,
		out float globalRelaxedThreshold,
		out float globalWarmThreshold,
		out float globalHotThreshold)
	{
		globalP50 = 0.0f;
		globalP90 = 0.0f;
		globalRelaxedThreshold = 0.0f;
		globalWarmThreshold = 0.0f;
		globalHotThreshold = 0.0f;
		if (!AdaptiveTelemetryEnvelopeScalingEnabledForCurrentRun())
		{
			return false;
		}

		if (mismatchTarget == null || mismatchTarget.Length != _filmWidth * _filmHeight ||
			activeMaskTarget == null || activeMaskTarget.Length != _filmWidth * _filmHeight)
		{
			return false;
		}

		float[] queryMinusCurvature = BuildDerivedNormalizedDifferenceArray(_telemetryQueryCount, _telemetryCurvatureMean);
		if (queryMinusCurvature.Length != _filmWidth * _filmHeight)
		{
			return false;
		}

		float[] active = new float[queryMinusCurvature.Length];
		int activeCount = 0;
		for (int i = 0; i < queryMinusCurvature.Length; i++)
		{
			float mismatch = queryMinusCurvature[i];
			mismatchTarget[i] = mismatch;
			bool isActive = _telemetryPass1AcceptedSteps[i] > 0f || _telemetryCurvatureMean[i] > 0f || _telemetryQueryCount[i] > 0f;
			activeMaskTarget[i] = isActive ? (byte)1 : (byte)0;
			if (!isActive)
			{
				continue;
			}

			active[activeCount++] = mismatch;
		}

		if (activeCount <= 0)
		{
			return false;
		}

		Array.Sort(active, 0, activeCount);
		globalP50 = SampleSortedPercentile(active, activeCount, 0.50f);
		globalP90 = SampleSortedPercentile(active, activeCount, 0.90f);
		globalRelaxedThreshold = SampleSortedPercentile(active, activeCount, NormalizeAdaptiveEnvelopePercentileSetting(AdaptiveEnvelopeRelaxedThresholdPercentile));
		globalWarmThreshold = SampleSortedPercentile(active, activeCount, NormalizeAdaptiveEnvelopePercentileSetting(AdaptiveEnvelopeWarmThresholdPercentile));
		globalHotThreshold = SampleSortedPercentile(active, activeCount, NormalizeAdaptiveEnvelopePercentileSetting(AdaptiveEnvelopeHotThresholdPercentile));
		return true;
	}

	private void RefreshAdaptiveEnvelopeTelemetryPriors()
	{
		if (!TryPopulateAdaptiveEnvelopeTelemetrySnapshot(
			_adaptiveEnvelopeMismatchPrior,
			_adaptiveEnvelopeActiveMask,
			out _adaptiveEnvelopeGlobalQueryMinusCurvatureP50,
			out _adaptiveEnvelopeGlobalQueryMinusCurvatureP90,
			out _adaptiveEnvelopeGlobalRelaxedThreshold,
			out _adaptiveEnvelopeGlobalWarmThreshold,
			out _adaptiveEnvelopeGlobalHotThreshold))
		{
			_adaptiveEnvelopeGlobalQueryMinusCurvatureP50 = 0.0f;
			_adaptiveEnvelopeGlobalQueryMinusCurvatureP90 = 0.0f;
			_adaptiveEnvelopeGlobalRelaxedThreshold = 0.0f;
			_adaptiveEnvelopeGlobalWarmThreshold = 0.0f;
			_adaptiveEnvelopeGlobalHotThreshold = 0.0f;
		}
	}

	private void CaptureAdaptiveEnvelopePreviousTelemetrySnapshot()
	{
		if (TryPopulateAdaptiveEnvelopeTelemetrySnapshot(
			_adaptiveEnvelopePreviousMismatchPrior,
			_adaptiveEnvelopePreviousActiveMask,
			out _adaptiveEnvelopePreviousGlobalQueryMinusCurvatureP50,
			out _adaptiveEnvelopePreviousGlobalQueryMinusCurvatureP90,
			out _adaptiveEnvelopePreviousGlobalRelaxedThreshold,
			out _adaptiveEnvelopePreviousGlobalWarmThreshold,
			out _adaptiveEnvelopePreviousGlobalHotThreshold))
		{
			_adaptiveEnvelopePreviousSnapshotAvailable = true;
			return;
		}

		_adaptiveEnvelopePreviousSnapshotAvailable = false;
		_adaptiveEnvelopePreviousGlobalQueryMinusCurvatureP50 = 0.0f;
		_adaptiveEnvelopePreviousGlobalQueryMinusCurvatureP90 = 0.0f;
		_adaptiveEnvelopePreviousGlobalRelaxedThreshold = 0.0f;
		_adaptiveEnvelopePreviousGlobalWarmThreshold = 0.0f;
		_adaptiveEnvelopePreviousGlobalHotThreshold = 0.0f;
	}

	private void RecordAdaptiveEnvelopePriorFallback(string reason)
	{
		_adaptiveEnvelopePriorFallbackBehaviorThisRun = "neutral";
		_adaptiveEnvelopePriorFallbackCountThisRun++;
		if (string.Equals(reason, "snapshot_unavailable", StringComparison.Ordinal))
		{
			_adaptiveEnvelopePriorSnapshotUnavailableFallbackCountThisRun++;
			if (!_adaptiveEnvelopePriorSnapshotUnavailableLoggedThisRun)
			{
				_adaptiveEnvelopePriorSnapshotUnavailableLoggedThisRun = true;
				GD.Print("[AdaptiveEnvelope] prior_source=previous_pass fallback=neutral reason=snapshot_unavailable");
			}
			return;
		}

		if (string.Equals(reason, "insufficient_prior_samples", StringComparison.Ordinal))
		{
			_adaptiveEnvelopePriorInsufficientDataFallbackCountThisRun++;
			if (!_adaptiveEnvelopePriorInsufficientDataLoggedThisRun)
			{
				_adaptiveEnvelopePriorInsufficientDataLoggedThisRun = true;
				GD.Print("[AdaptiveEnvelope] prior_source=previous_pass fallback=neutral reason=insufficient_prior_samples");
			}
		}
	}

	private enum AdaptiveEnvelopeRegime
	{
		Hot = 0,
		Warm = 1,
		Neutral = 2,
		Relaxed = 3
	}

	private float ComputeAdaptiveEnvelopeScaleForRect(int xStart, int xEndExclusive, int yStart, int yEndExclusive, float baseScale)
	{
		float baseClamped = Mathf.Clamp(baseScale, 0.65f, 1.1f);
		if (!AdaptiveTelemetryEnvelopeScalingEnabledForCurrentRun())
		{
			return baseClamped;
		}

		int x0 = Math.Max(0, xStart);
		int y0 = Math.Max(0, yStart);
		int x1 = Math.Min(_filmWidth, xEndExclusive);
		int y1 = Math.Min(_filmHeight, yEndExclusive);
		if (x0 >= x1 || y0 >= y1)
		{
			return baseClamped;
		}

		string priorSourceToken = ResolveAdaptiveEnvelopePriorSourceToken();
		float[] mismatchPrior = _adaptiveEnvelopeMismatchPrior;
		byte[] activeMask = _adaptiveEnvelopeActiveMask;
		float globalP50 = _adaptiveEnvelopeGlobalQueryMinusCurvatureP50;
		float globalP90 = _adaptiveEnvelopeGlobalQueryMinusCurvatureP90;
		float globalRelaxedThreshold = _adaptiveEnvelopeGlobalRelaxedThreshold;
		float globalWarmThreshold = _adaptiveEnvelopeGlobalWarmThreshold;
		float globalHotThreshold = _adaptiveEnvelopeGlobalHotThreshold;
		if (priorSourceToken == "previous_pass")
		{
			if (!_adaptiveEnvelopePreviousSnapshotAvailable)
			{
				RecordAdaptiveEnvelopePriorFallback("snapshot_unavailable");
				return 1.0f;
			}

			mismatchPrior = _adaptiveEnvelopePreviousMismatchPrior;
			activeMask = _adaptiveEnvelopePreviousActiveMask;
			globalP50 = _adaptiveEnvelopePreviousGlobalQueryMinusCurvatureP50;
			globalP90 = _adaptiveEnvelopePreviousGlobalQueryMinusCurvatureP90;
			globalRelaxedThreshold = _adaptiveEnvelopePreviousGlobalRelaxedThreshold;
			globalWarmThreshold = _adaptiveEnvelopePreviousGlobalWarmThreshold;
			globalHotThreshold = _adaptiveEnvelopePreviousGlobalHotThreshold;
		}

		double mismatchSum = 0.0;
		float mismatchMax = float.NegativeInfinity;
		float[] localMismatch = new float[Math.Max(1, (x1 - x0) * (y1 - y0))];
		int activeCount = 0;
		for (int y = y0; y < y1; y++)
		{
			int rowBase = y * _filmWidth;
			for (int x = x0; x < x1; x++)
			{
				int pi = rowBase + x;
				if (activeMask[pi] == 0)
				{
					continue;
				}

				float mismatchValue = mismatchPrior[pi];
				mismatchSum += mismatchValue;
				if (mismatchValue > mismatchMax)
				{
					mismatchMax = mismatchValue;
				}
				localMismatch[activeCount] = mismatchValue;
				activeCount++;
			}
		}

		if (activeCount < 4)
		{
			if (priorSourceToken == "previous_pass")
			{
				RecordAdaptiveEnvelopePriorFallback("insufficient_prior_samples");
				return 1.0f;
			}

			return baseClamped;
		}

		string statisticToken = ResolveAdaptiveEnvelopeThresholdStatisticToken();
		string controllerModeToken = ResolveAdaptiveEnvelopeControllerModeToken();
		float mismatch = statisticToken switch
		{
			"p90" => ComputeActivePercentile(localMismatch, activeCount, 0.90f),
			"max" => mismatchMax,
			_ => (float)(mismatchSum / activeCount)
		};
		AdaptiveEnvelopeRegime regime = AdaptiveEnvelopeRegime.Neutral;
		float localScale = Mathf.Clamp(AdaptiveEnvelopeNeutralScale, 0.1f, 2.0f);
		if (controllerModeToken == "four_state_warm")
		{
			float relaxedThreshold = globalRelaxedThreshold;
			float warmThreshold = Math.Max(globalRelaxedThreshold, globalWarmThreshold);
			float hotThreshold = Math.Max(warmThreshold, globalHotThreshold);
			if (mismatch > hotThreshold)
			{
				regime = AdaptiveEnvelopeRegime.Hot;
				localScale = Mathf.Clamp(AdaptiveEnvelopeTightScale, 0.1f, 2.0f);
			}
			else if (mismatch > warmThreshold)
			{
				regime = AdaptiveEnvelopeRegime.Warm;
				localScale = Mathf.Clamp(AdaptiveEnvelopeWarmScale, 0.1f, 2.0f);
			}
			else if (mismatch < relaxedThreshold)
			{
				regime = AdaptiveEnvelopeRegime.Relaxed;
				localScale = Mathf.Clamp(AdaptiveEnvelopeRelaxedScale, 0.1f, 2.0f);
			}
		}
		else if (mismatch > globalP90)
		{
			regime = AdaptiveEnvelopeRegime.Hot;
			localScale = Mathf.Clamp(AdaptiveEnvelopeTightScale, 0.1f, 2.0f);
		}
		else if (mismatch < globalP50)
		{
			regime = AdaptiveEnvelopeRegime.Relaxed;
			localScale = Mathf.Clamp(AdaptiveEnvelopeRelaxedScale, 0.1f, 2.0f);
		}

		float clampedScale = Mathf.Clamp(localScale, 0.65f, 1.1f);
		RecordAdaptiveEnvelopeScaleSample(clampedScale, regime);
		return clampedScale;
	}

	private float[] BuildAdaptiveEnvelopeScaleBySubtileForBand(int yStart, int bandHeight, float baseScale)
	{
		float[] scales = new float[Math.Max(0, _tileMetricCurrentSubtileCount)];
		if (scales.Length == 0)
		{
			return scales;
		}

		float defaultScale = Mathf.Clamp(baseScale, 0.65f, 1.1f);
		for (int i = 0; i < scales.Length; i++)
		{
			scales[i] = defaultScale;
		}

		if (!AdaptiveTelemetryEnvelopeScalingEnabledForCurrentRun())
		{
			return scales;
		}

		float passProgress = _filmHeight > 0 ? Mathf.Clamp((float)yStart / _filmHeight, 0f, 1f) : 0f;
		if (passProgress < 0.25f)
		{
			return scales;
		}

		RefreshAdaptiveEnvelopeTelemetryPriors();
		int yEnd = Math.Min(_filmHeight, yStart + Math.Max(1, bandHeight));
		for (int subtileIndex = 0; subtileIndex < scales.Length; subtileIndex++)
		{
			int subtileXStart = subtileIndex * _tileMetricCurrentSubtileWidth;
			int subtileXEnd = Math.Max(0, Math.Min(_filmWidth, subtileXStart + _tileMetricCurrentSubtileWidth));
			scales[subtileIndex] = ComputeAdaptiveEnvelopeScaleForRect(subtileXStart, subtileXEnd, yStart, yEnd, baseScale);
		}

		return scales;
	}

	private void RecordAdaptiveEnvelopeScaleSample(float scale, AdaptiveEnvelopeRegime regime)
	{
		float clamped = Mathf.Clamp(scale, 0.65f, 1.1f);
		if (_adaptiveEnvelopeScaleCountThisRun <= 0)
		{
			_adaptiveEnvelopeScaleMinThisRun = clamped;
			_adaptiveEnvelopeScaleMaxThisRun = clamped;
			_adaptiveEnvelopeScaleSumThisRun = clamped;
			_adaptiveEnvelopeScaleCountThisRun = 1;
		}
		else
		{
			_adaptiveEnvelopeScaleMinThisRun = Math.Min(_adaptiveEnvelopeScaleMinThisRun, clamped);
			_adaptiveEnvelopeScaleMaxThisRun = Math.Max(_adaptiveEnvelopeScaleMaxThisRun, clamped);
			_adaptiveEnvelopeScaleSumThisRun += clamped;
			_adaptiveEnvelopeScaleCountThisRun++;
		}

		switch (regime)
		{
			case AdaptiveEnvelopeRegime.Hot:
				_adaptiveEnvelopeTightCountThisRun++;
				break;
			case AdaptiveEnvelopeRegime.Warm:
				_adaptiveEnvelopeWarmCountThisRun++;
				break;
			case AdaptiveEnvelopeRegime.Relaxed:
				_adaptiveEnvelopeRelaxedCountThisRun++;
				break;
			default:
				_adaptiveEnvelopeNeutralCountThisRun++;
				break;
		}

		int histIndex;
		if (clamped < 0.75f) histIndex = 0;
		else if (clamped < 0.85f) histIndex = 1;
		else if (clamped < 0.95f) histIndex = 2;
		else if (clamped < 1.025f) histIndex = 3;
		else histIndex = 4;
		if ((uint)histIndex < (uint)_adaptiveEnvelopeScaleHistogram.Length)
		{
			_adaptiveEnvelopeScaleHistogram[histIndex]++;
		}
	}

	private static float SampleSortedPercentile(float[] sorted, int count, float percentile)
	{
		if (sorted == null || count <= 0)
		{
			return 0f;
		}

		float clampedPercentile = Mathf.Clamp(percentile, 0f, 1f);
		int index = Math.Clamp((int)MathF.Round((count - 1) * clampedPercentile), 0, count - 1);
		return sorted[index];
	}

	private static float ComputeActivePercentile(float[] values, int count, float percentile)
	{
		if (values == null || count <= 0)
		{
			return 0f;
		}

		float[] copy = new float[count];
		Array.Copy(values, copy, count);
		Array.Sort(copy, 0, count);
		return SampleSortedPercentile(copy, count, percentile);
	}

	private void AccumulateTelemetryBlock(float[] target, int x, int y, int stride, float value)
	{
		if (target == null || target.Length == 0 || value <= 0f || _filmWidth <= 0 || _filmHeight <= 0)
		{
			return;
		}

		int safeStride = Math.Max(1, stride);
		int yMax = Math.Min(_filmHeight, y + safeStride);
		int xMax = Math.Min(_filmWidth, x + safeStride);
		for (int yy = Math.Max(0, y); yy < yMax; yy++)
		{
			int rowBase = yy * _filmWidth;
			for (int xx = Math.Max(0, x); xx < xMax; xx++)
			{
				target[rowBase + xx] += value;
			}
		}
	}

	private bool TelemetryHeatmapsEnabledForCurrentRun()
	{
		return ExportTelemetryHeatmaps
			&& _filmWidth > 0
			&& _filmHeight > 0
			&& _telemetryPass1AcceptedSteps.Length == _filmWidth * _filmHeight
			&& _telemetryCandidateCount.Length == _filmWidth * _filmHeight
			&& _telemetryQueryCount.Length == _filmWidth * _filmHeight
			&& _telemetryResolveCount.Length == _filmWidth * _filmHeight
			&& _telemetryCurvatureMax.Length == _filmWidth * _filmHeight
			&& _telemetryCurvatureMean.Length == _filmWidth * _filmHeight
			&& _telemetryDkMax.Length == _filmWidth * _filmHeight
			&& _telemetryD2kMax.Length == _filmWidth * _filmHeight
			&& _telemetryTurnSum.Length == _filmWidth * _filmHeight
			&& _telemetryTurnMax.Length == _filmWidth * _filmHeight;
	}

	private bool DomainTelemetryEnabledForCurrentRun()
	{
		return EnableDomainTelemetry
			&& _filmWidth > 0
			&& _filmHeight > 0
			&& DomainIdBuffer.Length == _filmWidth * _filmHeight
			&& DomainConfidenceBuffer.Length == _filmWidth * _filmHeight
			&& BoundaryConfidenceBuffer.Length == _filmWidth * _filmHeight
			&& SelectionFlipBuffer.Length == _filmWidth * _filmHeight
			&& NormalDiscontinuityBuffer.Length == _filmWidth * _filmHeight
			&& _domainResolverComparedBuffer.Length == _filmWidth * _filmHeight
			&& _domainResolverChangedBuffer.Length == _filmWidth * _filmHeight
			&& _domainResolverColliderChangedBuffer.Length == _filmWidth * _filmHeight
			&& _domainResolverDistanceChangedBuffer.Length == _filmWidth * _filmHeight
			&& _domainResolverDistanceDeltaBuffer.Length == _filmWidth * _filmHeight
			&& _domainResolverScoreDeltaBuffer.Length == _filmWidth * _filmHeight
			&& _domainResolverScoreAvailableBuffer.Length == _filmWidth * _filmHeight
			&& _pixelDomainStates.Length == _filmWidth * _filmHeight;
	}

	private bool TryGetTelemetrySource(TelemetryHeatmapKind kind, out float[] source, out string key)
	{
		source = null;
		key = string.Empty;
		switch (kind)
		{
			case TelemetryHeatmapKind.Work:
				key = "work";
				return TelemetryHeatmapsEnabledForCurrentRun();
			case TelemetryHeatmapKind.Candidates:
				source = _telemetryCandidateCount;
				key = "candidates";
				break;
			case TelemetryHeatmapKind.Query:
				source = _telemetryQueryCount;
				key = "query";
				break;
			case TelemetryHeatmapKind.Resolve:
				source = _telemetryResolveCount;
				key = "resolve";
				break;
			case TelemetryHeatmapKind.Pass1Steps:
				source = _telemetryPass1AcceptedSteps;
				key = "pass1_steps";
				break;
			case TelemetryHeatmapKind.CurvatureMax:
				source = _telemetryCurvatureMax;
				key = "curvature_max";
				break;
			case TelemetryHeatmapKind.CurvatureMean:
				source = _telemetryCurvatureMean;
				key = "curvature_mean";
				break;
			case TelemetryHeatmapKind.DkMax:
				source = _telemetryDkMax;
				key = "dk_max";
				break;
			case TelemetryHeatmapKind.D2kMax:
				source = _telemetryD2kMax;
				key = "d2k_max";
				break;
			case TelemetryHeatmapKind.TurnSum:
				source = _telemetryTurnSum;
				key = "turn_sum";
				break;
			case TelemetryHeatmapKind.TurnMax:
				source = _telemetryTurnMax;
				key = "turn_max";
				break;
			case TelemetryHeatmapKind.WorkMinusCurvature:
				key = "work_minus_curvature";
				return TelemetryHeatmapsEnabledForCurrentRun();
			case TelemetryHeatmapKind.QueryMinusCurvature:
				key = "query_minus_curvature";
				return TelemetryHeatmapsEnabledForCurrentRun();
			case TelemetryHeatmapKind.Efficiency:
				key = "efficiency";
				return TelemetryHeatmapsEnabledForCurrentRun();
			default:
				return false;
		}

		return TelemetryHeatmapsEnabledForCurrentRun() && source != null;
	}

	private bool TryGetDomainTelemetrySource(DomainTelemetryMapKind kind, out float[] source, out string key)
	{
		source = null;
		key = string.Empty;
		if (!DomainTelemetryEnabledForCurrentRun())
		{
			return false;
		}

		switch (kind)
		{
			case DomainTelemetryMapKind.DomainId:
				source = DomainIdBuffer;
				key = "domain_id";
				break;
			case DomainTelemetryMapKind.DomainConfidence:
				source = DomainConfidenceBuffer;
				key = "domain_confidence";
				break;
			case DomainTelemetryMapKind.BoundaryConfidence:
				source = BoundaryConfidenceBuffer;
				key = "boundary_confidence";
				break;
			case DomainTelemetryMapKind.SelectionFlip:
				source = SelectionFlipBuffer;
				key = "selection_flip";
				break;
			case DomainTelemetryMapKind.NormalDiscontinuity:
				source = NormalDiscontinuityBuffer;
				key = "normal_discontinuity";
				break;
			case DomainTelemetryMapKind.StepConvergenceConfidence:
				source = StepConvergenceConfidenceBuffer;
				key = "step_convergence_confidence";
				break;
			case DomainTelemetryMapKind.StepSensitivity:
				source = StepSensitivityBuffer;
				key = "step_sensitivity";
				break;
			case DomainTelemetryMapKind.PrecisionRequired:
				source = PrecisionRequiredBuffer;
				key = "precision_required";
				break;
			case DomainTelemetryMapKind.ProbeHitDistanceDelta:
				source = ProbeHitDistanceDeltaBuffer;
				key = "probe_hit_distance_delta";
				break;
			case DomainTelemetryMapKind.ProbeNormalDelta:
				source = ProbeNormalDeltaBuffer;
				key = "probe_normal_delta";
				break;
			case DomainTelemetryMapKind.ProbeColliderMismatch:
				source = ProbeColliderMismatchBuffer;
				key = "probe_collider_mismatch";
				break;
			default:
				return false;
		}

		return source != null && source.Length == _filmWidth * _filmHeight;
	}

	private float[] BuildDerivedWorkScoreArray()
	{
		if (!TelemetryHeatmapsEnabledForCurrentRun())
		{
			return Array.Empty<float>();
		}

		int pixelCount = _filmWidth * _filmHeight;
		float[] work = new float[pixelCount];
		for (int i = 0; i < pixelCount; i++)
		{
			work[i] =
				_telemetryPass1AcceptedSteps[i] +
				_telemetryCandidateCount[i] +
				_telemetryQueryCount[i] +
				_telemetryResolveCount[i];
		}

		return work;
	}

	private float[] BuildDerivedNormalizedDifferenceArray(float[] lhs, float[] rhs)
	{
		if (!TelemetryHeatmapsEnabledForCurrentRun())
		{
			return Array.Empty<float>();
		}
		if (lhs == null || rhs == null || lhs.Length != rhs.Length || lhs.Length != (_filmWidth * _filmHeight))
		{
			return Array.Empty<float>();
		}

		TelemetryHeatmapStats lhsStats = ComputeTelemetryHeatmapStats(lhs, "lhs", ResolveTelemetryHeatmapModeToken());
		TelemetryHeatmapStats rhsStats = ComputeTelemetryHeatmapStats(rhs, "rhs", ResolveTelemetryHeatmapModeToken());
		float lhsDenom = lhsStats.ClampMax > 0f ? lhsStats.ClampMax : Math.Max(0f, lhsStats.Max);
		float rhsDenom = rhsStats.ClampMax > 0f ? rhsStats.ClampMax : Math.Max(0f, rhsStats.Max);
		float[] diff = new float[lhs.Length];
		for (int i = 0; i < lhs.Length; i++)
		{
			float lhsNorm = lhsDenom > 0f ? Mathf.Clamp(lhs[i] / lhsDenom, 0f, 1f) : 0f;
			float rhsNorm = rhsDenom > 0f ? Mathf.Clamp(rhs[i] / rhsDenom, 0f, 1f) : 0f;
			diff[i] = lhsNorm - rhsNorm;
		}

		return diff;
	}

	private float[] BuildDerivedEfficiencyArray(float epsilon)
	{
		if (!TelemetryHeatmapsEnabledForCurrentRun())
		{
			return Array.Empty<float>();
		}

		float safeEpsilon = Mathf.Max(1e-6f, epsilon);
		float[] work = BuildDerivedWorkScoreArray();
		if (work.Length != _telemetryCurvatureMean.Length)
		{
			return Array.Empty<float>();
		}

		float[] efficiency = new float[work.Length];
		for (int i = 0; i < work.Length; i++)
		{
			efficiency[i] = work[i] / (_telemetryCurvatureMean[i] + safeEpsilon);
		}

		return efficiency;
	}

	private bool IsSignedTelemetryHeatmapKind(TelemetryHeatmapKind kind)
	{
		return kind == TelemetryHeatmapKind.WorkMinusCurvature || kind == TelemetryHeatmapKind.QueryMinusCurvature;
	}

	private float[] ResolveTelemetryValues(TelemetryHeatmapKind kind, float[] source)
	{
		switch (kind)
		{
			case TelemetryHeatmapKind.Work:
				return BuildDerivedWorkScoreArray();
			case TelemetryHeatmapKind.WorkMinusCurvature:
				return BuildDerivedNormalizedDifferenceArray(BuildDerivedWorkScoreArray(), _telemetryCurvatureMean);
			case TelemetryHeatmapKind.QueryMinusCurvature:
				return BuildDerivedNormalizedDifferenceArray(_telemetryQueryCount, _telemetryCurvatureMean);
			case TelemetryHeatmapKind.Efficiency:
				return BuildDerivedEfficiencyArray(1e-3f);
			default:
				return source ?? Array.Empty<float>();
		}
	}

	private string ResolveTelemetryHeatmapModeToken(string overrideMode = null)
	{
		string source = string.IsNullOrWhiteSpace(overrideMode)
			? TelemetryHeatmapMode
			: overrideMode;
		string mode = string.IsNullOrWhiteSpace(source)
			? "basic"
			: source.Trim().ToLowerInvariant();
		if (string.IsNullOrWhiteSpace(mode))
		{
			return "basic";
		}

		return mode switch
		{
			"auto" or "basic" or "percentile" => "basic",
			"full" or "fullrange" or "range" => "full",
			"fixed" or "fixedrange" => "fixed",
			_ => mode,
		};
	}

	private static TelemetryHeatmapStats ComputeTelemetryHeatmapStats(float[] values, string key, string mode)
	{
		if (values == null || values.Length == 0)
		{
			return new TelemetryHeatmapStats(key, 0f, 0f, 0f, 0f, 0f, 0f, 0f, mode);
		}

		float min = float.PositiveInfinity;
		float max = float.NegativeInfinity;
		double sum = 0.0;
		float[] sorted = new float[values.Length];
		for (int i = 0; i < values.Length; i++)
		{
			float value = values[i];
			if (float.IsNaN(value) || float.IsInfinity(value))
			{
				value = 0f;
			}
			sorted[i] = value;
			if (value < min) min = value;
			if (value > max) max = value;
			sum += value;
		}

		Array.Sort(sorted);
		float p10 = SamplePercentile(sorted, 0.10f);
		float p50 = SamplePercentile(sorted, 0.50f);
		float p90 = SamplePercentile(sorted, 0.90f);
		float p99 = SamplePercentile(sorted, 0.99f);
		bool hasNegative = min < 0f;
		float clampMax;
		if (string.Equals(mode, "basic", StringComparison.OrdinalIgnoreCase))
		{
			if (hasNegative)
			{
				float p01 = SamplePercentile(sorted, 0.01f);
				clampMax = Math.Max(Math.Abs(p01), Math.Abs(p99));
				clampMax = Math.Max(clampMax, Math.Max(Math.Abs(p10), Math.Abs(p90)));
			}
			else
			{
				clampMax = Math.Max(p90, p99);
			}
		}
		else
		{
			clampMax = hasNegative ? Math.Max(Math.Abs(min), Math.Abs(max)) : max;
		}
		if (clampMax <= 0f)
		{
			clampMax = hasNegative ? Math.Max(Math.Abs(min), Math.Abs(max)) : max;
		}

		return new TelemetryHeatmapStats(
			key,
			float.IsFinite(min) ? min : 0f,
			float.IsFinite(max) ? max : 0f,
			(float)(sum / values.Length),
			p10,
			p50,
			p90,
			float.IsFinite(clampMax) ? clampMax : 0f,
			mode);
	}

	private static TelemetryHeatmapStats ComputeTelemetryHeatmapStats(float[] values, string key, string mode, float fixedMin, float fixedMax)
	{
		TelemetryHeatmapStats stats = ComputeTelemetryHeatmapStats(values, key, mode);
		if (!string.Equals(mode, "fixed", StringComparison.OrdinalIgnoreCase)
			|| !float.IsFinite(fixedMin)
			|| !float.IsFinite(fixedMax)
			|| fixedMax <= fixedMin)
		{
			return stats;
		}

		float clampMax = Math.Max(Math.Abs(fixedMin), Math.Abs(fixedMax));
		return new TelemetryHeatmapStats(
			key,
			fixedMin,
			fixedMax,
			stats.Mean,
			stats.P10,
			stats.P50,
			stats.P90,
			clampMax,
			mode);
	}

	private static void ResolveTelemetryDisplayRange(
		TelemetryHeatmapStats stats,
		bool signedMap,
		string mode,
		float fixedMin,
		float fixedMax,
		out float displayMin,
		out float displayMax)
	{
		if (string.Equals(mode, "fixed", StringComparison.OrdinalIgnoreCase)
			&& float.IsFinite(fixedMin)
			&& float.IsFinite(fixedMax)
			&& fixedMax > fixedMin)
		{
			displayMin = fixedMin;
			displayMax = fixedMax;
			return;
		}

		if (signedMap)
		{
			float absMax = stats.ClampMax > 0f
				? stats.ClampMax
				: Math.Max(Math.Abs(stats.Min), Math.Abs(stats.Max));
			displayMin = -absMax;
			displayMax = absMax;
			return;
		}

		displayMin = 0f;
		displayMax = stats.ClampMax > 0f ? stats.ClampMax : Math.Max(0f, stats.Max);
	}

	private static float NormalizeTelemetryDisplayValue(float raw, float displayMin, float displayMax, bool signedMap)
	{
		float safeRaw = float.IsFinite(raw) ? raw : 0f;
		if (!float.IsFinite(displayMin) || !float.IsFinite(displayMax) || displayMax <= displayMin)
		{
			return signedMap ? 0.5f : 0f;
		}

		return Mathf.Clamp(Mathf.InverseLerp(displayMin, displayMax, safeRaw), 0f, 1f);
	}

	private static float SamplePercentile(float[] sorted, float percentile)
	{
		if (sorted == null || sorted.Length == 0)
		{
			return 0f;
		}

		float clamped = Mathf.Clamp(percentile, 0f, 1f);
		int index = Mathf.Clamp(Mathf.RoundToInt((sorted.Length - 1) * clamped), 0, sorted.Length - 1);
		float value = sorted[index];
		return float.IsFinite(value) ? value : 0f;
	}

	private static Color EvaluateTelemetryHeatColor(float t)
	{
		float clamped = Mathf.Clamp(t, 0f, 1f);
		if (clamped <= 0.33f)
		{
			float local = clamped / 0.33f;
			return new Color(0f, local, 1f, 1f);
		}
		if (clamped <= 0.66f)
		{
			float local = (clamped - 0.33f) / 0.33f;
			return new Color(local, 1f, 1f - local, 1f);
		}

		float tail = (clamped - 0.66f) / 0.34f;
		return new Color(1f, 1f - tail, 0f, 1f);
	}

	private static Color EvaluateDomainScalarColor(float value)
	{
		float t = Mathf.Clamp(float.IsFinite(value) ? value : 0f, 0f, 1f);
		return new Color(t, t, t, 1f);
	}

	private static Color EvaluateDomainIdColor(CurvatureDomainKind kind)
	{
		return kind switch
		{
			CurvatureDomainKind.MouthNear => new Color(0.95f, 0.20f, 0.18f, 1f),
			CurvatureDomainKind.ThroatBridge => new Color(0.18f, 0.78f, 0.92f, 1f),
			CurvatureDomainKind.FarWall => new Color(0.24f, 0.46f, 0.95f, 1f),
			CurvatureDomainKind.TangentialFar => new Color(0.94f, 0.78f, 0.20f, 1f),
			CurvatureDomainKind.Background => new Color(0.10f, 0.12f, 0.16f, 1f),
			CurvatureDomainKind.BoundaryMixed => new Color(0.95f, 0.20f, 0.86f, 1f),
			_ => new Color(0.0f, 0.0f, 0.0f, 1f),
		};
	}

	public static string GetDomainTelemetryFileSuffix(DomainTelemetryMapKind kind)
	{
		return kind switch
		{
			DomainTelemetryMapKind.DomainId => "domain_id",
			DomainTelemetryMapKind.DomainConfidence => "domain_confidence",
			DomainTelemetryMapKind.BoundaryConfidence => "boundary_confidence",
			DomainTelemetryMapKind.SelectionFlip => "selection_flip",
			DomainTelemetryMapKind.NormalDiscontinuity => "normal_discontinuity",
			DomainTelemetryMapKind.StepConvergenceConfidence => "step_convergence_confidence",
			DomainTelemetryMapKind.StepSensitivity => "step_sensitivity",
			DomainTelemetryMapKind.PrecisionRequired => "precision_required",
			DomainTelemetryMapKind.ProbeHitDistanceDelta => "probe_hit_distance_delta",
			DomainTelemetryMapKind.ProbeNormalDelta => "probe_normal_delta",
			DomainTelemetryMapKind.ProbeColliderMismatch => "probe_collider_mismatch",
			_ => "domain_unknown"
		};
	}

	private static string FormatJsonFloatForArtifact(float value)
	{
		float safe = (float.IsNaN(value) || float.IsInfinity(value)) ? 0f : value;
		return safe.ToString("0.######", CultureInfo.InvariantCulture);
	}

	private static string JsonEscapeForArtifact(string value)
	{
		if (string.IsNullOrEmpty(value))
		{
			return string.Empty;
		}

		return value
			.Replace("\\", "\\\\")
			.Replace("\"", "\\\"");
	}

	private bool DomainAwareFirstHitResolverEnabledForCurrentRun(in EffectiveConfig cfg)
	{
		return cfg.EnableDomainAwareFirstHitResolver
			&& EnableDomainTelemetry
			&& _filmWidth > 0
			&& _filmHeight > 0
			&& _pixelDomainStates.Length == _filmWidth * _filmHeight;
	}

	private bool TryGetNeighborDomainPrior(int x, int y, int filmW, int filmH, out CurvatureDomainKind priorKind, out float confidence)
	{
		priorKind = CurvatureDomainKind.Unknown;
		confidence = 0f;
		if (_pixelDomainStates == null || _pixelDomainStates.Length != filmW * filmH)
			return false;

		int[] counts = new int[Enum.GetValues(typeof(CurvatureDomainKind)).Length];
		float[] weights = new float[counts.Length];
		void Observe(int nx, int ny)
		{
			if (nx < 0 || nx >= filmW || ny < 0 || ny >= filmH)
				return;
			PixelDomainState neighbor = _pixelDomainStates[(ny * filmW) + nx];
			int kind = (int)neighbor.Primary.Kind;
			if ((uint)kind >= (uint)counts.Length || neighbor.Primary.Kind == CurvatureDomainKind.Unknown)
				return;
			float w = Mathf.Clamp(neighbor.Primary.Confidence, 0f, 1f);
			if (w <= 0f)
				return;
			counts[kind]++;
			weights[kind] += w;
		}

		Observe(x - 1, y);
		Observe(x + 1, y);
		Observe(x, y - 1);
		Observe(x, y + 1);

		int bestKind = -1;
		float bestWeight = 0f;
		float totalWeight = 0f;
		for (int i = 0; i < weights.Length; i++)
		{
			totalWeight += weights[i];
			if (weights[i] > bestWeight)
			{
				bestWeight = weights[i];
				bestKind = i;
			}
		}

		if (bestKind < 0 || totalWeight <= 0f)
			return false;

		priorKind = (CurvatureDomainKind)bestKind;
		confidence = Mathf.Clamp(bestWeight / totalWeight, 0f, 1f);
		return true;
	}

	private DomainAwareHitCandidate BuildDomainAwareHitCandidate(
		in EffectiveConfig cfg,
		int globalPi,
		int x,
		int y,
		int filmW,
		int filmH,
		int segmentIndex,
		float distance,
		Vector3 position,
		Vector3 normal,
		Vector3 rayDir,
		ulong colliderId,
		int primitiveOrShapeId,
		string colliderName,
		int candidateCount,
		bool segmentPostRemap,
		int boundaryRemapCount,
		int eventCount,
		int boundaryCrossings,
		int transformCount,
		int entryCount,
		int exitCount,
		int lastCrossingLayer,
		byte lastCrossingKind,
		bool ambiguousOrdering,
		bool prevHadHit,
		bool testedAnyInPass0)
	{
		string fixtureHitKind = ClassifyFixtureHitKind(true, false, colliderId);
		PixelDomainState domainState = BuildPixelDomainState(
			globalPi,
			true,
			fixtureHitKind,
			distance,
			true,
			distance,
			colliderId,
			colliderId,
			normal,
			normal,
			rayDir,
			segmentPostRemap,
			segmentPostRemap ? 1 : 0,
			boundaryRemapCount,
			boundaryCrossings,
			transformCount,
			entryCount,
			exitCount,
			ambiguousOrdering,
			prevHadHit,
			testedAnyInPass0);

		bool hasPrior = TryGetNeighborDomainPrior(x, y, filmW, filmH, out CurvatureDomainKind priorKind, out float priorConfidence);
		bool domainFlipAgainstPrior = hasPrior
			&& priorKind != CurvatureDomainKind.Unknown
			&& priorKind != domainState.Primary.Kind;
		float neighborAgreement = !hasPrior
			? 0.5f
			: (domainFlipAgainstPrior ? 0f : Mathf.Clamp(priorConfidence, 0f, 1f));

		// Rendering heuristic only: choose among real candidate hits using local continuity signals.
		float score = 1f
			+ (cfg.DomainAwareConfidenceWeight * domainState.Primary.Confidence)
			+ (cfg.DomainAwareNeighborContinuityWeight * neighborAgreement)
			+ (cfg.DomainAwareBoundaryStabilityWeight * domainState.Primary.BoundaryStability)
			- (cfg.DomainAwareDiscontinuityPenalty * domainState.Primary.NormalDiscontinuity)
			- (cfg.DomainAwareFlipPenalty * (domainFlipAgainstPrior ? 1f : 0f));
		float confidenceComponent = cfg.DomainAwareConfidenceWeight * domainState.Primary.Confidence;
		float neighborComponent = cfg.DomainAwareNeighborContinuityWeight * neighborAgreement;
		float boundaryStabilityComponent = cfg.DomainAwareBoundaryStabilityWeight * domainState.Primary.BoundaryStability;
		float normalDiscontinuityComponent = cfg.DomainAwareDiscontinuityPenalty * domainState.Primary.NormalDiscontinuity;
		float flipPenaltyComponent = cfg.DomainAwareFlipPenalty * (domainFlipAgainstPrior ? 1f : 0f);

		return new DomainAwareHitCandidate
		{
			Valid = true,
			SegmentIndex = segmentIndex,
			Distance = distance,
			Position = position,
			Normal = normal,
			RayDir = rayDir,
			ColliderId = colliderId,
			PrimitiveOrShapeId = primitiveOrShapeId,
			ColliderName = colliderName ?? "<none>",
			CandidateCount = candidateCount,
			SegmentPostRemap = segmentPostRemap,
			BoundaryRemapCount = boundaryRemapCount,
			EventCount = eventCount,
			BoundaryCrossings = boundaryCrossings,
			TransformCount = transformCount,
			EntryCount = entryCount,
			ExitCount = exitCount,
			LastCrossingLayer = lastCrossingLayer,
			LastCrossingKind = lastCrossingKind,
			AmbiguousOrdering = ambiguousOrdering,
			DomainState = domainState,
			Score = score,
			ConfidenceComponent = confidenceComponent,
			NeighborContinuityComponent = neighborComponent,
			BoundaryStabilityComponent = boundaryStabilityComponent,
			NormalDiscontinuityComponent = normalDiscontinuityComponent,
			FlipPenaltyComponent = flipPenaltyComponent
		};
	}

	private bool ShouldReplaceStoredHitCandidateDomainAware(
		in EffectiveConfig cfg,
		in DomainAwareHitCandidate incumbent,
		in DomainAwareHitCandidate candidate)
	{
		if (!candidate.Valid)
			return false;
		if (!incumbent.Valid)
			return true;

		const float PlausibleCompetingHitDistanceEps = 0.08f;
		float distanceDelta = candidate.Distance - incumbent.Distance;
		if (distanceDelta < -PlausibleCompetingHitDistanceEps)
			return true;
		if (distanceDelta > PlausibleCompetingHitDistanceEps)
			return false;

		float scoreDelta = candidate.Score - incumbent.Score;
		if (scoreDelta > 0.0001f)
			return true;
		if (scoreDelta < -0.0001f)
			return false;

		return candidate.Distance < incumbent.Distance;
	}

	private void ApplyDomainAwareHitCandidate(
		in DomainAwareHitCandidate candidate,
		ref float bestHit,
		ref float hitDistance,
		ref bool hadHit,
		ref string hitName,
		bool needHitName,
		ref Vector3 bestHp,
		ref Vector3 bestHn,
		ref Vector3 bestRayDir,
		ref ulong bestCid,
		ref int bestPrimitiveOrShapeId,
		ref bool bestHitWasPostRemap,
		ref int bestEventCountThisPixel,
		ref int bestBoundaryCrossingsThisPixel,
		ref int bestTransformCountThisPixel,
		ref int bestEntryCountThisPixel,
		ref int bestExitCountThisPixel,
		ref int bestLastCrossingLayerThisPixel,
		ref byte bestLastCrossingKindThisPixel,
		ref bool bestAmbiguousOrderingThisPixel)
	{
		bestHit = candidate.Distance;
		hitDistance = candidate.Distance;
		hadHit = true;
		if (needHitName)
			hitName = candidate.ColliderName;
		bestHp = candidate.Position;
		bestHn = candidate.Normal;
		bestRayDir = candidate.RayDir;
		bestCid = candidate.ColliderId;
		bestPrimitiveOrShapeId = candidate.PrimitiveOrShapeId;
		bestHitWasPostRemap = candidate.SegmentPostRemap;
		bestEventCountThisPixel = candidate.EventCount;
		bestBoundaryCrossingsThisPixel = candidate.BoundaryCrossings;
		bestTransformCountThisPixel = candidate.TransformCount;
		bestEntryCountThisPixel = candidate.EntryCount;
		bestExitCountThisPixel = candidate.ExitCount;
		bestLastCrossingLayerThisPixel = candidate.LastCrossingLayer;
		bestLastCrossingKindThisPixel = candidate.LastCrossingKind;
		bestAmbiguousOrderingThisPixel = candidate.AmbiguousOrdering;
	}

	private DomainResolverTelemetrySample BuildDomainResolverTelemetrySample(
		in EffectiveConfig cfg,
		bool domainAwareFirstHitResolver,
		in DomainAwareHitCandidate selected,
		int globalPi,
		int x,
		int y,
		int filmW,
		int filmH,
		int segOffset,
		int firstAcceptedSegmentIndex,
		bool firstAcceptedHadHit,
		float firstAcceptedHitDistance,
		Vector3 firstAcceptedHp,
		Vector3 firstAcceptedHn,
		ulong firstAcceptedCid,
		int firstAcceptedPrimitiveOrShapeId,
		string firstAcceptedName,
		int firstAcceptedCandidateCount,
		bool prevHadHit,
		bool testedAnyInPass0)
	{
		const float HitDistanceChangeEps = 1e-4f;
		if (!domainAwareFirstHitResolver || !selected.Valid || !firstAcceptedHadHit || firstAcceptedSegmentIndex < 0)
			return default;

		int firstSegBufferIndex = segOffset + firstAcceptedSegmentIndex;
		if (firstSegBufferIndex < 0 || firstSegBufferIndex >= _segBuf.Length)
			return default;

		ref readonly var firstSeg = ref _segBuf[firstSegBufferIndex];
		Vector3 firstSegDelta = firstSeg.B - firstSeg.A;
		float firstSegLen = firstSegDelta.Length();
		Vector3 firstRayDir = firstSegLen > 0f
			? firstSegDelta.Normalized()
			: (firstAcceptedHp - firstSeg.A).Normalized();
		DomainAwareHitCandidate firstCandidate = BuildDomainAwareHitCandidate(
			in cfg,
			globalPi,
			x,
			y,
			filmW,
			filmH,
			firstAcceptedSegmentIndex,
			firstAcceptedHitDistance,
			firstAcceptedHp,
			firstAcceptedHn,
			firstRayDir,
			firstAcceptedCid,
			firstAcceptedPrimitiveOrShapeId,
			firstAcceptedName,
			firstAcceptedCandidateCount,
			firstSeg.BoundaryRemapCount > 0,
			firstSeg.BoundaryRemapCount,
			firstSeg.EventCount,
			firstSeg.BoundaryCrossings,
			firstSeg.TransformCount,
			firstSeg.EntryCount,
			firstSeg.ExitCount,
			firstSeg.LastCrossingLayer,
			firstSeg.LastCrossingKind,
			firstSeg.AmbiguousOrdering,
			prevHadHit,
			testedAnyInPass0);

		float distanceDelta = Mathf.Abs(selected.Distance - firstAcceptedHitDistance);
		bool colliderChanged = selected.ColliderId != firstAcceptedCid;
		bool distanceChanged = distanceDelta > HitDistanceChangeEps;
		bool primitiveChanged = selected.PrimitiveOrShapeId != firstAcceptedPrimitiveOrShapeId;
		bool changed = colliderChanged || distanceChanged || primitiveChanged;
		return new DomainResolverTelemetrySample
		{
			Compared = true,
			Changed = changed,
			ColliderChanged = colliderChanged,
			DistanceChanged = distanceChanged,
			DistanceDelta = distanceDelta,
			ScoreAvailable = firstCandidate.Valid,
			ScoreDelta = selected.Score - firstCandidate.Score,
			ConfidenceComponent = selected.ConfidenceComponent,
			NeighborContinuityComponent = selected.NeighborContinuityComponent,
			BoundaryStabilityComponent = selected.BoundaryStabilityComponent,
			NormalDiscontinuityComponent = selected.NormalDiscontinuityComponent,
			FlipPenaltyComponent = selected.FlipPenaltyComponent
		};
	}

	private PixelDomainState BuildPixelDomainState(
		int globalPi,
		bool hadHit,
		string fixtureHitKind,
		float hitDistance,
		bool firstAcceptedHadHit,
		float firstAcceptedHitDistance,
		ulong firstAcceptedCid,
		ulong bestCid,
		Vector3 firstAcceptedNormal,
		Vector3 bestNormal,
		Vector3 bestRayDir,
		bool bestHitWasPostRemap,
		int postRemapSegmentCount,
		int maxBoundaryRemapCount,
		int boundaryCrossings,
		int transformCount,
		int entryCount,
		int exitCount,
		bool ambiguousOrdering,
		bool prevHadHit,
		bool testedAnyInPass0)
	{
		float normalDiscontinuity = 0f;
		if (firstAcceptedHadHit && hadHit)
		{
			Vector3 a = firstAcceptedNormal.Normalized();
			Vector3 b = bestNormal.Normalized();
			if (a.LengthSquared() > 1e-12f && b.LengthSquared() > 1e-12f)
			{
				normalDiscontinuity = 1f - Mathf.Clamp(a.Dot(b), -1f, 1f);
			}
		}

		Vector3 rayDir = bestRayDir.Normalized();
		Vector3 normal = bestNormal.Normalized();
		float radialScore = 0f;
		if (rayDir.LengthSquared() > 1e-12f && normal.LengthSquared() > 1e-12f)
		{
			radialScore = Mathf.Abs(rayDir.Dot(normal));
		}
		float tangentialScore = 1f - radialScore;
		float curvatureMagnitude = Mathf.Clamp(
			(0.20f * postRemapSegmentCount) +
			(0.25f * boundaryCrossings) +
			(0.35f * maxBoundaryRemapCount) +
			(0.20f * transformCount),
			0f,
			1f);
		bool finalVsFirstFlip = firstAcceptedHadHit && hadHit && (
			firstAcceptedCid != bestCid ||
			Mathf.Abs(firstAcceptedHitDistance - hitDistance) > 1e-4f ||
			normalDiscontinuity > 0.15f);
		bool frameHitFlip = prevHadHit != hadHit && testedAnyInPass0;
		float selectionFlip = finalVsFirstFlip || frameHitFlip ? 1f : 0f;
		float boundaryConfidence = Mathf.Clamp(Mathf.Max(
			Mathf.Max(normalDiscontinuity * 0.65f, curvatureMagnitude),
			Mathf.Max(ambiguousOrdering ? 0.85f : 0f, selectionFlip * 0.70f)), 0f, 1f);

		CurvatureDomainKind kind;
		if (!hadHit)
		{
			kind = CurvatureDomainKind.Background;
		}
		else if (boundaryConfidence >= 0.72f || ambiguousOrdering)
		{
			kind = CurvatureDomainKind.BoundaryMixed;
		}
		else if (bestHitWasPostRemap || postRemapSegmentCount > 0 || transformCount > 0 || entryCount > 0 || exitCount > 0)
		{
			kind = CurvatureDomainKind.ThroatBridge;
		}
		else if (string.Equals(fixtureHitKind, "source", StringComparison.OrdinalIgnoreCase) ||
			string.Equals(fixtureHitKind, "absorbed", StringComparison.OrdinalIgnoreCase))
		{
			kind = CurvatureDomainKind.MouthNear;
		}
		else if (tangentialScore >= 0.65f)
		{
			kind = CurvatureDomainKind.TangentialFar;
		}
		else if (string.Equals(fixtureHitKind, "background", StringComparison.OrdinalIgnoreCase))
		{
			kind = CurvatureDomainKind.FarWall;
		}
		else
		{
			kind = CurvatureDomainKind.Unknown;
		}

		float baseConfidence = hadHit ? 0.72f : 0.55f;
		if (firstAcceptedHadHit) baseConfidence += 0.12f;
		if (kind == CurvatureDomainKind.BoundaryMixed) baseConfidence = Math.Max(baseConfidence, boundaryConfidence);
		float confidence = Mathf.Clamp(baseConfidence - (boundaryConfidence * 0.22f), 0f, 1f);
		int stableFrameCount = 1;
		if ((uint)globalPi < (uint)_pixelDomainStates.Length &&
			_pixelDomainStates[globalPi].Primary.Kind == kind &&
			_pixelDomainStates[globalPi].IsBoundaryPixel == (boundaryConfidence >= 0.55f))
		{
			stableFrameCount = Math.Min(_pixelDomainStates[globalPi].StableFrameCount + 1, int.MaxValue);
		}

		return new PixelDomainState
		{
			Primary = new DomainSignature
			{
				Kind = kind,
				Confidence = confidence,
				BoundaryStability = 1f - boundaryConfidence,
				CurvatureMagnitude = curvatureMagnitude,
				NormalDiscontinuity = normalDiscontinuity,
				BoundaryGradient = new Vector2(selectionFlip, boundaryConfidence),
				RadialScore = radialScore,
				TangentialScore = tangentialScore
			},
			Secondary = new DomainSignature
			{
				Kind = boundaryConfidence >= 0.55f ? CurvatureDomainKind.BoundaryMixed : CurvatureDomainKind.Unknown,
				Confidence = boundaryConfidence,
				BoundaryStability = 1f - boundaryConfidence,
				CurvatureMagnitude = curvatureMagnitude,
				NormalDiscontinuity = normalDiscontinuity,
				BoundaryGradient = new Vector2(selectionFlip, boundaryConfidence),
				RadialScore = radialScore,
				TangentialScore = tangentialScore
			},
			IsBoundaryPixel = boundaryConfidence >= 0.55f,
			BoundaryConfidence = boundaryConfidence,
			StableFrameCount = stableFrameCount
		};
	}

	private void WriteDomainTelemetryBlock(int x, int y, int stride, int filmW, int filmH, in PixelDomainState state, float selectionFlip, in DomainResolverTelemetrySample resolverTelemetry)
	{
		if (!DomainTelemetryEnabledForCurrentRun())
		{
			return;
		}

		FillFloatBlock(DomainIdBuffer, x, y, stride, filmW, filmH, (float)state.Primary.Kind);
		FillFloatBlock(DomainConfidenceBuffer, x, y, stride, filmW, filmH, state.Primary.Confidence);
		FillFloatBlock(BoundaryConfidenceBuffer, x, y, stride, filmW, filmH, state.BoundaryConfidence);
		FillFloatBlock(SelectionFlipBuffer, x, y, stride, filmW, filmH, selectionFlip);
		FillFloatBlock(NormalDiscontinuityBuffer, x, y, stride, filmW, filmH, state.Primary.NormalDiscontinuity);
		FillFloatBlock(_domainResolverComparedBuffer, x, y, stride, filmW, filmH, resolverTelemetry.Compared ? 1f : 0f);
		FillFloatBlock(_domainResolverChangedBuffer, x, y, stride, filmW, filmH, resolverTelemetry.Changed ? 1f : 0f);
		FillFloatBlock(_domainResolverColliderChangedBuffer, x, y, stride, filmW, filmH, resolverTelemetry.ColliderChanged ? 1f : 0f);
		FillFloatBlock(_domainResolverDistanceChangedBuffer, x, y, stride, filmW, filmH, resolverTelemetry.DistanceChanged ? 1f : 0f);
		FillFloatBlock(_domainResolverDistanceDeltaBuffer, x, y, stride, filmW, filmH, resolverTelemetry.DistanceDelta);
		FillFloatBlock(_domainResolverScoreDeltaBuffer, x, y, stride, filmW, filmH, resolverTelemetry.ScoreDelta);
		FillFloatBlock(_domainResolverScoreAvailableBuffer, x, y, stride, filmW, filmH, resolverTelemetry.ScoreAvailable ? 1f : 0f);
		FillFloatBlock(_domainResolverConfidenceComponentBuffer, x, y, stride, filmW, filmH, resolverTelemetry.ConfidenceComponent);
		FillFloatBlock(_domainResolverNeighborComponentBuffer, x, y, stride, filmW, filmH, resolverTelemetry.NeighborContinuityComponent);
		FillFloatBlock(_domainResolverBoundaryStabilityComponentBuffer, x, y, stride, filmW, filmH, resolverTelemetry.BoundaryStabilityComponent);
		FillFloatBlock(_domainResolverNormalDiscontinuityComponentBuffer, x, y, stride, filmW, filmH, resolverTelemetry.NormalDiscontinuityComponent);
		FillFloatBlock(_domainResolverFlipPenaltyComponentBuffer, x, y, stride, filmW, filmH, resolverTelemetry.FlipPenaltyComponent);
		FillDomainStateBlock(_pixelDomainStates, x, y, stride, filmW, filmH, state);
	}

	// Passive step-convergence probe using position-shifted step phases.
	// Re-runs an isolated first-hit acquisition over the finalized legacy segment list
	// after shifting the step windows along the ray direction. This measures phase
	// sensitivity instead of subdividing the already-known hit segment.
	private void ComputeStepConvergenceProbe(
		PhysicsDirectSpaceState3D space,
		int maxSeg,
		Camera3D pass1Cam, float pass1PxPerRad, Vector3 pass1CamPos,
		Vector3 rayOrigin, Vector3 rayDir, Vector3 bendDir,
		Vector3 center, float beta, float gamma,
		RayBeamRenderer.FieldSourceSnap[] fieldSnaps, bool hasSources,
		float farForSim,
		Plane insightPlane, bool useInsightPlane, float insightEps,
		bool pass1StopOnHit, bool pass1ProbeEnabledForRay,
		int pass1ProbeEveryNSegments, float pass1ProbeMinTravelDelta,
		string renderSpaceSource, string renderSceneName, string renderFixtureName, string renderModeToken,
		CurvatureBoundGrid curvatureGridForPass1, FieldGrid3D fieldGridForPass1,
		float stepLength,
		bool baselineHadHit, ulong baselineCid, float baselineDist, Vector3 baselineNormal,
		uint collisionMask, float collisionRaySubdivideThreshold, int maxCollisionSubsteps,
		bool hitBackFaces, bool hitFromInside,
		bool nearestHitOnly, float earlyOutDistanceEps,
		out float confidence, out float sensitivity, out float precisionRequired,
		out float hitDistanceDelta, out float normalDelta, out float colliderMismatch)
	{
		confidence = 1f;
		sensitivity = 0f;
		precisionRequired = 0f;
		hitDistanceDelta = 0f;
		normalDelta = 0f;
		colliderMismatch = 0f;

		if (space == null || !IsUsablePhysicsSpaceState(space) || _rbr == null || !GodotObject.IsInstanceValid(_rbr))
			return;
		if (maxSeg <= 0 || rayDir.LengthSquared() <= 1e-10f)
			return;

		RayBeamRenderer.RaySeg[] probeSegs = new RayBeamRenderer.RaySeg[Math.Max(1, maxSeg)];
		PhysicsRayQueryParameters3D probeQuickRayParams = new PhysicsRayQueryParameters3D
		{
			CollisionMask = collisionMask,
			CollideWithBodies = true,
			CollideWithAreas = true,
			HitFromInside = hitFromInside,
			HitBackFaces = hitBackFaces
		};

		bool ProbeFirstHit(float offsetFraction, out float probeDist, out Vector3 probePos, out Vector3 probeNormal, out ulong probeCid)
		{
			probeDist = -1f;
			probePos = Vector3.Zero;
			probeNormal = Vector3.Zero;
			probeCid = 0;
			bool probeHadHit = false;
			float bestProbeDist = float.PositiveInfinity;
			Vector3 bestProbePos = Vector3.Zero;
			Vector3 bestProbeNormal = Vector3.Zero;
			ulong bestProbeCid = 0;
			float offsetLen = offsetFraction * stepLength;
			float farEarlyOutEps = Mathf.Max(0f, earlyOutDistanceEps);
			Vector3 shiftedOrigin = rayOrigin + rayDir.Normalized() * offsetLen;

			int probeSegCount = _rbr.BuildRaySegmentsCamera_Pass1(
				space,
				ref probeQuickRayParams,
				pass1Cam,
				pass1PxPerRad,
				pass1CamPos,
				shiftedOrigin,
				rayDir,
				bendDir,
				center,
				beta,
				gamma,
				fieldSnaps,
				hasSources,
				farForSim,
				probeSegs,
				0,
				probeSegs.Length,
				insightPlane,
				useInsightPlane,
				insightEps,
				pass1StopOnHit,
				pass1ProbeEnabledForRay,
				pass1ProbeEveryNSegments,
				pass1ProbeMinTravelDelta,
				renderSpaceSource,
				renderSceneName,
				renderFixtureName,
				renderModeToken,
				out _,
				out _,
				out _,
				out _,
				out _,
				out _,
				out _,
				out _,
				out _,
				out _,
				out _,
				out _,
				out _,
				out _,
				out _,
				out _,
				out _,
				out _,
				curvatureGridForPass1,
				fieldGridForPass1);

			for (int si = 0; si < probeSegCount; si++)
			{
				ref readonly var seg = ref probeSegs[si];
				Vector3 segA = seg.A;
				Vector3 segB = seg.B;
				Vector3 segDelta = segB - segA;
				float segLen = segDelta.Length();
				if (segLen <= 1e-6f)
					continue;

				if (nearestHitOnly && probeHadHit)
				{
					float segStartDist = seg.TraveledB - segLen;
					if (segStartDist > bestProbeDist + farEarlyOutEps)
						break;
				}

				int sub = 1;
				if (segLen > collisionRaySubdivideThreshold)
					sub = Mathf.CeilToInt(segLen / Mathf.Max(1e-6f, collisionRaySubdivideThreshold));
				sub = Mathf.Clamp(sub, 1, Math.Max(1, maxCollisionSubsteps));

				bool didHit = RayBeamRenderer.SubdividedRayHit(
					space,
					segA,
					segB,
					collisionMask,
					sub,
					out Vector3 hp,
					out Vector3 hn,
					out ulong cid,
					out string _,
					out int _,
					includeColliderName: false,
					hitBackFaces: hitBackFaces,
					hitFromInside: hitFromInside,
					diagnosticQueryKind: "step_convergence_shifted_probe");
				if (!didHit)
					continue;

				Vector3 segDir = segDelta / segLen;
				float resolvedDist = seg.TraveledB - segLen + (hp - segA).Dot(segDir);
				if (!probeHadHit || resolvedDist < bestProbeDist)
				{
					probeHadHit = true;
					bestProbeDist = resolvedDist;
					bestProbePos = hp;
					bestProbeNormal = hn;
					bestProbeCid = cid;
				}
				if (nearestHitOnly)
					break;
			}

			if (!probeHadHit)
				return false;
			probeDist = bestProbeDist;
			probePos = bestProbePos;
			probeNormal = bestProbeNormal;
			probeCid = bestProbeCid;
			return true;
		}

		float[] offsets = { -0.5f, -0.125f, 0.125f, 0.5f };
		int probeCount = offsets.Length;
		int mismatchCount = 0;
		int hitMissTransitionCount = 0;
		bool fineDisagrees = false;
		bool coarseDisagrees = false;
		float maxDistDelta = 0f;
		float maxNormDelta = 0f;

		for (int pi = 0; pi < offsets.Length; pi++)
		{
			float offFrac = offsets[pi];
			bool phit = ProbeFirstHit(offFrac, out float phDist, out Vector3 _, out Vector3 phNorm, out ulong phCid);
			if (phit != baselineHadHit)
			{
				hitMissTransitionCount++;
				mismatchCount++;
				if (Mathf.Abs(offFrac) >= 0.5f) coarseDisagrees = true;
				else fineDisagrees = true;
				continue;
			}
			if (!phit)
				continue;

			bool colliderDisagrees = phCid != baselineCid;
			float distDelta = baselineHadHit && baselineDist >= 0f
				? Mathf.Abs(phDist - baselineDist) / Mathf.Max(1e-6f, stepLength)
				: 0f;
			bool distanceDisagrees = distDelta >= 0.25f;
			float nDelta = 0f;
			if (baselineNormal.LengthSquared() > 0.25f && phNorm.LengthSquared() > 0.25f)
			{
				float dot = baselineNormal.Normalized().Dot(phNorm.Normalized());
				nDelta = (1f - Mathf.Clamp(dot, -1f, 1f)) * 0.5f;
			}
			bool disagrees = colliderDisagrees || distanceDisagrees;
			if (disagrees)
			{
				mismatchCount++;
				if (Mathf.Abs(offFrac) >= 0.5f) coarseDisagrees = true;
				else fineDisagrees = true;
			}
			maxDistDelta = Mathf.Max(maxDistDelta, distDelta);
			maxNormDelta = Mathf.Max(maxNormDelta, nDelta);
		}

		colliderMismatch = probeCount > 0 ? (float)mismatchCount / probeCount : 0f;
		confidence = 1f - colliderMismatch;
		float hitMissSensitivity = hitMissTransitionCount > 0 ? 1f : 0f;
		sensitivity = Mathf.Clamp(Mathf.Max(colliderMismatch, Mathf.Max(maxDistDelta, hitMissSensitivity)), 0f, 1f);

		if (fineDisagrees) precisionRequired = 1.0f;
		else if (coarseDisagrees) precisionRequired = 0.5f;

		hitDistanceDelta = Mathf.Clamp(maxDistDelta, 0f, 1f);
		normalDelta = Mathf.Clamp(maxNormDelta, 0f, 1f);
	}

	private void WriteStepConvergenceBlock(int x, int y, int stride, int filmW, int filmH,
		float confidence, float sensitivity, float precisionRequired,
		float hitDistanceDelta, float normalDelta, float colliderMismatch)
	{
		if (!DomainTelemetryEnabledForCurrentRun())
			return;
		FillFloatBlock(StepConvergenceConfidenceBuffer, x, y, stride, filmW, filmH, confidence);
		FillFloatBlock(StepSensitivityBuffer, x, y, stride, filmW, filmH, sensitivity);
		FillFloatBlock(PrecisionRequiredBuffer, x, y, stride, filmW, filmH, precisionRequired);
		FillFloatBlock(ProbeHitDistanceDeltaBuffer, x, y, stride, filmW, filmH, hitDistanceDelta);
		FillFloatBlock(ProbeNormalDeltaBuffer, x, y, stride, filmW, filmH, normalDelta);
		FillFloatBlock(ProbeColliderMismatchBuffer, x, y, stride, filmW, filmH, colliderMismatch);
	}

	private static float ComputePearsonCorrelation(float[] lhs, float[] rhs)
	{
		if (lhs == null || rhs == null || lhs.Length == 0 || lhs.Length != rhs.Length)
		{
			return 0f;
		}

		double lhsSum = 0.0;
		double rhsSum = 0.0;
		int count = lhs.Length;
		for (int i = 0; i < count; i++)
		{
			double l = SanitizeTelemetryValue(lhs[i]);
			double r = SanitizeTelemetryValue(rhs[i]);
			lhsSum += l;
			rhsSum += r;
		}

		double lhsMean = lhsSum / count;
		double rhsMean = rhsSum / count;
		double covariance = 0.0;
		double lhsVar = 0.0;
		double rhsVar = 0.0;
		for (int i = 0; i < count; i++)
		{
			double l = SanitizeTelemetryValue(lhs[i]) - lhsMean;
			double r = SanitizeTelemetryValue(rhs[i]) - rhsMean;
			covariance += l * r;
			lhsVar += l * l;
			rhsVar += r * r;
		}

		double denom = Math.Sqrt(lhsVar * rhsVar);
		if (!double.IsFinite(denom) || denom <= 1e-12)
		{
			return 0f;
		}

		double corr = covariance / denom;
		if (!double.IsFinite(corr))
		{
			return 0f;
		}

		return (float)Mathf.Clamp((float)corr, -1f, 1f);
	}

	private static double SanitizeTelemetryValue(float value)
	{
		return (float.IsNaN(value) || float.IsInfinity(value)) ? 0.0 : value;
	}

	private void ResetFixtureRowParticipationForRunStart()
	{
		if (_fixtureRowsConsidered.Length > 0) Array.Clear(_fixtureRowsConsidered, 0, _fixtureRowsConsidered.Length);
		if (_fixtureRowsProcessed.Length > 0) Array.Clear(_fixtureRowsProcessed, 0, _fixtureRowsProcessed.Length);
		if (_fixtureRowsSkipped.Length > 0) Array.Clear(_fixtureRowsSkipped, 0, _fixtureRowsSkipped.Length);
		if (_fixtureRowsZeroHit.Length > 0) Array.Clear(_fixtureRowsZeroHit, 0, _fixtureRowsZeroHit.Length);
	}

