		if (_fixtureDiagnosticHitFoundAfterBudgetWarning.Length > 0)
		{
			Array.Clear(_fixtureDiagnosticHitFoundAfterBudgetWarning, 0, _fixtureDiagnosticHitFoundAfterBudgetWarning.Length);
