			Array.Clear(_fixtureDiagnosticFinalStepCount, 0, _fixtureDiagnosticFinalStepCount.Length);
		}
		if (_fixtureDiagnosticHitClass.Length > 0)
		{
			Array.Clear(_fixtureDiagnosticHitClass, 0, _fixtureDiagnosticHitClass.Length);
		}
		if (_fixtureDiagnosticFirstAcceptedHadHit.Length > 0)
		{
			Array.Clear(_fixtureDiagnosticFirstAcceptedHadHit, 0, _fixtureDiagnosticFirstAcceptedHadHit.Length);
		}
		if (_fixtureDiagnosticFirstAcceptedHitDistance.Length > 0)
		{
			for (int i = 0; i < _fixtureDiagnosticFirstAcceptedHitDistance.Length; i++)
				_fixtureDiagnosticFirstAcceptedHitDistance[i] = -1f;
		}
		if (_fixtureDiagnosticFirstAcceptedHitNormal.Length > 0)
		{
			Array.Clear(_fixtureDiagnosticFirstAcceptedHitNormal, 0, _fixtureDiagnosticFirstAcceptedHitNormal.Length);
		}
		if (_fixtureDiagnosticFirstAcceptedHitPosition.Length > 0)
		{
			Array.Clear(_fixtureDiagnosticFirstAcceptedHitPosition, 0, _fixtureDiagnosticFirstAcceptedHitPosition.Length);
		}
		if (_fixtureDiagnosticFirstAcceptedColliderId.Length > 0)
		{
			Array.Clear(_fixtureDiagnosticFirstAcceptedColliderId, 0, _fixtureDiagnosticFirstAcceptedColliderId.Length);
		}
		if (_fixtureDiagnosticFirstAcceptedPrimitiveOrShapeId.Length > 0)
		{
			for (int i = 0; i < _fixtureDiagnosticFirstAcceptedPrimitiveOrShapeId.Length; i++)
				_fixtureDiagnosticFirstAcceptedPrimitiveOrShapeId[i] = -1;
		}
		if (_fixtureDiagnosticFirstAcceptedSegmentIndex.Length > 0)
		{
			for (int i = 0; i < _fixtureDiagnosticFirstAcceptedSegmentIndex.Length; i++)
				_fixtureDiagnosticFirstAcceptedSegmentIndex[i] = -1;
		}
		if (_fixtureDiagnosticFirstAcceptedCandidateCount.Length > 0)
		{
			for (int i = 0; i < _fixtureDiagnosticFirstAcceptedCandidateCount.Length; i++)
				_fixtureDiagnosticFirstAcceptedCandidateCount[i] = -1;
		}
	}

	private void EnsureFixtureRowParticipationCapacity(int filmHeight)
	{
		int resolvedHeight = Math.Max(0, filmHeight);
		if (_fixtureRowsConsidered.Length != resolvedHeight)
		{
			_fixtureRowsConsidered = new byte[resolvedHeight];
			_fixtureRowsProcessed = new byte[resolvedHeight];
			_fixtureRowsSkipped = new byte[resolvedHeight];
			_fixtureRowsZeroHit = new byte[resolvedHeight];
			_fixtureRowsStarted = new byte[resolvedHeight];
			_fixtureRowsCompleted = new byte[resolvedHeight];
			_fixtureRowsPartiallyWritten = new byte[resolvedHeight];
			_fixtureRowsEarlyTerminated = new byte[resolvedHeight];
		}
	}

	private void RecordFixtureRowParticipationBand(
		int bandStart,
		int bandEnd,
		bool markProcessed,
		bool markSkipped,
		bool markZeroHit)
	{
		int filmHeight = Math.Max(0, _filmHeight);
		EnsureFixtureRowParticipationCapacity(filmHeight);
		if (filmHeight <= 0)
		{
			return;
		}

		int start = Mathf.Clamp(bandStart, 0, filmHeight);
		int end = Mathf.Clamp(bandEnd, 0, filmHeight);
		if (end <= start)
		{
			return;
		}

		MarkFixtureRowRange(_fixtureRowsConsidered, start, end);
		if (markProcessed)
		{
			MarkFixtureRowRange(_fixtureRowsProcessed, start, end);
		}
		if (markSkipped)
		{
			MarkFixtureRowRange(_fixtureRowsSkipped, start, end);
		}
		if (markZeroHit)
		{
			MarkFixtureRowRange(_fixtureRowsZeroHit, start, end);
		}
	}

	private static void MarkFixtureRowRange(byte[] rows, int start, int end)
	{
		if (rows.Length == 0)
		{
			return;
		}

		int clampedStart = Math.Max(0, Math.Min(start, rows.Length));
		int clampedEnd = Math.Max(clampedStart, Math.Min(end, rows.Length));
		for (int index = clampedStart; index < clampedEnd; index++)
		{
			rows[index] = 1;
		}
	}

	private void RecordFixtureRowWriteStart(int row)
	{
		int filmHeight = Math.Max(0, _filmHeight);
		EnsureFixtureRowParticipationCapacity(filmHeight);
		if (row < 0 || row >= _fixtureRowsStarted.Length)
		{
			return;
		}

		_fixtureRowsStarted[row] = 1;
	}

	private void RecordFixtureRowWriteOutcome(int row, bool rowHadWrites, bool rowCompleted)
	{
		if (row < 0 || row >= _fixtureRowsStarted.Length)
		{
			return;
		}

		if (rowCompleted)
		{
			_fixtureRowsCompleted[row] = 1;
			return;
		}

		_fixtureRowsEarlyTerminated[row] = 1;
		if (rowHadWrites)
		{
			_fixtureRowsPartiallyWritten[row] = 1;
		}
	}

	private static int CountMarkedRows(byte[] rows)
	{
		int count = 0;
		for (int index = 0; index < rows.Length; index++)
		{
			if (rows[index] != 0)
			{
				count++;
			}
		}
		return count;
	}

	private void RecordTraversalOverlayActiveRect(int x, int y, int width, int height)
	{
		_traversalOverlayActiveX = Math.Max(0, x);
		_traversalOverlayActiveY = Math.Max(0, y);
		_traversalOverlayActiveW = Math.Max(1, width);
		_traversalOverlayActiveH = Math.Max(1, height);
	}

	private void PushTraversalOverlayStateToFilmOverlay(int filmW, int filmH, string traversalMode, int yStart, int yEnd)
	{
		if (_filmOverlay == null || !GodotObject.IsInstanceValid(_filmOverlay))
			return;

		if (!_filmOverlay.ShowTraversalOverlay && !_filmOverlay.ShowTraversalMinimap)
			return;

		if (filmW <= 0 || filmH <= 0)
		{
			_filmOverlay.ClearTraversalOverlayState();
			return;
		}

		int tileSize = Math.Max(1, _filmOverlay.TraversalOverlayTileSize);
		int cols = Math.Max(1, (filmW + tileSize - 1) / tileSize);
		int rows = Math.Max(1, (filmH + tileSize - 1) / tileSize);
		int tileCount = cols * rows;
		if (_traversalOverlayTileStates.Length != tileCount)
			_traversalOverlayTileStates = new byte[tileCount];
		else
			Array.Clear(_traversalOverlayTileStates, 0, _traversalOverlayTileStates.Length);

		for (int ty = 0; ty < rows; ty++)
		{
			int row0 = ty * tileSize;
			int row1 = Math.Min(filmH, row0 + tileSize);
			if (row0 >= row1)
				continue;

			bool allComplete = true;
			bool anyStartedOrPartial = false;
			for (int row = row0; row < row1; row++)
			{
				bool completed = row < _fixtureRowsCompleted.Length && _fixtureRowsCompleted[row] != 0;
				bool started = row < _fixtureRowsStarted.Length && _fixtureRowsStarted[row] != 0;
				bool partial = row < _fixtureRowsPartiallyWritten.Length && _fixtureRowsPartiallyWritten[row] != 0;
				if (!completed)
					allComplete = false;
				if (started || partial || completed)
					anyStartedOrPartial = true;
			}

			bool pendingPass1 = _pendingBandHasPass1 &&
				_pendingBandRowStart < row1 &&
				(_pendingBandRowStart + Math.Max(0, _pendingBandRowCount)) > row0;

			byte state = allComplete ? (byte)2 : (pendingPass1 || anyStartedOrPartial ? (byte)1 : (byte)0);
			int offset = ty * cols;
			for (int tx = 0; tx < cols; tx++)
				_traversalOverlayTileStates[offset + tx] = state;
		}

		string normalizedMode = NormalizeRenderTestFirstPassTraversalMode(traversalMode);
		Rect2I activeRect = default;
		bool activeKnown = false;
		bool useTileMarker = (normalizedMode == "tile" || normalizedMode == "checkerboard") &&
			_traversalOverlayActiveX >= 0 &&
			_traversalOverlayActiveY >= 0 &&
			_traversalOverlayActiveW > 0 &&
			_traversalOverlayActiveH > 0;
		if (useTileMarker)
		{
			activeRect = new Rect2I(
				Mathf.Clamp(_traversalOverlayActiveX, 0, filmW),
				Mathf.Clamp(_traversalOverlayActiveY, 0, filmH),
				Mathf.Clamp(_traversalOverlayActiveW, 1, filmW),
				Mathf.Clamp(_traversalOverlayActiveH, 1, filmH));
			activeKnown = true;
		}
		else
		{
			int activeY = _pendingBandHasPass1 ? _pendingBandRowStart : yStart;
			int activeH = Math.Max(1, yEnd - yStart);
			activeRect = new Rect2I(0, Mathf.Clamp(activeY, 0, filmH), filmW, Math.Min(activeH, filmH));
			activeKnown = true;
		}

		_filmOverlay.SetTraversalOverlayState(
			filmW,
			filmH,
			tileSize,
			tileSize,
			_traversalOverlayTileStates.AsSpan(0, tileCount),
			cols,
			rows,
			activeRect,
			activeKnown,
			normalizedMode,
			CountMarkedRows(_fixtureRowsCompleted));
	}

	private static bool IsCategoricalVoidPixel(Color color)
	{
		return color.R <= 0.001f &&
			color.G <= 0.001f &&
			color.B <= 0.001f &&
			color.A >= 0.999f;
	}

	private static int FindFirstMarkedRow(byte[] rows)
	{
		for (int index = 0; index < rows.Length; index++)
		{
			if (rows[index] != 0)
			{
				return index;
			}
		}
		return -1;
	}

	private static int FindLastMarkedRow(byte[] rows)
	{
		for (int index = rows.Length - 1; index >= 0; index--)
		{
			if (rows[index] != 0)
			{
				return index;
			}
		}
		return -1;
	}

	private static string BuildMarkedRowRanges(byte[] rows)
	{
		if (rows.Length == 0)
		{
			return "";
		}

		System.Text.StringBuilder builder = new System.Text.StringBuilder();
		int rangeStart = -1;
		for (int index = 0; index <= rows.Length; index++)
		{
			bool marked = index < rows.Length && rows[index] != 0;
			if (marked)
			{
				if (rangeStart < 0)
				{
					rangeStart = index;
				}
				continue;
			}

			if (rangeStart < 0)
			{
				continue;
			}

			int rangeEnd = index - 1;
			if (builder.Length > 0)
			{
				builder.Append(",");
			}
			builder.Append(rangeStart.ToString(CultureInfo.InvariantCulture));
			if (rangeEnd > rangeStart)
			{
				builder.Append("-").Append(rangeEnd.ToString(CultureInfo.InvariantCulture));
			}
			rangeStart = -1;
		}

		return builder.ToString();
	}

	private static string FormatCompactRowRanges(string ranges)
	{
		return string.IsNullOrWhiteSpace(ranges) ? "-" : ranges;
	}

