	private void ResetRenderHealthOverlayWindowState()
	{
		_overlayRolling.Reset();
		_lastRenderHealthEmissionTimestamp = 0;
		_hasLastRenderHealthEmissionTimestamp = false;
		_rowsPerSecEma = 0.0;
		_msPerRowEma = 0.0;
		_hasRenderThroughputEma = false;
		_renderThroughputWindowTrusted = false;
	}

	private void UpdateRenderThroughputMetricsFromRenderHealth(long rowsAdvancedInWindow, bool windowTrusted)
	{
		long now = Stopwatch.GetTimestamp();
		if (!_hasLastRenderHealthEmissionTimestamp)
		{
			_lastRenderHealthEmissionTimestamp = now;
			_hasLastRenderHealthEmissionTimestamp = true;
			_renderThroughputWindowTrusted = false;
			return;
		}

		long deltaTicks = now - _lastRenderHealthEmissionTimestamp;
		_lastRenderHealthEmissionTimestamp = now;
		_renderThroughputWindowTrusted = false;
		if (deltaTicks <= 0)
			return;

		double elapsedSec = deltaTicks / (double)Stopwatch.Frequency;
		if (!double.IsFinite(elapsedSec) || elapsedSec <= 0.0 || !windowTrusted || rowsAdvancedInWindow <= 0)
			return;

		double rowsPerSec = rowsAdvancedInWindow / elapsedSec;
		double msPerRow = (elapsedSec * 1000.0) / rowsAdvancedInWindow;
		if (!double.IsFinite(rowsPerSec) || !double.IsFinite(msPerRow) || rowsPerSec <= 0.0 || msPerRow <= 0.0)
			return;

		if (!_hasRenderThroughputEma)
		{
			_rowsPerSecEma = rowsPerSec;
			_msPerRowEma = msPerRow;
			_hasRenderThroughputEma = true;
		}
		else
		{
			_rowsPerSecEma += (rowsPerSec - _rowsPerSecEma) * OverlayRenderThroughputEmaAlpha;
			_msPerRowEma += (msPerRow - _msPerRowEma) * OverlayRenderThroughputEmaAlpha;
		}

		_renderThroughputWindowTrusted = true;
	}

	private void EmitRenderMetricsOverlay()
	{
		if (_filmOverlay == null || !GodotObject.IsInstanceValid(_filmOverlay))
			return;

		_overlayRolling.SetWindowSeconds(RenderHealthRollingWindowSec);
		_presentRolling.SetWindowSeconds(RenderHealthRollingWindowSec);
		long now = Stopwatch.GetTimestamp();
		OverlayRollingSnapshot rolling = _overlayRolling.Snapshot(now);
		OverlayRollingSnapshot presentRolling = _presentRolling.Snapshot(now);
		double elapsedSec = rolling.ElapsedSec;
		if ((!double.IsFinite(elapsedSec) || elapsedSec <= 0.0) && rolling.StepMsTotal > 0.0)
			elapsedSec = rolling.StepMsTotal / 1000.0;
		bool hasElapsed = elapsedSec > 0.0 && double.IsFinite(elapsedSec);
		bool hasSteps = rolling.Steps > 0;
		bool hasRows = rolling.RowsAdvanced > 0 && hasElapsed;
		double rollingRowsPerSec = hasRows ? (rolling.RowsAdvanced / elapsedSec) : 0.0;
		double rollingMsPerRow = hasRows ? (rolling.StepMsTotal / rolling.RowsAdvanced) : 0.0;
		double rollingMsPerStep = hasSteps ? (rolling.StepMsTotal / rolling.Steps) : 0.0;
		double rollingStepsPerSec = hasSteps && hasElapsed ? (rolling.Steps / elapsedSec) : 0.0;
		double rollingHitsPerSec = hasSteps && hasElapsed ? (rolling.Hits / elapsedSec) : 0.0;
		double rollingRayTestsPerSec = hasElapsed && rolling.RayTestsSamples > 0 ? (rolling.RayTests / elapsedSec) : 0.0;
		double presentElapsedSec = presentRolling.ElapsedSec;
		bool hasPresentElapsed = presentElapsedSec > 0.0 && double.IsFinite(presentElapsedSec);
		double rollingPresentsPerSec = hasPresentElapsed && presentRolling.Steps > 0 ? (presentRolling.Steps / presentElapsedSec) : 0.0;

		_overlayHudSb.Clear();
		var lines = new System.Collections.Generic.List<string>(6);
		string hudMetadata = BuildHudMetadataLine();
		if (!string.IsNullOrWhiteSpace(hudMetadata))
		{
			MaybeLogHudMetadata(hudMetadata);
			AddHudMetadataOverlayLines(lines);
		}
		MaybeLogHudRuntimeSummary();
		RenderHealthSample latest = default;
		bool hasLatest = _renderHealthCount > 0;
		if (hasLatest)
			latest = GetRenderHealthSampleFromEnd(0);
		bool showProbeOnlyStatus = !UpdateEveryFrame && !hasLatest && HasHudProbeStatus();
		if (showProbeOnlyStatus)
		{
			AddHudProbeStatusLines(lines);
			Vector2 probeOverlayBasePos = new Vector2(16f, 24f);
			DebugOverlayBus.AddText(probeOverlayBasePos, string.Join("\n", lines), Colors.White);
			return;
		}

		double engineFps = Engine.GetFramesPerSecond();
		string FmtInt(bool has, int value) => has ? value.ToString() : "na";
		string FmtLong(bool has, long value) => has ? value.ToString() : "na";
		string FmtBool01(bool has, bool value) => has ? (value ? "1" : "0") : "na";
		string FmtDouble(bool has, double value, string fmt)
			=> (has && double.IsFinite(value)) ? value.ToString(fmt) : "na";

		string rowsPerSecText = (hasRows && double.IsFinite(rollingRowsPerSec) && rollingRowsPerSec > 0.0)
			? rollingRowsPerSec.ToString("0.0")
			: "na";
		string msPerRowText = (hasRows && double.IsFinite(rollingMsPerRow) && rollingMsPerRow > 0.0)
			? rollingMsPerRow.ToString("0.0")
			: "na";
		string msPerStepText = (hasSteps && double.IsFinite(rollingMsPerStep) && rollingMsPerStep >= 0.0)
			? rollingMsPerStep.ToString("0.0")
			: "na";
		string stepsPerSecText = (hasSteps && hasElapsed && double.IsFinite(rollingStepsPerSec) && rollingStepsPerSec >= 0.0)
			? rollingStepsPerSec.ToString("0.0")
			: "na";
		string hitsPerSecText = (hasSteps && hasElapsed && double.IsFinite(rollingHitsPerSec) && rollingHitsPerSec >= 0.0)
			? rollingHitsPerSec.ToString("0.0")
			: "na";
		string rayTestsPerSecText = (hasElapsed && rolling.RayTestsSamples > 0 && double.IsFinite(rollingRayTestsPerSec) && rollingRayTestsPerSec >= 0.0)
			? rollingRayTestsPerSec.ToString("0.0")
			: "na";
		string presentsPerSecText = (hasPresentElapsed && presentRolling.Steps > 0 && double.IsFinite(rollingPresentsPerSec) && rollingPresentsPerSec >= 0.0)
			? rollingPresentsPerSec.ToString("0.0")
			: "na";
		string etaText = "na";
		double etaFullFilmSec = 0.0;
		if (_filmHeight > 0 && hasRows && rollingRowsPerSec > 0.0)
		{
			etaFullFilmSec = _filmHeight / rollingRowsPerSec;
			if (double.IsFinite(etaFullFilmSec) && etaFullFilmSec >= 0.0)
				etaText = etaFullFilmSec.ToString("0.0");
		}
		bool latestHasHitRate = hasLatest && latest.TracedPixels > 0;
		double latestHitRate = latestHasHitRate ? (double)latest.Hits / latest.TracedPixels : 0.0;

		_overlayHudSb.Append("RH step=").Append(FmtInt(hasLatest, latest.StepIndex))
			.Append(" row=").Append(FmtInt(hasLatest, latest.RowCursorAfter))
			.Append(" adv=").Append(FmtInt(hasLatest, latest.RowsAdvanced))
			.Append(" bands=").Append(FmtInt(hasLatest, latest.BandsProcessed))
			.Append(" hitRate=").Append(FmtDouble(latestHasHitRate, latestHitRate, "0.000"))
			.Append(" fps=").Append(FmtDouble(double.IsFinite(engineFps) && engineFps >= 0.0, engineFps, "0.0"))
			.Append(" present/s=").Append(presentsPerSecText)
			.Append(" tickMs=").Append(FmtDouble(double.IsFinite(_lastFrameRenderMs) && _lastFrameRenderMs >= 0.0, _lastFrameRenderMs, "0.0"))
			.Append(" eta=").Append(etaText);
		lines.Add(_overlayHudSb.ToString());

		_overlayHudSb.Clear();
		_overlayHudSb.Append("roll ms/step=").Append(msPerStepText)
			.Append(" steps/s=").Append(stepsPerSecText)
			.Append(" rows/s=").Append(rowsPerSecText)
			.Append(" ms/row=").Append(msPerRowText)
			.Append(" hits/s=").Append(hitsPerSecText)
			.Append(" rayTests/s=").Append(rayTestsPerSecText);
		lines.Add(_overlayHudSb.ToString());

		_overlayHudSb.Clear();
		_overlayHudSb.Append("refresh px=").Append(_lastPresentedPixelsUpdated)
			.Append(" cover=").Append(FmtDouble(_filmWidth > 0 && _filmHeight > 0, _lastPresentedCoverageRatio, "0.000"))
			.Append(" fullFrames=").Append(_lastFullRefreshMeasured && _lastFramesToFullRefresh > 0 ? _lastFramesToFullRefresh.ToString() : "na")
			.Append(" fullMs=").Append(FmtDouble(_lastFullRefreshMeasured, _lastTimeToFullRefreshMs, "0.0"))
			.Append(" fullFps=").Append(FmtDouble(_lastFullRefreshMeasured, _lastEffectiveFullRefreshFps, "0.00"));
		lines.Add(_overlayHudSb.ToString());

		_overlayHudSb.Clear();
		_overlayHudSb.Append("prune=").Append(hasLatest ? (latest.UseGeometryTLASPruning ? "on" : "off") : "na")
			.Append(" trusted=").Append(FmtBool01(_testHasRenderHealthSnapshot, _testLastGeomTrusted))
			.Append(" reason=").Append(_testHasRenderHealthSnapshot ? _testLastGeomTrustReason : "na")
			.Append(" perPxOff=").Append(FmtDouble(_testHasRenderHealthSnapshot && _testLastGeomPerPxOffAvailable, _testLastGeomPerPxOff, "0.000"))
			.Append(" perPxOn=").Append(FmtDouble(_testHasRenderHealthSnapshot && _testLastGeomPerPxOnAvailable, _testLastGeomPerPxOn, "0.000"))
			.Append(" saved%=").Append(FmtDouble(_testHasRenderHealthSnapshot && _testLastGeomSavedPctAvailable, _testLastGeomSavedPct, "0.00"));
		lines.Add(_overlayHudSb.ToString());

		if (_renderHealthTestTrustEnforcementEnabled || DebugRenderHealthRollingOverlay)
		{
			int minP2 = GetRenderHealthMinP2SamplesForTrustEffective();
			int p2Every = RenderHealthPass2SampleEveryNSegments;
			if (_renderHealthTestTrustEnforcementEnabled && _renderHealthTestPass2SampleEveryNSegmentsOverride > 0)
				p2Every = _renderHealthTestPass2SampleEveryNSegmentsOverride;
			p2Every = Math.Max(1, p2Every);
			_overlayHudSb.Clear();
			_overlayHudSb.Append("gate metPix=").Append(FmtBool01(_testHasRenderHealthSnapshot, _testLastTrustGeomPixMet))
				.Append(" metRay=").Append(FmtBool01(_testHasRenderHealthSnapshot, _testLastTrustRayTestsMet))
				.Append(" metP2=").Append(FmtBool01(_testHasRenderHealthSnapshot, _testLastTrustP2Met))
				.Append(" minPix=").Append(_renderHealthTestMinGeomPixProcessedPerWindow)
				.Append(" minRay=").Append(_renderHealthTestMinGeomRayTestsTotalPerWindow)
				.Append(" minP2=").Append(minP2)
				.Append(" p2Every=").Append(p2Every);
			lines.Add(_overlayHudSb.ToString());
		}

		if (_renderHealthTestTrustEnforcementEnabled)
		{
			_overlayHudSb.Clear();
			_overlayHudSb.Append("raw pix=").Append(FmtLong(_testHasRenderHealthSnapshot, _testLastGeomPixProcessedRaw))
				.Append(" rays=").Append(FmtLong(_testHasRenderHealthSnapshot, _testLastGeomRayTestsTotalRaw))
				.Append(" p2=").Append(FmtLong(_testHasRenderHealthSnapshot, _testLastP2SampRaw))
				.Append(" noCand=").Append(FmtLong(_testHasRenderHealthSnapshot, _testLastGeomPixNoCandRaw))
				.Append(" seg0%=").Append(FmtDouble(_testHasRenderHealthSnapshot && _testLastGeomSegZeroRatePctAvailable, _testLastGeomSegZeroRatePct, "0.00"));
			lines.Add(_overlayHudSb.ToString());
		}

		bool showDiag = DebugRenderHealthRollingOverlay
			|| !_testHasRenderHealthSnapshot
			|| !string.Equals(_testLastGeomTrustReason, "ok", StringComparison.Ordinal);
		if (showDiag)
		{
			string exitText = hasLatest
				? (string.IsNullOrEmpty(latest.BudgetExitReason) ? "none" : latest.BudgetExitReason)
				: "na";
			_overlayHudSb.Clear();
			_overlayHudSb.Append("diag qray0=").Append(FmtInt(hasLatest, latest.QuickRayZeroCount))
				.Append(" hybridFB=").Append(FmtInt(hasLatest, latest.HybridFallbackCount))
				.Append(" exit=").Append(exitText)
				.Append(" topExit=").Append(_testHasRenderHealthSnapshot ? _testLastTopExit : "na")
				.Append(" stalled=").Append(FmtInt(hasLatest, _renderHealthStallSteps));
			lines.Add(_overlayHudSb.ToString());
		}

		if (lines.Count > 7)
			lines.RemoveRange(7, lines.Count - 7);

		Vector2 overlayBasePos = new Vector2(16f, 24f);
		DebugOverlayBus.AddText(overlayBasePos, string.Join("\n", lines), Colors.White);
	}

	public void SetHudFixtureName(string fixtureName)
	{
		_hudFixtureName = NormalizeHudValue(fixtureName);
	}

	public void SetHudTransportModel(string transportModel)
	{
		_hudTransportModel = NormalizeHudValue(transportModel);
	}

	public void SetHudProfileToken(string profileToken)
	{
		_hudProfileToken = NormalizeHudValue(profileToken);
	}

	public void SetHudSourcePatternMode(string sourcePatternMode)
	{
		_hudSourcePatternMode = NormalizeHudValue(sourcePatternMode);
	}

	public void SetHudRenderTestMode(string renderTestMode)
	{
		_hudRenderTestMode = NormalizeHudValue(renderTestMode).ToUpperInvariant();
	}

	public void SetHudRenderLoopStatus(string renderLoopStatus)
	{
		_hudRenderLoopStatus = NormalizeHudValue(renderLoopStatus).ToUpperInvariant();
	}

	public void SetHudRenderProbeRayCount(int rayCount)
	{
		_hudRenderProbeRayCount = rayCount >= 0 ? rayCount : -1;
	}

	public void SetHudMetricSteeringLaw(string metricSteeringLaw)
	{
		_hudMetricSteeringLaw = NormalizeHudValue(metricSteeringLaw);
	}

	public void SetHudMetricGainOverride(float metricGainOverride, bool active)
	{
		_hudMetricGainOverride = float.IsFinite(metricGainOverride) ? metricGainOverride : 1.0f;
		_hudMetricGainOverrideActive = active && float.IsFinite(metricGainOverride);
	}

	private string BuildHudMetadataLine()
	{
		_overlayHudSb.Clear();
		AppendHudToken(_overlayHudSb, "fixture", ResolveHudFixtureName());
		AppendHudToken(_overlayHudSb, "transport", ResolveHudTransportModel());
		AppendHudToken(_overlayHudSb, "profile", ResolveHudProfileToken());

		if (TryResolveHudMetricGainOverride(out float metricGainOverride))
		{
			AppendHudToken(_overlayHudSb, "metricGain", metricGainOverride.ToString("0.0##"));
		}
		string metricSteeringLaw = ResolveHudMetricSteeringLaw();
		if (!string.IsNullOrWhiteSpace(metricSteeringLaw))
		{
			AppendHudToken(_overlayHudSb, "metricLaw", metricSteeringLaw);
		}

		AppendHudToken(_overlayHudSb, "sourcePattern", ResolveHudSourcePatternMode());
		AppendHudToken(_overlayHudSb, "MODE", ResolveHudModePath());
		if (ShouldShowRuntimeMacroHudStatus())
		{
			AppendHudToken(_overlayHudSb, "macro", ResolveRuntimeMacroHudToken());
		}
		AppendHudToken(_overlayHudSb, "FILM_ACCUM", ResolveHudFilmAccumulationStatus());
		return _overlayHudSb.ToString();
	}

	private void AddHudMetadataOverlayLines(System.Collections.Generic.List<string> lines)
	{
		if (lines == null)
			return;

		_overlayHudSb.Clear();
		AppendHudToken(_overlayHudSb, "fixture", ResolveHudFixtureName());
		AppendHudToken(_overlayHudSb, "transport", ResolveHudTransportModel());
		AppendHudToken(_overlayHudSb, "mode", ResolveHudModePath());
		if (_overlayHudSb.Length > 0)
			lines.Add(_overlayHudSb.ToString());

		_overlayHudSb.Clear();
		AppendHudToken(_overlayHudSb, "profile", ResolveHudProfileToken());
		if (TryResolveHudMetricGainOverride(out float metricGainOverride))
		{
			AppendHudToken(_overlayHudSb, "metricGain", metricGainOverride.ToString("0.0##"));
		}
		string metricSteeringLaw = ResolveHudMetricSteeringLaw();
		if (!string.IsNullOrWhiteSpace(metricSteeringLaw))
		{
			AppendHudToken(_overlayHudSb, "metricLaw", metricSteeringLaw);
		}
		AppendHudToken(_overlayHudSb, "sourcePattern", ResolveHudSourcePatternMode());
		if (ShouldShowRuntimeMacroHudStatus())
		{
			AppendHudToken(_overlayHudSb, "macro", ResolveRuntimeMacroHudToken());
			AppendHudToken(_overlayHudSb, "camMotion", _runtimeMacroCameraMoving ? "moving" : "still");
		}
		AppendHudToken(_overlayHudSb, "filmAccum", ResolveHudFilmAccumulationStatus());
		if (_overlayHudSb.Length > 0)
			lines.Add(_overlayHudSb.ToString());
	}

	private void MaybeLogHudMetadata(string metadata)
	{
		if (string.IsNullOrWhiteSpace(metadata) ||
			string.Equals(metadata, _lastLoggedHudMetadata, StringComparison.Ordinal))
		{
			return;
		}

		_lastLoggedHudMetadata = metadata;
		GD.Print($"[HUDMeta] {metadata}");
	}

	private void MaybeLogHudRuntimeSummary()
	{
		string summary = BuildHudRuntimeSummaryLine();
		if (string.IsNullOrWhiteSpace(summary) ||
			string.Equals(summary, _lastLoggedHudRuntimeSummary, StringComparison.Ordinal))
		{
			return;
		}

		_lastLoggedHudRuntimeSummary = summary;
		GD.Print($"[RuntimeMode] {summary}");
	}

	private string ResolveHudFixtureName()
	{
		if (!string.IsNullOrWhiteSpace(_hudFixtureName))
			return _hudFixtureName;

		string scenePath = GetTree().CurrentScene?.SceneFilePath ?? string.Empty;
		if (scenePath.IndexOf("blackhole", StringComparison.OrdinalIgnoreCase) >= 0)
			return "blackhole_minimal";
		if (scenePath.IndexOf("einstein", StringComparison.OrdinalIgnoreCase) >= 0)
			return "einstein_ring_minimal";
		if (scenePath.IndexOf("atomic-orbital-grin-room", StringComparison.OrdinalIgnoreCase) >= 0)
			return "atomic_orbital_grin_room";
		if (scenePath.IndexOf("atomic-orbital-visual-observatory", StringComparison.OrdinalIgnoreCase) >= 0)
			return "atomic_orbital_visual_observatory";
		if (scenePath.IndexOf("curved-minimal", StringComparison.OrdinalIgnoreCase) >= 0)
			return "curved_minimal";
		if (scenePath.IndexOf("straight", StringComparison.OrdinalIgnoreCase) >= 0)
			return "straight";
		return string.Empty;
	}

	private string ResolveHudTransportModel()
	{
		if (!string.IsNullOrWhiteSpace(_hudTransportModel))
			return _hudTransportModel;

		foreach (string arg in GetHudCmdArgs())
		{
			if (TryGetHudArgValue(arg, "--blackhole-transport-model=", out string value) ||
				TryGetHudArgValue(arg, "--einstein-transport-model=", out value) ||
				TryGetHudArgValue(arg, "--transport-model=", out value))
			{
				return NormalizeTransportHudValue(value);
			}
		}

		string scenePath = GetTree().CurrentScene?.SceneFilePath ?? string.Empty;
		if (scenePath.IndexOf("-metric", StringComparison.OrdinalIgnoreCase) >= 0)
			return TransportModel.Metric_NullGeodesic.ToString();
		if (scenePath.IndexOf("-grin", StringComparison.OrdinalIgnoreCase) >= 0)
			return TransportModel.GRIN_Optical.ToString();

		return string.Empty;
	}

	private string ResolveHudProfileToken()
	{
		if (!string.IsNullOrWhiteSpace(_hudProfileToken))
			return _hudProfileToken;

		foreach (string arg in GetHudCmdArgs())
		{
			if (TryGetHudArgValue(arg, "--render-test-profile=", out string value))
				return NormalizeHudValue(value);
		}

		return string.Empty;
	}

	private string ResolveHudSourcePatternMode()
	{
		return _hudSourcePatternMode;
	}

	private bool ShouldEmitMetadataOnlyOverlay()
	{
		return HasHudProbeStatus() || !string.IsNullOrWhiteSpace(ResolveHudModePath());
	}

	private bool HasHudProbeStatus()
	{
		return !string.IsNullOrWhiteSpace(_hudRenderTestMode)
			|| !string.IsNullOrWhiteSpace(_hudRenderLoopStatus)
			|| _hudRenderProbeRayCount >= 0;
	}

	private void AddHudProbeStatusLines(System.Collections.Generic.List<string> lines)
	{
		if (lines == null)
			return;

		if (_hudRenderProbeRayCount >= 0)
			lines.Add($"RAYS={_hudRenderProbeRayCount}");
	}

	private string ResolveHudModePath()
	{
		if (!string.IsNullOrWhiteSpace(_hudRenderTestMode))
			return _hudRenderTestMode;

		foreach (string arg in GetHudCmdArgs())
		{
			string trimmed = NormalizeHudValue(arg);
			if (string.Equals(trimmed, "--render-test", StringComparison.OrdinalIgnoreCase) ||
				trimmed.StartsWith("--render-test-", StringComparison.OrdinalIgnoreCase) ||
				trimmed.StartsWith("--render-test-fixture=", StringComparison.OrdinalIgnoreCase))
			{
				return "RENDER_TEST_MATRIX";
			}
		}

		return UpdateEveryFrame ? "FULL_RENDER" : "FIXTURE_PROBE";
	}

	private string ResolveHudFilmAccumulationStatus()
	{
		if (!string.IsNullOrWhiteSpace(_hudRenderLoopStatus))
		{
			string explicitStatus = _hudRenderLoopStatus.ToUpperInvariant();
			if (explicitStatus is "ENABLED" or "ON" or "TRUE" or "1")
				return "ON";
			if (explicitStatus is "DISABLED" or "OFF" or "FALSE" or "0")
				return "OFF";
			return explicitStatus;
		}

		foreach (string arg in GetHudCmdArgs())
		{
			string trimmed = NormalizeHudValue(arg);
			if (string.Equals(trimmed, "--render-test", StringComparison.OrdinalIgnoreCase) ||
				trimmed.StartsWith("--render-test-", StringComparison.OrdinalIgnoreCase) ||
				trimmed.StartsWith("--render-test-fixture=", StringComparison.OrdinalIgnoreCase))
			{
				return "ON";
			}
		}

		return UpdateEveryFrame ? "ON" : "OFF";
	}

	private string BuildHudRuntimeSummaryLine()
	{
		_overlayHudSb.Clear();
		AppendHudToken(_overlayHudSb, "scene", ResolveHudSceneName());
		AppendHudToken(_overlayHudSb, "fixture", ResolveHudFixtureName());
		AppendHudToken(_overlayHudSb, "transport", ResolveHudTransportModel());
		AppendHudToken(_overlayHudSb, "mode", ResolveHudModePath());
		if (ShouldShowRuntimeMacroHudStatus())
		{
			AppendHudToken(_overlayHudSb, "macro", ResolveRuntimeMacroHudToken());
			AppendHudToken(_overlayHudSb, "camMotion", _runtimeMacroCameraMoving ? "moving" : "still");
		}
		AppendHudToken(_overlayHudSb, "filmAccum", ResolveHudFilmAccumulationStatus());
		return _overlayHudSb.ToString();
	}

	private string ResolveRuntimeMacroHudToken()
	{
		if (!_runtimeMacroModeActive)
			return $"inactive({GetRuntimeMacroModeLabel(RuntimeMacroSelectedMode)})";
		return GetRuntimeMacroModeLabel(RuntimeMacroSelectedMode);
	}

	private string ResolveHudSceneName()
	{
		string scenePath = GetTree().CurrentScene?.SceneFilePath ?? string.Empty;
		if (!string.IsNullOrWhiteSpace(scenePath))
			return NormalizeHudValue(Path.GetFileNameWithoutExtension(scenePath));

		return NormalizeHudValue(GetTree().CurrentScene?.Name ?? string.Empty);
	}

	private string ResolveHudMetricSteeringLaw()
	{
		if (!string.IsNullOrWhiteSpace(_hudMetricSteeringLaw))
		{
			return _hudMetricSteeringLaw;
		}

		string transportModel = ResolveHudTransportModel();
		if (!string.Equals(transportModel, TransportModel.Metric_NullGeodesic.ToString(), StringComparison.Ordinal))
		{
			return string.Empty;
		}

		foreach (string arg in GetHudCmdArgs())
		{
			if (TryGetHudArgValue(arg, "--metric-steering-law=", out string value) ||
				TryGetHudArgValue(arg, "--metric-law=", out value))
			{
				return NormalizeMetricSteeringLawHudValue(value);
			}
		}

		return RayBeamRenderer.GetMetricSteeringLawToken(
			RayBeamRenderer.ResolveMetricSteeringLawOverride(MetricSteeringLaw.MetricLaw_CurrentEnvelope));
	}

	private bool TryResolveHudMetricGainOverride(out float metricGainOverride)
	{
		metricGainOverride = 1.0f;
		if (_hudMetricGainOverrideActive)
		{
			metricGainOverride = _hudMetricGainOverride;
			return true;
		}

		string transportModel = ResolveHudTransportModel();
		if (!string.Equals(transportModel, TransportModel.Metric_NullGeodesic.ToString(), StringComparison.Ordinal))
			return false;

		float parsedOverride = RayBeamRenderer.ResolveMetricComparisonScalarOverride();
		if (!float.IsFinite(parsedOverride) || Mathf.IsEqualApprox(parsedOverride, 1.0f))
			return false;

		metricGainOverride = parsedOverride;
		return true;
	}

	private void ApplyHudOverlayVisualSettings()
	{
		if (_filmOverlay == null || !GodotObject.IsInstanceValid(_filmOverlay))
			return;

		_filmOverlay.HudFontScale = ResolveHudOverlayFontScale();
		_filmOverlay.QueueRedraw();
	}

	private float ResolveHudOverlayFontScale()
	{
		float resolved = Mathf.Clamp(HudOverlayFontScale, HudOverlayFontScaleMin, HudOverlayFontScaleMax);
		foreach (string arg in GetHudCmdArgs())
		{
			if (!(TryGetHudArgValue(arg, "--hud-font-scale=", out string value) ||
				TryGetHudArgValue(arg, "--hud-scale=", out value)))
			{
				continue;
			}

			if (float.TryParse(value, NumberStyles.Float, CultureInfo.InvariantCulture, out float parsed) ||
				float.TryParse(value, NumberStyles.Float, CultureInfo.CurrentCulture, out parsed))
			{
				resolved = parsed;
			}
		}

		return Mathf.Clamp(resolved, HudOverlayFontScaleMin, HudOverlayFontScaleMax);
	}

	private static void AppendHudToken(StringBuilder sb, string key, string value)
	{
		if (sb == null || string.IsNullOrWhiteSpace(key) || string.IsNullOrWhiteSpace(value))
			return;

		if (sb.Length > 0)
			sb.Append(' ');

		sb.Append(key).Append('=').Append(value);
	}

	private static string NormalizeHudValue(string value)
	{
		return string.IsNullOrWhiteSpace(value) ? string.Empty : value.Trim();
	}

	private static string NormalizeTransportHudValue(string value)
	{
		string normalized = NormalizeHudValue(value);
		if (string.IsNullOrWhiteSpace(normalized))
			return string.Empty;

		if (string.Equals(normalized, "grin", StringComparison.OrdinalIgnoreCase) ||
			string.Equals(normalized, "optical", StringComparison.OrdinalIgnoreCase))
		{
			return TransportModel.GRIN_Optical.ToString();
		}
		if (string.Equals(normalized, "metric", StringComparison.OrdinalIgnoreCase) ||
			string.Equals(normalized, "nullgeodesic", StringComparison.OrdinalIgnoreCase))
		{
			return TransportModel.Metric_NullGeodesic.ToString();
		}

		return normalized;
	}

	private static string NormalizeMetricSteeringLawHudValue(string value)
	{
		if (string.IsNullOrWhiteSpace(value))
		{
			return string.Empty;
		}

		string normalized = value.Replace("-", string.Empty)
			.Replace("_", string.Empty)
			.Trim()
			.ToLowerInvariant();
		return normalized switch
		{
			"impact" or "impactparameter" or "impactparameterapprox" or "metriclawimpactparameterapprox"
				=> RayBeamRenderer.GetMetricSteeringLawToken(MetricSteeringLaw.MetricLaw_ImpactParameterApprox),
			"current" or "currentenvelope" or "metriclawcurrentenvelope" or "baseline"
				=> RayBeamRenderer.GetMetricSteeringLawToken(MetricSteeringLaw.MetricLaw_CurrentEnvelope),
			_ => NormalizeHudValue(value)
		};
	}

	private static bool TryGetHudArgValue(string arg, string prefix, out string value)
	{
		value = string.Empty;
		if (string.IsNullOrWhiteSpace(arg) || string.IsNullOrWhiteSpace(prefix))
			return false;

		string trimmed = arg.Trim();
		if (!trimmed.StartsWith(prefix, StringComparison.OrdinalIgnoreCase))
			return false;

		value = NormalizeHudValue(trimmed.Substring(prefix.Length));
		return !string.IsNullOrWhiteSpace(value);
	}

	private static string[] GetHudCmdArgs()
	{
		string[] userArgs = OS.GetCmdlineUserArgs();
		string[] args = OS.GetCmdlineArgs();
		if ((userArgs == null || userArgs.Length == 0) && (args == null || args.Length == 0))
			return Array.Empty<string>();
		if (userArgs == null || userArgs.Length == 0)
			return args ?? Array.Empty<string>();
		if (args == null || args.Length == 0)
			return userArgs;

		var merged = new System.Collections.Generic.HashSet<string>(StringComparer.Ordinal);
		var ordered = new System.Collections.Generic.List<string>(userArgs.Length + args.Length);
		for (int i = 0; i < userArgs.Length; i++)
		{
			string token = NormalizeHudValue(userArgs[i]);
			if (!string.IsNullOrWhiteSpace(token) && merged.Add(token))
				ordered.Add(token);
		}
		for (int i = 0; i < args.Length; i++)
		{
			string token = NormalizeHudValue(args[i]);
			if (!string.IsNullOrWhiteSpace(token) && merged.Add(token))
				ordered.Add(token);
		}

		return ordered.ToArray();
	}

	private void ApplyTileMetricsCmdArgs()
	{
		foreach (string arg in GetHudCmdArgs())
		{
			if (TryGetHudArgValue(arg, "--tile-metrics=", out string enabledValue))
			{
				string normalized = enabledValue.Trim().ToLowerInvariant();
				EnableTileMetricsScaffold = normalized is "1" or "true" or "on" or "yes";
				continue;
			}

			if (TryGetHudArgValue(arg, "--tile-metrics-subtile-width=", out string subtileWidthValue)
				&& int.TryParse(subtileWidthValue, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedWidth))
			{
				TileMetricsSubtileWidth = Math.Max(1, parsedWidth);
			}

			if (TryGetHudArgValue(arg, "--tile-metrics-max-logs=", out string maxLogsValue)
				&& int.TryParse(maxLogsValue, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedMaxLogs))
			{
				TileMetricsMaxLogsPerFrame = Math.Max(0, parsedMaxLogs);
			}

			if (TryGetHudArgValue(arg, "--tile-metrics-simulate-reorder=", out string simulateValue))
			{
				string normalized = simulateValue.Trim().ToLowerInvariant();
				EnableTileMetricsReorderSimulation = normalized is "1" or "true" or "on" or "yes";
				continue;
			}

			if (TryGetHudArgValue(arg, "--tile-metrics-reorder-execution=", out string executeValue))
			{
				string normalized = executeValue.Trim().ToLowerInvariant();
				EnableTileMetricsReorderExecution = normalized is "1" or "true" or "on" or "yes";
				continue;
			}

			if (TryGetHudArgValue(arg, "--tile-metrics-persistent-priors=", out string priorsValue))
			{
				string normalized = priorsValue.Trim().ToLowerInvariant();
				EnableTileMetricsPersistentPriors = normalized is "1" or "true" or "on" or "yes";
				continue;
			}

			if (TryGetHudArgValue(arg, "--experimental-subtile-scheduler=", out string schedulerValue))
			{
				string normalized = schedulerValue.Trim().ToLowerInvariant();
				EnableTileMetricsReorderExecution = normalized is "1" or "true" or "on" or "yes";
			}

			if (TryGetHudArgValue(arg, "--tile-metrics-band-seed=", out string bandSeedValue))
			{
				string normalized = bandSeedValue.Trim().ToLowerInvariant();
				EnableTileMetricsBandSeed = normalized is "1" or "true" or "on" or "yes";
				continue;
			}

			if (TryGetHudArgValue(arg, "--tile-metrics-band-seed-path=", out string bandSeedPath) &&
				!string.IsNullOrWhiteSpace(bandSeedPath))
			{
				TileMetricsBandSeedPath = bandSeedPath.Trim();
			}

			if (TryGetHudArgValue(arg, "--object-seeded-tile-scheduler=", out string objectSeededValue))
			{
				string normalized = objectSeededValue.Trim().ToLowerInvariant();
				EnableObjectSeededTileScheduler = normalized is "1" or "true" or "on" or "yes";
				if (EnableObjectSeededTileScheduler)
					EnableTileMetricsScaffold = true;
				continue;
			}

			if (TryGetHudArgValue(arg, "--render-test-traversal=", out string traversalValue))
			{
				string normalized = traversalValue.Trim().ToLowerInvariant().Replace("-", "_");
				if (normalized is "object_seeded_tile" or "object_seeded")
				{
					EnableObjectSeededTileScheduler = true;
					EnableTileMetricsScaffold = true;
				}
				else if (normalized is "tile" or "normal_tile")
				{
					EnableTileMetricsScaffold = true;
				}
				else if (normalized is "shuffled_row" or "experimental_subtile")
				{
					EnableTileMetricsScaffold = true;
					EnableTileMetricsReorderExecution = true;
				}
				continue;
			}

			if (TryGetHudArgValue(arg, "--object-seeded-seed=", out string seedValue)
				&& int.TryParse(seedValue, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedSeed))
			{
				ObjectSeededTileSchedulerSeed = Math.Max(0, parsedSeed);
			}

			if (TryGetHudArgValue(arg, "--object-seeded-max-observers=", out string maxObserversValue)
				&& int.TryParse(maxObserversValue, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedMaxObservers))
			{
				ObjectSeededMaxObservers = Math.Max(0, parsedMaxObservers);
			}

			if (TryGetHudArgValue(arg, "--object-seeded-max-probes=", out string maxProbesValue)
				&& int.TryParse(maxProbesValue, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedMaxProbes))
			{
				ObjectSeededMaxProbes = Math.Max(0, parsedMaxProbes);
			}

			if (TryGetHudArgValue(arg, "--object-seeded-min-confidence=", out string minConfidenceValue)
				&& float.TryParse(minConfidenceValue, NumberStyles.Float, CultureInfo.InvariantCulture, out float parsedMinConfidence))
			{
				ObjectSeededMinConfidence = Math.Clamp(parsedMinConfidence, 0.0f, 1.0f);
			}

			if (TryGetHudArgValue(arg, "--object-seeded-risk-epsilon=", out string riskEpsilonValue)
				&& float.TryParse(riskEpsilonValue, NumberStyles.Float, CultureInfo.InvariantCulture, out float parsedRiskEpsilon))
			{
				ObjectSeededRiskEpsilon = Math.Max(0.0f, parsedRiskEpsilon);
			}

			if (TryGetHudArgValue(arg, "--reference-geodesic-probe=", out string referenceProbeValue))
			{
				string normalized = referenceProbeValue.Trim().ToLowerInvariant();
				EnableReferenceGeodesicProbe = normalized is "1" or "true" or "on" or "yes";
				continue;
			}

			if (TryGetHudArgValue(arg, "--reference-geodesic-probe-max-anchors=", out string refMaxAnchorsValue)
				&& int.TryParse(refMaxAnchorsValue, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedRefMaxAnchors))
			{
				ReferenceGeodesicProbeMaxAnchors = Math.Max(1, parsedRefMaxAnchors);
			}

			if (TryGetHudArgValue(arg, "--reference-geodesic-probe-max-steps=", out string refMaxStepsValue)
				&& int.TryParse(refMaxStepsValue, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedRefMaxSteps))
			{
				ReferenceGeodesicProbeMaxSteps = Math.Max(64, parsedRefMaxSteps);
			}

			if (TryGetHudArgValue(arg, "--reference-geodesic-probe-diagonals=", out string refDiagValue))
			{
				string normalized = refDiagValue.Trim().ToLowerInvariant();
				ReferenceGeodesicProbeIncludeDiagonals = normalized is "1" or "true" or "on" or "yes";
			}

			if (TryGetHudArgValue(arg, "--transport-coherence-basin=", out string basinValue))
			{
				string normalized = basinValue.Trim().ToLowerInvariant();
				EnableTransportCoherenceBasin = normalized is "1" or "true" or "on" or "yes";
				if (EnableTransportCoherenceBasin)
					EnableReferenceGeodesicProbe = true;
				continue;
			}

			if (TryGetHudArgValue(arg, "--transport-coherence-basin-radii=", out string basinRadiiValue)
				&& !string.IsNullOrWhiteSpace(basinRadiiValue))
			{
				TransportCoherenceBasinRadii = basinRadiiValue.Trim();
			}

			if (TryGetHudArgValue(arg, "--transport-coherence-basin-max-centers=", out string basinMaxCentersValue)
				&& int.TryParse(basinMaxCentersValue, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedBasinMaxCenters))
			{
				TransportCoherenceBasinMaxCenters = Math.Max(0, parsedBasinMaxCenters);
			}

			if (TryGetHudArgValue(arg, "--corner-transport-probe=", out string cornerProbeValue))
			{
				string normalized = cornerProbeValue.Trim().ToLowerInvariant();
				EnableCornerTransportProbe = normalized is "1" or "true" or "on" or "yes";
				if (EnableCornerTransportProbe)
					EnableReferenceGeodesicProbe = true;
				continue;
			}

			if (TryGetHudArgValue(arg, "--corner-transport-probe-steps=", out string cornerStepsValue)
				&& !string.IsNullOrWhiteSpace(cornerStepsValue))
			{
				CornerTransportProbeSteps = cornerStepsValue.Trim();
			}

			if (TryGetHudArgValue(arg, "--corner-transport-probe-radii=", out string cornerRadiiValue)
				&& !string.IsNullOrWhiteSpace(cornerRadiiValue))
			{
				CornerTransportProbeRadii = cornerRadiiValue.Trim();
			}

			if (TryGetHudArgValue(arg, "--corner-transport-probe-patch-size=", out string cornerPatchValue)
				&& int.TryParse(cornerPatchValue, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedCornerPatch))
			{
				CornerTransportProbePatchSize = Math.Max(0, parsedCornerPatch);
			}

			if (TryGetHudArgValue(arg, "--corner-transport-probe-max-rois=", out string cornerMaxRoisValue)
				&& int.TryParse(cornerMaxRoisValue, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedCornerMaxRois))
			{
				CornerTransportProbeMaxRois = Math.Max(1, parsedCornerMaxRois);
			}

			if (TryGetHudArgValue(arg, "--corner-transport-probe-manual-rois=", out string manualRoisValue))
			{
				CornerTransportProbeManualRois = manualRoisValue.Trim();
			}

			if (TryGetHudArgValue(arg, "--render-test-first-pass-traversal=", out string firstPassTraversalValue)
				&& !string.IsNullOrWhiteSpace(firstPassTraversalValue))
			{
				RenderTestFirstPassTraversalMode = NormalizeRenderTestFirstPassTraversalMode(firstPassTraversalValue);
			}

			if (TryGetHudArgValue(arg, "--reference-transport-oracle=", out string transportOracleValue))
			{
				string normalized = transportOracleValue.Trim().ToLowerInvariant();
				EnableReferenceTransportOracle = normalized is "1" or "true" or "on" or "yes";
				continue;
			}

			if (TryGetHudArgValue(arg, "--reference-transport-oracle-manual-rois=", out string transportOracleRoisValue))
			{
				ReferenceTransportOracleManualRois = transportOracleRoisValue.Trim();
				continue;
			}

			if (TryGetHudArgValue(arg, "--reference-transport-oracle-max-pixels=", out string transportOracleMaxPixelsValue)
				&& int.TryParse(transportOracleMaxPixelsValue, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedOracleMaxPixels))
			{
				ReferenceTransportOracleMaxPixels = Math.Max(1, parsedOracleMaxPixels);
				continue;
			}

			if (TryGetHudArgValue(arg, "--reference-transport-oracle-patch-size=", out string transportOraclePatchValue)
				&& int.TryParse(transportOraclePatchValue, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedOraclePatch))
			{
				ReferenceTransportOraclePatchSize = Math.Max(1, parsedOraclePatch);
				continue;
			}

			if (TryGetHudArgValue(arg, "--reference-transport-oracle-production-steps=", out string transportOracleStepsValue)
				&& !string.IsNullOrWhiteSpace(transportOracleStepsValue))
			{
				ReferenceTransportOracleProductionSteps = transportOracleStepsValue.Trim();
				continue;
			}

			if (TryGetHudArgValue(arg, "--reference-transport-oracle-step-length=", out string transportOracleStepValue)
				&& float.TryParse(transportOracleStepValue, NumberStyles.Float, CultureInfo.InvariantCulture, out float parsedOracleStep))
			{
				ReferenceTransportOracleStepLength = Math.Max(0.00001f, parsedOracleStep);
				continue;
			}

			if (TryGetHudArgValue(arg, "--reference-transport-oracle-tolerance=", out string transportOracleToleranceValue)
				&& float.TryParse(transportOracleToleranceValue, NumberStyles.Float, CultureInfo.InvariantCulture, out float parsedOracleTolerance))
			{
				ReferenceTransportOracleTolerance = Math.Max(0.0f, parsedOracleTolerance);
				continue;
			}

			if (TryGetHudArgValue(arg, "--reference-transport-oracle-max-steps=", out string transportOracleMaxStepsValue)
				&& int.TryParse(transportOracleMaxStepsValue, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedOracleMaxSteps))
			{
				ReferenceTransportOracleMaxSteps = Math.Max(64, parsedOracleMaxSteps);
				continue;
			}

			if (TryGetHudArgValue(arg, "--reference-transport-oracle-replay-count=", out string transportOracleReplayValue)
				&& int.TryParse(transportOracleReplayValue, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsedOracleReplay))
			{
				ReferenceTransportOracleReplayCount = Math.Clamp(parsedOracleReplay, 1, 8);
				continue;
			}

			if (TryGetHudArgValue(arg, "--reference-transport-oracle-adaptive-refinement=", out string transportOracleAdaptiveValue))
			{
				string normalized = transportOracleAdaptiveValue.Trim().ToLowerInvariant();
				ReferenceTransportOracleAdaptiveRefinement = normalized is "1" or "true" or "on" or "yes";
				continue;
			}

			if (TryGetHudArgValue(arg, "--reference-transport-oracle-family-samples=", out string transportOracleFamilyValue))
			{
				string normalized = transportOracleFamilyValue.Trim().ToLowerInvariant();
				ReferenceTransportOracleFamilySamples = normalized is "1" or "true" or "on" or "yes";
				continue;
			}
		}
	}

	private static string NormalizeRenderTestFirstPassTraversalMode(string mode)
	{
		string token = (mode ?? string.Empty).Trim().ToLowerInvariant();
		return token switch
		{
			"row" or "row_baseline" or "baseline" => "row",
			"reverse_row" or "reverse-row" or "row_reverse" => "reverse_row",
			"column" or "column_major" or "col" => "column",
			"tile" or "square_tile" or "square" => "tile",
			"checkerboard" or "checkerboard_tile" or "checker" => "checkerboard",
			_ => "row"
		};
	}

	// Loads band_tile_signals.json produced by band_detector.py and pre-seeds _tileMetricColumnSeeds
	// with known high-band-energy tile columns. Called once at startup after film dimensions are set.
	// This is the "offline seed" path — distinct from live prior accumulation (SaveTileMetricBandHistoryForCurrentBand).
	private void TryLoadBandTileSeed()
	{
		_tileMetricBandSeedLoaded = false;
		_tileMetricBandSeedTilesSeeded = 0;
		_tileMetricBandSeedTileGridW = 0;
		_tileMetricBandSeedTileGridH = 0;
		_tileMetricBandSeedTileH = 0;
		_tileMetricColumnSeeds.Clear();

		if (!EnableTileMetricsScaffold || !EnableTileMetricsBandSeed)
			return;

		string seedPath = TileMetricsBandSeedPath?.Trim() ?? string.Empty;
		if (string.IsNullOrWhiteSpace(seedPath))
		{
			GD.Print("[TileMetricsBandSeed] EnableTileMetricsBandSeed=true but TileMetricsBandSeedPath is empty; skipping seed.");
			return;
		}
		if (!File.Exists(seedPath))
		{
			GD.Print($"[TileMetricsBandSeed] seed file not found: {seedPath}");
			return;
		}

		try
		{
			string json = File.ReadAllText(seedPath, System.Text.Encoding.UTF8);
			using JsonDocument doc = JsonDocument.Parse(json);
			JsonElement root = doc.RootElement;

			int tileW = root.TryGetProperty("tile_width", out JsonElement twEl) && twEl.TryGetInt32(out int twVal) ? twVal : TileMetricsSubtileWidth;
			int tileH = root.TryGetProperty("tile_height", out JsonElement thEl) && thEl.TryGetInt32(out int thVal) ? thVal : TileMetricsSubtileWidth;
			int gridW = root.TryGetProperty("tile_grid_w", out JsonElement gwEl) && gwEl.TryGetInt32(out int gwVal) ? gwVal : 0;
			int gridH = root.TryGetProperty("tile_grid_h", out JsonElement ghEl) && ghEl.TryGetInt32(out int ghVal) ? ghVal : 0;

			_tileMetricBandSeedTileGridW = gridW;
			_tileMetricBandSeedTileGridH = gridH;
			_tileMetricBandSeedTileH = tileH;

			if (!root.TryGetProperty("tiles", out JsonElement tilesEl) || tilesEl.ValueKind != JsonValueKind.Array)
			{
				GD.Print($"[TileMetricsBandSeed] no 'tiles' array found in: {seedPath}");
				return;
			}

			const double BandFractionThreshold = 0.10;
			int tilesConsidered = 0;
			int tilesSeeded = 0;
			double energyMin = double.MaxValue;
			double energyMax = 0.0;

			foreach (JsonElement tile in tilesEl.EnumerateArray())
			{
				tilesConsidered++;
				if (!tile.TryGetProperty("band_pixel_fraction", out JsonElement bpfEl) || !bpfEl.TryGetDouble(out double bandFraction))
					continue;
				if (bandFraction <= BandFractionThreshold)
					continue;

				if (!tile.TryGetProperty("tile_x", out JsonElement txEl) || !txEl.TryGetInt32(out int tileX))
					continue;
				double confidence = 0.5;
				if (tile.TryGetProperty("mean_band_score", out JsonElement mbsEl) && mbsEl.TryGetDouble(out double mbsVal))
					confidence = Math.Clamp(mbsVal, 0.0, 1.0);

				// Map tile_x to subtile column x (snap to subtile width grid).
				int col = tileX / Math.Max(1, TileMetricsSubtileWidth);
				int colX = col * TileMetricsSubtileWidth;
				if (colX < 0 || ((_filmWidth > 0) && colX >= _filmWidth))
					continue;

				double bandEnergy = Math.Clamp(bandFraction, 0.0, 1.0);
				// Apply blend constant so seed doesn't override live render data.
				double seededEnergy = bandEnergy * TileMetricsPersistentPriorBlendWeight;
				double seededConfidence = confidence * TileMetricsPersistentPriorBlendWeight;

				if (_tileMetricColumnSeeds.TryGetValue(colX, out TileMetricBandSeedEntry existing))
				{
					// Accumulate: take max energy, weighted-average confidence.
					if (seededEnergy > existing.BandEnergy)
					{
						_tileMetricColumnSeeds[colX] = new TileMetricBandSeedEntry
						{
							BandEnergy = seededEnergy,
							Confidence = seededConfidence
						};
					}
				}
				else
				{
					_tileMetricColumnSeeds[colX] = new TileMetricBandSeedEntry
					{
						BandEnergy = seededEnergy,
						Confidence = seededConfidence
					};
				}

				tilesSeeded++;
				if (seededEnergy < energyMin) energyMin = seededEnergy;
				if (seededEnergy > energyMax) energyMax = seededEnergy;
			}

			if (tilesSeeded > 0)
			{
				_tileMetricBandSeedLoaded = true;
				_tileMetricBandSeedTilesSeeded = tilesSeeded;
				GD.Print(
					$"[TileMetricsBandSeed] loaded seed: path={seedPath} considered={tilesConsidered} seeded={tilesSeeded} " +
					$"columns={_tileMetricColumnSeeds.Count} energyRange=[{energyMin:0.###},{energyMax:0.###}] " +
					$"gridW={gridW} gridH={gridH} tileH={tileH}");
			}
			else
			{
				GD.Print($"[TileMetricsBandSeed] no tiles above threshold ({BandFractionThreshold:0.##}) in: {seedPath} (considered={tilesConsidered})");
			}
		}
		catch (Exception ex)
		{
			GD.PrintErr($"[TileMetricsBandSeed] failed to load seed from {seedPath}: {ex.GetType().Name}: {ex.Message}");
		}
	}

	// Writes tile_metrics_summary.json alongside domain_telemetry_summary.json after a fixture run.
	// Reports seeded columns, band energies, and simulated priority order snapshot.
	// Only writes when EnableTileMetricsScaffold is true.
	public bool TryWriteTileMetricsSummary(string outputDir, string captureStem, string fixtureName, out string summaryPath)
	{
		summaryPath = string.Empty;
		if ((!EnableTileMetricsScaffold && !EnableObjectSeededTileScheduler) || string.IsNullOrWhiteSpace(outputDir))
			return false;

		try
		{
			Directory.CreateDirectory(outputDir);
			string safeStem = string.IsNullOrWhiteSpace(captureStem) ? "capture" : captureStem.Trim();
			string safeFixture = string.IsNullOrWhiteSpace(fixtureName) ? "unknown" : fixtureName.Trim();
			int subtileW = Math.Max(1, TileMetricsSubtileWidth);
			int tileGridW = _filmWidth > 0 ? (_filmWidth + subtileW - 1) / subtileW : 0;

			double energySum = 0.0;
			var energyValues = new List<double>(_tileMetricColumnSeeds.Count);
			int tilesWithHighEnergy = 0;
			const double HighEnergyThreshold = 0.15;
			foreach (var kv in _tileMetricColumnSeeds)
			{
				double e = kv.Value.BandEnergy;
				energySum += e;
				energyValues.Add(e);
				if (e >= HighEnergyThreshold) tilesWithHighEnergy++;
			}
			double energyMean = energyValues.Count > 0 ? energySum / energyValues.Count : 0.0;
			energyValues.Sort();
			double energyP90 = energyValues.Count > 0
				? energyValues[(int)Math.Min(energyValues.Count - 1, Math.Floor(energyValues.Count * 0.9))]
				: 0.0;

			// Build top_priority_tiles sorted by band_energy descending.
			var topTiles = new List<(int col, double energy, double confidence, bool seeded)>();
			foreach (var kv in _tileMetricColumnSeeds)
			{
				int col = _filmWidth > 0 ? kv.Key / subtileW : 0;
				topTiles.Add((col, kv.Value.BandEnergy, kv.Value.Confidence, true));
			}
			topTiles.Sort((a, b) => b.energy.CompareTo(a.energy));
			int topN = Math.Min(topTiles.Count, 20);

			var sb = new StringBuilder(1024);
			sb.Append("{");
			sb.Append("\"fixture\":\"").Append(JsonEscapeForArtifact(safeFixture)).Append("\",");
			sb.Append("\"tile_grid_w\":").Append(tileGridW).Append(",");
			sb.Append("\"tile_grid_h\":").Append(_tileMetricBandSeedTileGridH).Append(",");
			sb.Append("\"tile_count\":").Append(tileGridW).Append(",");
			sb.Append("\"tiles_with_band_seed\":").Append(_tileMetricColumnSeeds.Count).Append(",");
			sb.Append("\"tiles_with_high_prior_energy\":").Append(tilesWithHighEnergy).Append(",");
			sb.Append("\"prior_energy_mean\":").Append(FormatJsonFloatForArtifact((float)energyMean)).Append(",");
			sb.Append("\"prior_energy_p90\":").Append(FormatJsonFloatForArtifact((float)energyP90)).Append(",");
			sb.Append("\"reorder_simulation_active\":").Append(EnableTileMetricsReorderSimulation ? "true" : "false").Append(",");
			sb.Append("\"object_seeded_scheduler_active\":").Append(EnableObjectSeededTileScheduler ? "true" : "false").Append(",");
			sb.Append("\"object_seeded_seed\":").Append(ObjectSeededTileSchedulerSeed).Append(",");
			sb.Append("\"object_seeded_observer_count\":").Append(_objectSeededLastBandSchedule.ObserverCount).Append(",");
			sb.Append("\"object_seeded_anchor_count\":").Append(_objectSeededLastBandSchedule.AnchorCount).Append(",");
			sb.Append("\"object_seeded_probe_count\":").Append(_objectSeededLastBandSchedule.ProbeCount).Append(",");
			sb.Append("\"object_seeded_seeded_tile_count\":").Append(_objectSeededLastBandSchedule.SeededTileCount).Append(",");
			sb.Append("\"object_seeded_fallback_tile_count\":").Append(_objectSeededLastBandSchedule.FallbackTileCount).Append(",");
			sb.Append("\"object_seeded_stale_observer_fallback_count\":").Append(_objectSeededLastBandSchedule.StaleObserverFallbackCount).Append(",");
			sb.Append("\"object_seeded_probe_cache_hits\":").Append(_objectSeededLastBandSchedule.CacheHits).Append(",");
			sb.Append("\"object_seeded_probe_cache_misses\":").Append(_objectSeededLastBandSchedule.CacheMisses).Append(",");
			sb.Append("\"object_seeded_max_risk\":").Append(FormatJsonFloatForArtifact((float)_objectSeededLastBandSchedule.MaxRisk)).Append(",");
			sb.Append("\"object_seeded_max_confidence\":").Append(FormatJsonFloatForArtifact((float)_objectSeededLastBandSchedule.MaxConfidence)).Append(",");
			sb.Append("\"object_seeded_diagnostics\":").Append(EnableObjectSeededTileScheduler ? _objectSeededTileScheduler.BuildDiagnosticsJson() : "{}").Append(",");
			sb.Append("\"top_priority_tiles\":[");
			for (int i = 0; i < topN; i++)
			{
				if (i > 0) sb.Append(",");
				var t = topTiles[i];
				sb.Append("{");
				sb.Append("\"tile_col\":").Append(t.col).Append(",");
				sb.Append("\"tile_row\":0,");
				sb.Append("\"priority_score\":").Append(FormatJsonFloatForArtifact((float)t.energy)).Append(",");
				sb.Append("\"band_energy\":").Append(FormatJsonFloatForArtifact((float)t.energy)).Append(",");
				sb.Append("\"domain_confidence\":").Append(FormatJsonFloatForArtifact((float)t.confidence)).Append(",");
				sb.Append("\"was_seeded\":").Append(t.seeded ? "true" : "false");
				sb.Append("}");
			}
			sb.Append("]}");

			summaryPath = Path.Combine(outputDir, safeStem + ".tile_metrics_summary.json");
			File.WriteAllText(summaryPath, sb.ToString());
			GD.Print(
				$"[TileMetricsSummary] written: path={summaryPath} seeded_cols={_tileMetricColumnSeeds.Count} " +
				$"highEnergy={tilesWithHighEnergy} energyMean={energyMean:0.###} p90={energyP90:0.###}");
			return true;
		}
		catch (Exception ex)
		{
			GD.PrintErr($"[TileMetricsSummary] failed: {ex.GetType().Name}: {ex.Message}");
			return false;
		}
	}

	public bool TryWriteDiagnosticWireframePrimitivePacket(
		string outputDir,
		string captureStem,
		string fixtureName,
		string manualRois,
		bool cartesianEnabled,
		bool transportEnabled,
		bool riskEnabled,
		bool spacetimeEnabled,
		bool continuityEnabled,
		bool labelsEnabled,
		out string primitivePath,
		out string hitCsvPath)
	{
		// Diagnostic overlay packets are post-capture instrumentation only. Rendering,
		// scheduling, hit selection, shading, resolver scoring, and precision stepping
		// never consume this file or the hit diagnostics CSV.
		primitivePath = string.Empty;
		hitCsvPath = string.Empty;
		if (string.IsNullOrWhiteSpace(outputDir) || _cam == null || !GodotObject.IsInstanceValid(_cam))
			return false;

		SceneSnapshot snap = FrameSnapshotBus.CurrentSnapshot;
		if (snap == null)
			return false;

		Directory.CreateDirectory(outputDir);
		string safeStem = string.IsNullOrWhiteSpace(captureStem) ? "capture" : captureStem.Trim();
		string safeFixture = string.IsNullOrWhiteSpace(fixtureName) ? "unknown" : fixtureName.Trim();
		primitivePath = Path.Combine(outputDir, safeStem + ".diagnostic_wireframe_primitives.json");
		if (transportEnabled || riskEnabled || continuityEnabled)
		{
			hitCsvPath = Path.Combine(outputDir, safeStem + ".hit_diagnostics.csv");
			if (!TryExportFixtureHitDiagnosticsCsvForTesting(hitCsvPath))
				hitCsvPath = string.Empty;
		}

		var fingerprint = new SceneTransportFingerprint();
		fingerprint.Rebuild(snap, 512);
		var manualPoints = ParseCornerTransportProbeManualRois(manualRois);
		var sb = new StringBuilder(16384);
		int objectCount = 0;
		int cartesianPointCount = 0;
		int cartesianLineCount = 0;
		int spacetimePolylineCount = 0;
		int spacetimeEventCount = 0;

		static int TryParseAnchorIndex(string anchorId, string token)
		{
			int idx = anchorId.IndexOf(token, StringComparison.Ordinal);
			if (idx < 0)
				return -1;
			string suffix = anchorId[(idx + token.Length)..];
			int colon = suffix.IndexOf(':', StringComparison.Ordinal);
			if (colon >= 0)
				suffix = suffix[..colon];
			return int.TryParse(suffix, NumberStyles.Integer, CultureInfo.InvariantCulture, out int parsed) ? parsed : -1;
		}

		void AppendPointObject(StringBuilder target, int x, int y)
		{
			target.Append("{\"x\":").Append(x).Append(",\"y\":").Append(y).Append("}");
		}

		void AppendProjectedPoint(
			StringBuilder target,
			string layer,
			string kind,
			string objectId,
			string anchorId,
			TransportAnchorMode mode,
			Vector2I pixel,
			Vector3 world,
			bool label)
		{
			target.Append("{")
				.Append("\"layer\":\"").Append(JsonEscapeForArtifact(layer)).Append("\",")
				.Append("\"kind\":\"").Append(JsonEscapeForArtifact(kind)).Append("\",")
				.Append("\"object_id\":\"").Append(JsonEscapeForArtifact(objectId)).Append("\",")
				.Append("\"anchor_id\":\"").Append(JsonEscapeForArtifact(anchorId)).Append("\",")
				.Append("\"anchor_mode\":\"").Append(JsonEscapeForArtifact(mode.ToString())).Append("\",")
				.Append("\"x\":").Append(pixel.X).Append(",")
				.Append("\"y\":").Append(pixel.Y).Append(",")
				.Append("\"world_x\":").Append(FormatJsonFloatForArtifact(world.X)).Append(",")
				.Append("\"world_y\":").Append(FormatJsonFloatForArtifact(world.Y)).Append(",")
				.Append("\"world_z\":").Append(FormatJsonFloatForArtifact(world.Z)).Append(",")
				.Append("\"label\":\"").Append(label ? JsonEscapeForArtifact(objectId) : "").Append("\"")
				.Append("}");
		}

		void AppendLineObject(StringBuilder target, string objectId, string kind, Vector2I a, Vector2I b)
		{
			target.Append("{")
				.Append("\"layer\":\"cartesian\",")
				.Append("\"kind\":\"").Append(JsonEscapeForArtifact(kind)).Append("\",")
				.Append("\"object_id\":\"").Append(JsonEscapeForArtifact(objectId)).Append("\",")
				.Append("\"x0\":").Append(a.X).Append(",")
				.Append("\"y0\":").Append(a.Y).Append(",")
				.Append("\"x1\":").Append(b.X).Append(",")
				.Append("\"y1\":").Append(b.Y)
				.Append("}");
		}

		sb.Append("{");
		sb.Append("\"schema_version\":1,");
		sb.Append("\"capture_stem\":\"").Append(JsonEscapeForArtifact(safeStem)).Append("\",");
		sb.Append("\"fixture\":\"").Append(JsonEscapeForArtifact(safeFixture)).Append("\",");
		sb.Append("\"image_width\":").Append(_filmWidth).Append(",");
		sb.Append("\"image_height\":").Append(_filmHeight).Append(",");
		sb.Append("\"scene_fingerprint\":\"").Append(JsonEscapeForArtifact(fingerprint.VersionStamp)).Append("\",");
		sb.Append("\"post_process_only\":true,");
		sb.Append("\"enabled_layers\":{")
			.Append("\"cartesian\":").Append(cartesianEnabled ? "true" : "false").Append(",")
			.Append("\"transport\":").Append(transportEnabled ? "true" : "false").Append(",")
			.Append("\"risk\":").Append(riskEnabled ? "true" : "false").Append(",")
			.Append("\"spacetime\":").Append(spacetimeEnabled ? "true" : "false").Append(",")
			.Append("\"continuity\":").Append(continuityEnabled ? "true" : "false").Append(",")
			.Append("\"labels\":").Append(labelsEnabled ? "true" : "false")
			.Append("},");
		sb.Append("\"manual_rois\":[");
		for (int i = 0; i < manualPoints.Length; i++)
		{
			if (i > 0) sb.Append(",");
			AppendPointObject(sb, manualPoints[i].X, manualPoints[i].Y);
		}
		sb.Append("],");

		var objectJson = new StringBuilder(8192);
		var pointJson = new StringBuilder(8192);
		var lineJson = new StringBuilder(8192);
		var spacetimeJson = new StringBuilder(8192);
		var eventJson = new StringBuilder(8192);
		bool objectAny = false;
		bool pointAny = false;
		bool lineAny = false;
		bool spacetimeAny = false;
		bool eventAny = false;
		int[,] edgePairs =
		{
			{0, 1}, {0, 2}, {0, 4}, {1, 3}, {1, 5}, {2, 3},
			{2, 6}, {3, 7}, {4, 5}, {4, 6}, {5, 7}, {6, 7}
		};

		foreach (ObjectTransportObserver observer in fingerprint.Observers)
		{
			var corners = new Dictionary<int, Vector2I>();
			var projectedAnchors = new List<(TransportAnchor Anchor, Vector2I Pixel)>();
			foreach (TransportAnchor anchor in observer.AnchorSamples)
			{
				if (!TryProjectWorldToFilmPixel(_cam, anchor.WorldPosition, _filmWidth, _filmHeight, out Vector2I pixel))
					continue;
				projectedAnchors.Add((anchor, pixel));
				if (anchor.AnchorId.Contains(":corner:", StringComparison.Ordinal))
				{
					int idx = TryParseAnchorIndex(anchor.AnchorId, ":corner:");
					if (idx >= 0)
						corners[idx] = pixel;
				}
			}
			if (projectedAnchors.Count == 0)
				continue;

			if (objectAny) objectJson.Append(",");
			objectAny = true;
			objectCount++;
			objectJson.Append("{")
				.Append("\"object_id\":\"").Append(JsonEscapeForArtifact(observer.StableObjectId)).Append("\",")
				.Append("\"kind\":\"").Append(JsonEscapeForArtifact(observer.Kind.ToString())).Append("\",")
				.Append("\"anchor_count\":").Append(projectedAnchors.Count).Append(",")
				.Append("\"centroid_world_x\":").Append(FormatJsonFloatForArtifact(observer.Centroid.X)).Append(",")
				.Append("\"centroid_world_y\":").Append(FormatJsonFloatForArtifact(observer.Centroid.Y)).Append(",")
				.Append("\"centroid_world_z\":").Append(FormatJsonFloatForArtifact(observer.Centroid.Z))
				.Append("}");

			if (cartesianEnabled)
			{
				foreach ((TransportAnchor anchor, Vector2I pixel) in projectedAnchors)
				{
					if (pointAny) pointJson.Append(",");
					pointAny = true;
					cartesianPointCount++;
					string kind = anchor.Mode switch
					{
						TransportAnchorMode.Centroid => "centroid",
						TransportAnchorMode.AabbCorner => "corner",
						TransportAnchorMode.EdgeMidpoint => "edge_midpoint",
						TransportAnchorMode.PrincipalAxis => "principal_axis",
						TransportAnchorMode.DomainBoundarySample => anchor.AnchorId.Contains(":corner:", StringComparison.Ordinal) ? "corner" : "domain_boundary",
						_ => "anchor"
					};
					AppendProjectedPoint(pointJson, "cartesian", kind, observer.StableObjectId, anchor.AnchorId, anchor.Mode, pixel, anchor.WorldPosition, labelsEnabled && anchor.Mode == TransportAnchorMode.Centroid);
				}

				for (int i = 0; i < edgePairs.GetLength(0); i++)
				{
					if (!corners.TryGetValue(edgePairs[i, 0], out Vector2I a) || !corners.TryGetValue(edgePairs[i, 1], out Vector2I b))
						continue;
					if (lineAny) lineJson.Append(",");
					lineAny = true;
					cartesianLineCount++;
					AppendLineObject(lineJson, observer.StableObjectId, "aabb_edge", a, b);
				}
			}

			if (spacetimeEnabled)
			{
				Vector2I screenCenter = new(Math.Max(0, _filmWidth / 2), Math.Max(0, _filmHeight / 2));
				foreach ((TransportAnchor anchor, Vector2I pixel) in projectedAnchors.Take(16))
				{
					if (spacetimeAny) spacetimeJson.Append(",");
					spacetimeAny = true;
					spacetimePolylineCount++;
					spacetimeJson.Append("{")
						.Append("\"kind\":\"ray_segment_polyline\",")
						.Append("\"object_id\":\"").Append(JsonEscapeForArtifact(observer.StableObjectId)).Append("\",")
						.Append("\"anchor_id\":\"").Append(JsonEscapeForArtifact(anchor.AnchorId)).Append("\",")
						.Append("\"path_length\":").Append(FormatJsonFloatForArtifact((observer.Centroid - anchor.WorldPosition).Length())).Append(",")
						.Append("\"order_index\":").Append(spacetimePolylineCount).Append(",")
						.Append("\"points\":[");
					AppendPointObject(spacetimeJson, screenCenter.X, screenCenter.Y);
					spacetimeJson.Append(",");
					AppendPointObject(spacetimeJson, pixel.X, pixel.Y);
					spacetimeJson.Append("]}");

					if (eventAny) eventJson.Append(",");
					eventAny = true;
					spacetimeEventCount++;
					eventJson.Append("{")
						.Append("\"kind\":\"first_hit_event\",")
						.Append("\"object_id\":\"").Append(JsonEscapeForArtifact(observer.StableObjectId)).Append("\",")
						.Append("\"anchor_id\":\"").Append(JsonEscapeForArtifact(anchor.AnchorId)).Append("\",")
						.Append("\"x\":").Append(pixel.X).Append(",")
						.Append("\"y\":").Append(pixel.Y).Append(",")
						.Append("\"order_index\":").Append(spacetimeEventCount)
						.Append("}");
				}
			}
		}

		sb.Append("\"objects\":[");
		sb.Append(objectJson);
		sb.Append("],");
		sb.Append("\"primitives\":{");
		sb.Append("\"cartesian\":{")
			.Append("\"points\":[").Append(pointJson).Append("],")
			.Append("\"lines\":[").Append(lineJson).Append("]")
			.Append("},");
		sb.Append("\"spacetime\":{")
			.Append("\"polylines\":[").Append(spacetimeJson).Append("],")
			.Append("\"events\":[").Append(eventJson).Append("]")
			.Append("}");
		sb.Append("},");
		sb.Append("\"primitive_count_by_layer\":{")
			.Append("\"cartesian_points\":").Append(cartesianPointCount).Append(",")
			.Append("\"cartesian_lines\":").Append(cartesianLineCount).Append(",")
			.Append("\"spacetime_polylines\":").Append(spacetimePolylineCount).Append(",")
			.Append("\"spacetime_events\":").Append(spacetimeEventCount).Append(",")
			.Append("\"manual_rois\":").Append(manualPoints.Length)
			.Append("},");
		sb.Append("\"object_count\":").Append(objectCount);
		sb.Append("}");

		File.WriteAllText(primitivePath, sb.ToString());
		return true;
	}

	private readonly struct ReferenceProbeSample
	{
		public readonly string AnchorId;
		public readonly string ObjectId;
		public readonly float StepLength;
		public readonly float ReferenceStepLength;
		public readonly int ProjectedX;
		public readonly int ProjectedY;
		public readonly int ProjectedTile;
		public readonly int ObjectCentroidProjectedX;
		public readonly int ObjectCentroidProjectedY;
		public readonly float RadialDistFromObjectCentroid;
		public readonly float RadialAngleFromObjectCentroid;
		public readonly string NearestAnchorKind;
		public readonly float NearestCornerDist;
		public readonly float NearestEdgeDist;
		public readonly string SamplePhase;
		public readonly int NeighborhoodCenterX;
		public readonly int NeighborhoodCenterY;
		public readonly int NeighborhoodRadius;
		public readonly string NeighborhoodDirection;
		public readonly int OffsetX;
		public readonly int OffsetY;
		public readonly bool Hit;
		public readonly ulong ColliderId;
		public readonly int DomainId;
		public readonly int BoundaryEvents;
		public readonly int PortalEvents;
		public readonly float HitDistance;
		public readonly Vector3 Normal;
		public readonly float PathLength;
		public readonly double DecisionRisk;
		public readonly bool MatchedReference;
		public readonly string RequiredPrecisionLabel;

		public ReferenceProbeSample(
			string anchorId,
			string objectId,
			float stepLength,
			float referenceStepLength,
			int projectedX,
			int projectedY,
			int projectedTile,
			int objectCentroidProjectedX,
			int objectCentroidProjectedY,
			float radialDistFromObjectCentroid,
			float radialAngleFromObjectCentroid,
			string nearestAnchorKind,
			float nearestCornerDist,
			float nearestEdgeDist,
			string samplePhase,
			int neighborhoodCenterX,
			int neighborhoodCenterY,
			int neighborhoodRadius,
			string neighborhoodDirection,
			int offsetX,
			int offsetY,
			bool hit,
			ulong colliderId,
			int domainId,
			int boundaryEvents,
			int portalEvents,
			float hitDistance,
			Vector3 normal,
			float pathLength,
			double decisionRisk,
			bool matchedReference,
			string requiredPrecisionLabel)
		{
			AnchorId = anchorId ?? "";
			ObjectId = objectId ?? "";
			StepLength = stepLength;
			ReferenceStepLength = referenceStepLength;
			ProjectedX = projectedX;
			ProjectedY = projectedY;
			ProjectedTile = projectedTile;
			ObjectCentroidProjectedX = objectCentroidProjectedX;
			ObjectCentroidProjectedY = objectCentroidProjectedY;
			RadialDistFromObjectCentroid = radialDistFromObjectCentroid;
			RadialAngleFromObjectCentroid = radialAngleFromObjectCentroid;
			NearestAnchorKind = nearestAnchorKind ?? "";
			NearestCornerDist = nearestCornerDist;
			NearestEdgeDist = nearestEdgeDist;
			SamplePhase = samplePhase ?? "anchor_probe";
			NeighborhoodCenterX = neighborhoodCenterX;
			NeighborhoodCenterY = neighborhoodCenterY;
			NeighborhoodRadius = neighborhoodRadius;
			NeighborhoodDirection = neighborhoodDirection ?? "center";
			OffsetX = offsetX;
			OffsetY = offsetY;
			Hit = hit;
			ColliderId = colliderId;
			DomainId = domainId;
			BoundaryEvents = boundaryEvents;
			PortalEvents = portalEvents;
			HitDistance = hitDistance;
			Normal = normal;
			PathLength = pathLength;
			DecisionRisk = decisionRisk;
			MatchedReference = matchedReference;
			RequiredPrecisionLabel = requiredPrecisionLabel ?? "reference";
		}
	}

	private sealed class ReferenceProbeObjectGeometry
	{
		public Vector2I CentroidPixel = new(-1, -1);
		public readonly List<(Vector2I Pixel, TransportAnchorMode Mode)> Anchors = new();
		public readonly List<Vector2I> Corners = new();
		public readonly List<Vector2I> EdgeMidpoints = new();
	}

	private readonly struct ReferenceProbeOffsetInfo
	{
		public readonly Vector2I Offset;
		public readonly int Radius;
		public readonly string Direction;

		public ReferenceProbeOffsetInfo(Vector2I offset, int radius, string direction)
		{
			Offset = offset;
			Radius = radius;
			Direction = direction ?? "center";
		}
	}

	private readonly struct ReferenceProbeBudgetMetrics
	{
		public readonly int ProbeSampleCount;
		public readonly long ProbeRuntimeMs;
		public readonly int MaxCentersUsed;
		public readonly int CentersSkippedDueToBudget;
		public readonly int RowsWritten;

		public ReferenceProbeBudgetMetrics(int probeSampleCount, long probeRuntimeMs, int maxCentersUsed, int centersSkippedDueToBudget, int rowsWritten)
		{
			ProbeSampleCount = probeSampleCount;
			ProbeRuntimeMs = probeRuntimeMs;
			MaxCentersUsed = maxCentersUsed;
			CentersSkippedDueToBudget = centersSkippedDueToBudget;
			RowsWritten = rowsWritten;
		}
	}

	public bool TryWriteReferenceGeodesicProbeDiagnostics(string outputDir, string captureStem, string fixtureName, out string jsonPath, out string csvPath)
	{
		// Transport coherence basin data is diagnostic-only. Nothing written here is
		// consumed by render scheduling, hit selection, shading, resolver, or precision stepping.
		Stopwatch probeStopwatch = Stopwatch.StartNew();
		jsonPath = string.Empty;
		csvPath = string.Empty;
		if (!EnableReferenceGeodesicProbe || string.IsNullOrWhiteSpace(outputDir))
			return false;
		if (_rbr == null || !GodotObject.IsInstanceValid(_rbr) || _cam == null || !GodotObject.IsInstanceValid(_cam))
			return false;
		if (!TryResolveRenderSpaceState(out PhysicsDirectSpaceState3D space, out string renderSpaceSource))
			return false;

		SceneSnapshot snap = FrameSnapshotBus.CurrentSnapshot;
		if (snap == null)
			return false;

		ResolveEffectiveConfig(out EffectiveConfig cfg);
		RayBeamRenderer.FieldSourceSnap[] fieldSnaps = GetFieldSourceSnaps(in cfg, _frameIndex, out bool hasSources, out _);
		float beta = 0f;
		float gamma = 2f;
		if (cfg.UseCameraPropsBetaGamma)
		{
			beta = ReadFloat(_cam, "Beta", 0f);
			gamma = ReadFloat(_cam, "Gamma", 2f);
		}
		Vector3 center = cfg.RayMarch.FieldCenterIsCamera ? _cam.GlobalPosition : cfg.RayMarch.FieldCenter;
		Vector3 bendDir = _cam.GlobalTransform.Basis.X;
		float pxPerRad = 0f;
		if (cfg.RayMarch.UseScreenSpaceCollisionCadence)
		{
			float fovY = Mathf.DegToRad(_cam.Fov);
			float vpHeight = Mathf.Max(1f, _cam.GetViewport()?.GetVisibleRect().Size.Y ?? 720f);
			pxPerRad = (vpHeight * 0.5f) / Mathf.Max(1e-6f, Mathf.Tan(fovY * 0.5f));
		}

		var fingerprint = new SceneTransportFingerprint();
		fingerprint.Rebuild(snap, Math.Max(1, ReferenceGeodesicProbeMaxAnchors));
		Dictionary<string, ReferenceProbeObjectGeometry> objectGeometry = BuildReferenceProbeObjectGeometry(fingerprint, _cam, _filmWidth, _filmHeight);
		var anchors = EnableCornerTransportProbe
			? SelectCornerTransportProbeAnchors(fingerprint, _cam, _filmWidth, _filmHeight, Math.Max(1, CornerTransportProbeMaxRois))
			: SelectReferenceProbeAnchors(fingerprint, _cam, _filmWidth, _filmHeight, Math.Max(1, ReferenceGeodesicProbeMaxAnchors));
		int anchorLimit = EnableCornerTransportProbe ? CornerTransportProbeMaxRois : ReferenceGeodesicProbeMaxAnchors;
		if (anchors.Count > anchorLimit)
			anchors.RemoveRange(anchorLimit, anchors.Count - anchorLimit);
		if (anchors.Count == 0)
			return false;

		float[] stepLengths = EnableCornerTransportProbe
			? ParseReferenceProbeStepLengths(CornerTransportProbeSteps, new[] { 0.02f, 0.0125f, 0.003125f })
			: new[] { 0.015f, 0.0125f, 0.00625f, 0.003125f };
		Array.Sort(stepLengths);
		Array.Reverse(stepLengths);
		float referenceStep = stepLengths[^1];
		int tileWidth = Math.Max(1, TileMetricsSubtileWidth);
		var rows = new List<ReferenceProbeSample>(anchors.Count * 48 * stepLengths.Length);
		var anchorById = new Dictionary<string, TransportAnchor>(StringComparer.Ordinal);
		foreach (TransportAnchor anchor in anchors)
			anchorById[anchor.AnchorId] = anchor;
		int maxCentersUsed = 0;
		int centersSkippedDueToBudget = 0;

		int savedStepsPerRay = _rbr.StepsPerRay;
		float savedStepLength = _rbr.StepLength;
		float savedMinStepLength = _rbr.MinStepLength;
		float savedMaxStepLength = _rbr.MaxStepLength;
		try
		{
			var anchorCenters = new List<(TransportAnchor Anchor, Vector2I Pixel)>();
			foreach (TransportAnchor anchor in anchors)
			{
				if (TryProjectWorldToFilmPixel(_cam, anchor.WorldPosition, _filmWidth, _filmHeight, out Vector2I projectedPixel))
					anchorCenters.Add((anchor, projectedPixel));
			}
			if (EnableCornerTransportProbe)
			{
				foreach (Vector2I manualPixel in ParseCornerTransportProbeManualRois(CornerTransportProbeManualRois))
				{
					if (manualPixel.X < 0 || manualPixel.Y < 0 || manualPixel.X >= _filmWidth || manualPixel.Y >= _filmHeight || anchorCenters.Count == 0)
						continue;
					(TransportAnchor Anchor, Vector2I Pixel) nearest = anchorCenters[0];
					float nearestDist = FilmPixelDistance(manualPixel, nearest.Pixel);
					foreach ((TransportAnchor Anchor, Vector2I Pixel) candidate in anchorCenters)
					{
						float d = FilmPixelDistance(manualPixel, candidate.Pixel);
						if (d < nearestDist)
						{
							nearest = candidate;
							nearestDist = d;
						}
					}
					var manualAnchor = new TransportAnchor
					{
						AnchorId = $"manual_roi:{manualPixel.X}:{manualPixel.Y}:{nearest.Anchor.AnchorId}",
						StableObjectId = nearest.Anchor.StableObjectId,
						ObserverKind = nearest.Anchor.ObserverKind,
						Mode = nearest.Anchor.Mode,
						WorldPosition = nearest.Anchor.WorldPosition,
						WorldNormalOrAxis = nearest.Anchor.WorldNormalOrAxis,
						InfluenceRadius = nearest.Anchor.InfluenceRadius
					};
					anchorCenters.Add((manualAnchor, manualPixel));
					anchorById[manualAnchor.AnchorId] = manualAnchor;
				}
			}

			foreach ((TransportAnchor anchor, Vector2I anchorPixel) in anchorCenters)
			{
				objectGeometry.TryGetValue(anchor.StableObjectId, out ReferenceProbeObjectGeometry geom);
				Vector2I[] offsets = EnableCornerTransportProbe
					? BuildCornerTransportProbeOffsets(anchorPixel, geom?.CentroidPixel ?? new Vector2I(-1, -1), ParseTransportCoherenceBasinRadii(CornerTransportProbeRadii), CornerTransportProbePatchSize)
					: BuildReferenceProbeOffsets(anchorPixel, geom?.CentroidPixel ?? new Vector2I(-1, -1));

				foreach (Vector2I offset in offsets)
				{
					Vector2I probePixel = new Vector2I(anchorPixel.X + offset.X, anchorPixel.Y + offset.Y);
					if (probePixel.X < 0 || probePixel.Y < 0 || probePixel.X >= _filmWidth || probePixel.Y >= _filmHeight)
						continue;

					var raw = new List<ReferenceProbeSample>(stepLengths.Length);
					ReferenceProbeSample reference = default;
					for (int si = 0; si < stepLengths.Length; si++)
					{
						float step = stepLengths[si];
						ReferenceProbeSample sample = RunReferenceProbeSample(
							space,
							renderSpaceSource,
							fixtureName,
							anchor,
							step,
							referenceStep,
							probePixel,
							geom,
							"anchor_probe",
							anchorPixel,
							ReferenceProbeOffsetRadius(offset),
							ClassifyReferenceProbeOffset(offset),
							offset,
							tileWidth,
							center,
							beta,
							gamma,
							bendDir,
							fieldSnaps,
							hasSources,
							pxPerRad,
							in cfg);
						raw.Add(sample);
						if (Math.Abs(step - referenceStep) <= 1e-8f)
							reference = sample;
					}

					string requiredPrecision = ResolveRequiredReferencePrecisionLabel(raw, reference, ObjectSeededRiskEpsilon);
					foreach (ReferenceProbeSample sample in raw)
					{
						double risk = ComputeReferenceDecisionRisk(sample, reference);
						rows.Add(new ReferenceProbeSample(
							sample.AnchorId,
							sample.ObjectId,
							sample.StepLength,
							sample.ReferenceStepLength,
							sample.ProjectedX,
							sample.ProjectedY,
							sample.ProjectedTile,
							sample.ObjectCentroidProjectedX,
							sample.ObjectCentroidProjectedY,
							sample.RadialDistFromObjectCentroid,
							sample.RadialAngleFromObjectCentroid,
							sample.NearestAnchorKind,
							sample.NearestCornerDist,
							sample.NearestEdgeDist,
							sample.SamplePhase,
							sample.NeighborhoodCenterX,
							sample.NeighborhoodCenterY,
							sample.NeighborhoodRadius,
							sample.NeighborhoodDirection,
							sample.OffsetX,
							sample.OffsetY,
							sample.Hit,
							sample.ColliderId,
							sample.DomainId,
							sample.BoundaryEvents,
							sample.PortalEvents,
							sample.HitDistance,
							sample.Normal,
							sample.PathLength,
							risk,
							risk <= ObjectSeededRiskEpsilon,
							requiredPrecision));
					}
				}
			}

			if (EnableTransportCoherenceBasin && TransportCoherenceBasinMaxCenters > 0)
			{
				List<ReferenceProbeSample> centers = SelectTransportCoherenceBasinCenters(rows, TransportCoherenceBasinMaxCenters, ObjectSeededRiskEpsilon, out centersSkippedDueToBudget);
				maxCentersUsed = centers.Count;
				int[] basinRadii = ParseTransportCoherenceBasinRadii(TransportCoherenceBasinRadii);
				foreach (ReferenceProbeSample centerSample in centers)
				{
					if (!anchorById.TryGetValue(centerSample.AnchorId, out TransportAnchor anchor))
						continue;
					objectGeometry.TryGetValue(anchor.StableObjectId, out ReferenceProbeObjectGeometry geom);
					Vector2I centerPixel = new(centerSample.ProjectedX, centerSample.ProjectedY);
					ReferenceProbeOffsetInfo[] offsets = BuildTransportCoherenceBasinOffsets(centerPixel, geom?.CentroidPixel ?? new Vector2I(-1, -1), basinRadii);

					foreach (ReferenceProbeOffsetInfo offsetInfo in offsets)
					{
						Vector2I probePixel = new(centerPixel.X + offsetInfo.Offset.X, centerPixel.Y + offsetInfo.Offset.Y);
						if (probePixel.X < 0 || probePixel.Y < 0 || probePixel.X >= _filmWidth || probePixel.Y >= _filmHeight)
							continue;

						var raw = new List<ReferenceProbeSample>(stepLengths.Length);
						ReferenceProbeSample reference = default;
						for (int si = 0; si < stepLengths.Length; si++)
						{
							float step = stepLengths[si];
							ReferenceProbeSample sample = RunReferenceProbeSample(
								space,
								renderSpaceSource,
								fixtureName,
								anchor,
								step,
								referenceStep,
								probePixel,
								geom,
								"basin_neighborhood",
								centerPixel,
								offsetInfo.Radius,
								offsetInfo.Direction,
								offsetInfo.Offset,
								tileWidth,
								center,
								beta,
								gamma,
								bendDir,
								fieldSnaps,
								hasSources,
								pxPerRad,
								in cfg);
							raw.Add(sample);
							if (Math.Abs(step - referenceStep) <= 1e-8f)
								reference = sample;
						}

						string requiredPrecision = ResolveRequiredReferencePrecisionLabel(raw, reference, ObjectSeededRiskEpsilon);
						foreach (ReferenceProbeSample sample in raw)
						{
							double risk = ComputeReferenceDecisionRisk(sample, reference);
							rows.Add(new ReferenceProbeSample(
								sample.AnchorId,
								sample.ObjectId,
								sample.StepLength,
								sample.ReferenceStepLength,
								sample.ProjectedX,
								sample.ProjectedY,
								sample.ProjectedTile,
								sample.ObjectCentroidProjectedX,
								sample.ObjectCentroidProjectedY,
								sample.RadialDistFromObjectCentroid,
								sample.RadialAngleFromObjectCentroid,
								sample.NearestAnchorKind,
								sample.NearestCornerDist,
								sample.NearestEdgeDist,
								sample.SamplePhase,
								sample.NeighborhoodCenterX,
								sample.NeighborhoodCenterY,
								sample.NeighborhoodRadius,
								sample.NeighborhoodDirection,
								sample.OffsetX,
								sample.OffsetY,
								sample.Hit,
								sample.ColliderId,
								sample.DomainId,
								sample.BoundaryEvents,
								sample.PortalEvents,
								sample.HitDistance,
								sample.Normal,
								sample.PathLength,
								risk,
								risk <= ObjectSeededRiskEpsilon,
								requiredPrecision));
						}
					}
				}
			}
		}
		finally
		{
			_rbr.StepsPerRay = savedStepsPerRay;
			_rbr.StepLength = savedStepLength;
			_rbr.MinStepLength = savedMinStepLength;
			_rbr.MaxStepLength = savedMaxStepLength;
		}

		if (rows.Count == 0)
			return false;

		Directory.CreateDirectory(outputDir);
		probeStopwatch.Stop();
		var budget = new ReferenceProbeBudgetMetrics(rows.Count, probeStopwatch.ElapsedMilliseconds, maxCentersUsed, centersSkippedDueToBudget, rows.Count);
		string safeStem = string.IsNullOrWhiteSpace(captureStem) ? "capture" : captureStem.Trim();
		csvPath = Path.Combine(outputDir, safeStem + ".reference_geodesic_probe.csv");
		jsonPath = Path.Combine(outputDir, safeStem + ".reference_geodesic_probe.json");
		File.WriteAllText(csvPath, BuildReferenceProbeCsv(rows));
		File.WriteAllText(jsonPath, BuildReferenceProbeJson(rows, fixtureName, fingerprint.VersionStamp, referenceStep, budget));
		if (EnableCornerTransportProbe)
		{
			File.WriteAllText(Path.Combine(outputDir, safeStem + ".corner_transport_probe.csv"), BuildReferenceProbeCsv(rows));
			File.WriteAllText(Path.Combine(outputDir, safeStem + ".corner_transport_probe.json"), BuildReferenceProbeJson(rows, fixtureName, fingerprint.VersionStamp, referenceStep, budget));
		}
		GD.Print($"[ReferenceGeodesicProbe] written rows={rows.Count} basin={EnableTransportCoherenceBasin} runtime_ms={budget.ProbeRuntimeMs} csv={csvPath} json={jsonPath}");
		return true;
	}

	private ReferenceProbeSample RunReferenceProbeSample(
		PhysicsDirectSpaceState3D space,
		string renderSpaceSource,
		string fixtureName,
		TransportAnchor anchor,
		float stepLength,
		float referenceStep,
		Vector2I filmPixel,
		ReferenceProbeObjectGeometry geom,
		string samplePhase,
		Vector2I neighborhoodCenter,
		int neighborhoodRadius,
		string neighborhoodDirection,
		Vector2I offset,
		int tileWidth,
		Vector3 center,
		float beta,
		float gamma,
		Vector3 bendDir,
		RayBeamRenderer.FieldSourceSnap[] fieldSnaps,
		bool hasSources,
		float pxPerRad,
		in EffectiveConfig cfg)
	{
		_rbr.StepLength = stepLength;
		_rbr.MinStepLength = stepLength;
		_rbr.MaxStepLength = stepLength;
		int requestedSteps = Mathf.CeilToInt(Mathf.Max(0.001f, cfg.Film.MaxDistance) / Mathf.Max(0.0001f, stepLength));
		_rbr.StepsPerRay = Math.Max(1, Math.Min(Math.Max(64, ReferenceGeodesicProbeMaxSteps), requestedSteps));

		Vector2 viewportPixel = FilmPixelToViewportPixel(_cam, filmPixel, _filmWidth, _filmHeight);
		Vector3 origin = _cam.ProjectRayOrigin(viewportPixel);
		Vector3 dir = _cam.ProjectRayNormal(viewportPixel).Normalized();
		int maxSeg = Math.Max(4, ReferenceGeodesicProbeMaxSteps + 4);
		var segs = new RayBeamRenderer.RaySeg[maxSeg];
		var quickRayParams = new PhysicsRayQueryParameters3D
		{
			CollisionMask = cfg.RayMarch.CollisionMask,
			CollideWithBodies = true,
			CollideWithAreas = true,
			HitFromInside = false,
			HitBackFaces = false
		};

		int segCount = _rbr.BuildRaySegmentsCamera_Pass1(
			space,
			ref quickRayParams,
			_cam,
			pxPerRad,
			_cam.GlobalPosition,
			origin,
			dir,
			bendDir,
			center,
			beta,
			gamma,
			fieldSnaps,
			hasSources,
			cfg.Film.MaxDistance,
			segs,
			0,
			segs.Length,
			default,
			false,
			0f,
			true,
			true,
			1,
			0f,
			renderSpaceSource,
			"",
			fixtureName,
			"reference_geodesic_probe",
			out RayBeamRenderer.Pass1HitInfo hitInfo,
			out _,
			out _,
			out _,
			out _,
			out _,
			out _,
			out _,
			out _,
			out _,
			out _,
			out _,
			out _,
			out _,
			out _,
			out _,
			out _,
			out _,
			FrameSnapshotBus.CurrentSnapshot?.CurvatureGrid,
			null);

		float pathLength = 0f;
		if (segCount > 0)
		{
			ref readonly RayBeamRenderer.RaySeg last = ref segs[Math.Min(segCount - 1, segs.Length - 1)];
			pathLength = origin.DistanceTo(last.B);
		}
		int tile = tileWidth > 0 ? Math.Clamp(filmPixel.X / tileWidth, 0, Math.Max(0, (_filmWidth + tileWidth - 1) / tileWidth - 1)) : -1;
		int centroidX = geom?.CentroidPixel.X ?? -1;
		int centroidY = geom?.CentroidPixel.Y ?? -1;
		float radialDist = -1f;
		float radialAngle = 0f;
		if (centroidX >= 0 && centroidY >= 0)
		{
			float dx = filmPixel.X - centroidX;
			float dy = filmPixel.Y - centroidY;
			radialDist = Mathf.Sqrt(dx * dx + dy * dy);
			radialAngle = Mathf.Atan2(dy, dx);
		}
		string nearestAnchorKind = anchor.Mode.ToString();
		float nearestAnchorDist = float.PositiveInfinity;
		float nearestCornerDist = float.PositiveInfinity;
		float nearestEdgeDist = float.PositiveInfinity;
		if (geom != null)
		{
			foreach ((Vector2I Pixel, TransportAnchorMode Mode) candidate in geom.Anchors)
			{
				float d = FilmPixelDistance(filmPixel, candidate.Pixel);
				if (d < nearestAnchorDist)
				{
					nearestAnchorDist = d;
					nearestAnchorKind = candidate.Mode.ToString();
				}
			}
			foreach (Vector2I corner in geom.Corners)
				nearestCornerDist = Math.Min(nearestCornerDist, FilmPixelDistance(filmPixel, corner));
			foreach (Vector2I edge in geom.EdgeMidpoints)
				nearestEdgeDist = Math.Min(nearestEdgeDist, FilmPixelDistance(filmPixel, edge));
		}
		return new ReferenceProbeSample(
			anchor.AnchorId,
			anchor.StableObjectId,
			stepLength,
			referenceStep,
			filmPixel.X,
			filmPixel.Y,
			tile,
			centroidX,
			centroidY,
			radialDist,
			radialAngle,
			nearestAnchorKind,
			float.IsFinite(nearestCornerDist) ? nearestCornerDist : -1f,
			float.IsFinite(nearestEdgeDist) ? nearestEdgeDist : -1f,
			samplePhase,
			neighborhoodCenter.X,
			neighborhoodCenter.Y,
			neighborhoodRadius,
			neighborhoodDirection,
			offset.X,
			offset.Y,
			hitInfo.Found,
			hitInfo.ColliderId,
			anchor.ObserverKind == TransportObserverKind.Domain ? StableReferenceDomainId(anchor.StableObjectId) : -1,
			anchor.Mode == TransportAnchorMode.DomainBoundarySample ? 1 : 0,
			anchor.Mode == TransportAnchorMode.PortalThroatCenter ? 1 : 0,
			hitInfo.Found ? hitInfo.Distance : -1f,
			hitInfo.Found ? hitInfo.Normal : Vector3.Up,
			pathLength,
			0.0,
			true,
			"reference");
	}

	private static Dictionary<string, ReferenceProbeObjectGeometry> BuildReferenceProbeObjectGeometry(SceneTransportFingerprint fingerprint, Camera3D camera, int filmWidth, int filmHeight)
	{
		var map = new Dictionary<string, ReferenceProbeObjectGeometry>(StringComparer.Ordinal);
		foreach (ObjectTransportObserver observer in fingerprint.Observers)
		{
			var geom = new ReferenceProbeObjectGeometry();
			TryProjectWorldToFilmPixel(camera, observer.Centroid, filmWidth, filmHeight, out geom.CentroidPixel);
			foreach (TransportAnchor anchor in observer.AnchorSamples)
			{
				if (!TryProjectWorldToFilmPixel(camera, anchor.WorldPosition, filmWidth, filmHeight, out Vector2I pixel))
					continue;
				geom.Anchors.Add((pixel, anchor.Mode));
				if (anchor.Mode == TransportAnchorMode.AabbCorner || (anchor.Mode == TransportAnchorMode.DomainBoundarySample && anchor.AnchorId.Contains(":corner:", StringComparison.Ordinal)))
					geom.Corners.Add(pixel);
				if (anchor.Mode == TransportAnchorMode.EdgeMidpoint || anchor.AnchorId.Contains(":edge_midpoint:", StringComparison.Ordinal))
					geom.EdgeMidpoints.Add(pixel);
			}
			map[observer.StableObjectId] = geom;
		}
		return map;
	}

	private static List<TransportAnchor> SelectReferenceProbeAnchors(SceneTransportFingerprint fingerprint, Camera3D camera, int filmWidth, int filmHeight, int maxAnchors)
	{
		var selected = new List<TransportAnchor>(Math.Max(1, maxAnchors));
		var seen = new HashSet<string>(StringComparer.Ordinal);

		void AddAnchor(TransportAnchor anchor)
		{
			if (selected.Count >= maxAnchors || anchor == null || !seen.Add(anchor.AnchorId))
				return;
			selected.Add(anchor);
		}

		foreach (ObjectTransportObserver observer in fingerprint.Observers)
		{
			foreach (TransportAnchor anchor in observer.AnchorSamples)
			{
				if (anchor.Mode == TransportAnchorMode.Centroid)
					AddAnchor(anchor);
			}

			var projectedCorners = new List<(TransportAnchor anchor, float score)>();
			foreach (TransportAnchor anchor in observer.AnchorSamples)
			{
				if (anchor.Mode != TransportAnchorMode.AabbCorner && anchor.Mode != TransportAnchorMode.DomainBoundarySample)
					continue;
				if (!TryProjectWorldToFilmPixel(camera, anchor.WorldPosition, filmWidth, filmHeight, out Vector2I pixel))
					continue;
				float dx = pixel.X - filmWidth * 0.5f;
				float dy = pixel.Y - filmHeight * 0.5f;
				projectedCorners.Add((anchor, dx * dx + dy * dy));
			}
			projectedCorners.Sort((a, b) => b.score.CompareTo(a.score));
			for (int i = 0; i < Math.Min(4, projectedCorners.Count); i++)
				AddAnchor(projectedCorners[i].anchor);

			foreach (TransportAnchor anchor in observer.AnchorSamples)
			{
				if (anchor.Mode == TransportAnchorMode.EdgeMidpoint || anchor.AnchorId.Contains(":edge_midpoint:", StringComparison.Ordinal))
					AddAnchor(anchor);
			}

			foreach (TransportAnchor anchor in observer.AnchorSamples)
			{
				if (anchor.Mode == TransportAnchorMode.PrincipalAxis)
					AddAnchor(anchor);
			}
		}

		foreach (ObjectTransportObserver observer in fingerprint.Observers)
		foreach (TransportAnchor anchor in observer.AnchorSamples)
			AddAnchor(anchor);

		return selected;
	}

	private static List<TransportAnchor> SelectCornerTransportProbeAnchors(SceneTransportFingerprint fingerprint, Camera3D camera, int filmWidth, int filmHeight, int maxAnchors)
	{
		var selected = new List<TransportAnchor>(Math.Max(1, maxAnchors));
		var seen = new HashSet<string>(StringComparer.Ordinal);
		void AddAnchor(TransportAnchor anchor)
		{
			if (selected.Count >= maxAnchors || anchor == null || !seen.Add(anchor.AnchorId))
				return;
			selected.Add(anchor);
		}

		foreach (ObjectTransportObserver observer in fingerprint.Observers)
		{
			var candidates = new List<(TransportAnchor Anchor, float Score)>();
			foreach (TransportAnchor anchor in observer.AnchorSamples)
			{
				bool isCornerOrEdge =
					anchor.Mode == TransportAnchorMode.AabbCorner ||
					anchor.Mode == TransportAnchorMode.EdgeMidpoint ||
					anchor.AnchorId.Contains(":corner:", StringComparison.Ordinal) ||
					anchor.AnchorId.Contains(":edge_midpoint:", StringComparison.Ordinal);
				if (!isCornerOrEdge)
					continue;
				if (!TryProjectWorldToFilmPixel(camera, anchor.WorldPosition, filmWidth, filmHeight, out Vector2I pixel))
					continue;
				float dx = pixel.X - filmWidth * 0.5f;
				float dy = pixel.Y - filmHeight * 0.5f;
				float cornerBias = anchor.Mode == TransportAnchorMode.AabbCorner ? filmWidth * filmWidth : 0f;
				candidates.Add((anchor, cornerBias + dx * dx + dy * dy));
			}
			candidates.Sort((a, b) => b.Score.CompareTo(a.Score));
			foreach ((TransportAnchor anchor, _) in candidates)
				AddAnchor(anchor);
		}

		if (selected.Count == 0)
		{
			foreach (ObjectTransportObserver observer in fingerprint.Observers)
			foreach (TransportAnchor anchor in observer.AnchorSamples)
			{
				if (anchor.Mode == TransportAnchorMode.Centroid || anchor.Mode == TransportAnchorMode.PrincipalAxis)
					AddAnchor(anchor);
			}
		}
		return selected;
	}

	private static Vector2I[] BuildReferenceProbeOffsets(Vector2I anchorPixel, Vector2I centroidPixel)
	{
		var offsets = new List<Vector2I>
		{
			new Vector2I(0, 0)
		};
		var seen = new HashSet<(int X, int Y)> { (0, 0) };
		void AddOffset(int x, int y)
		{
			if (seen.Add((x, y)))
				offsets.Add(new Vector2I(x, y));
		}

		Vector2 radial = Vector2.Zero;
		if (centroidPixel.X >= 0 && centroidPixel.Y >= 0)
		{
			radial = new Vector2(anchorPixel.X - centroidPixel.X, anchorPixel.Y - centroidPixel.Y);
			if (radial.LengthSquared() > 1e-6f)
				radial = radial.Normalized();
		}

		int[] radii = { 1, 2, 4, 8, 16 };
		foreach (int r in radii)
		{
			AddOffset(r, 0);
			AddOffset(-r, 0);
			AddOffset(0, r);
			AddOffset(0, -r);
			AddOffset(r, r);
			AddOffset(r, -r);
			AddOffset(-r, r);
			AddOffset(-r, -r);
			if (radial != Vector2.Zero)
			{
				int rx = Mathf.RoundToInt(radial.X * r);
				int ry = Mathf.RoundToInt(radial.Y * r);
				if (rx != 0 || ry != 0)
				{
					AddOffset(rx, ry);
					AddOffset(-rx, -ry);
				}
			}
		}
		return offsets.ToArray();
	}

	private static ReferenceProbeOffsetInfo[] BuildTransportCoherenceBasinOffsets(Vector2I centerPixel, Vector2I centroidPixel, int[] radii)
	{
		var offsets = new List<ReferenceProbeOffsetInfo>
		{
			new ReferenceProbeOffsetInfo(new Vector2I(0, 0), 0, "center")
		};
		var seen = new HashSet<(int X, int Y)> { (0, 0) };
		void AddOffset(int x, int y, int radius, string direction)
		{
			if (seen.Add((x, y)))
				offsets.Add(new ReferenceProbeOffsetInfo(new Vector2I(x, y), radius, direction));
		}

		Vector2 radial = Vector2.Zero;
		if (centroidPixel.X >= 0 && centroidPixel.Y >= 0)
		{
			radial = new Vector2(centerPixel.X - centroidPixel.X, centerPixel.Y - centroidPixel.Y);
			if (radial.LengthSquared() > 1e-6f)
				radial = radial.Normalized();
		}
		Vector2 tangent = radial == Vector2.Zero ? Vector2.Zero : new Vector2(-radial.Y, radial.X);

		foreach (int rawRadius in radii)
		{
			int r = Math.Max(1, rawRadius);
			AddOffset(r, 0, r, "cardinal_east");
			AddOffset(-r, 0, r, "cardinal_west");
			AddOffset(0, r, r, "cardinal_south");
			AddOffset(0, -r, r, "cardinal_north");
			AddOffset(r, r, r, "diagonal_southeast");
			AddOffset(r, -r, r, "diagonal_northeast");
			AddOffset(-r, r, r, "diagonal_southwest");
			AddOffset(-r, -r, r, "diagonal_northwest");
			if (radial != Vector2.Zero)
			{
				int rx = Mathf.RoundToInt(radial.X * r);
				int ry = Mathf.RoundToInt(radial.Y * r);
				if (rx != 0 || ry != 0)
				{
					AddOffset(rx, ry, r, "radial_outward");
					AddOffset(-rx, -ry, r, "radial_inward");
				}
				int tx = Mathf.RoundToInt(tangent.X * r);
				int ty = Mathf.RoundToInt(tangent.Y * r);
				if (tx != 0 || ty != 0)
				{
					AddOffset(tx, ty, r, "tangent_cw");
					AddOffset(-tx, -ty, r, "tangent_ccw");
				}
			}
		}
		return offsets.ToArray();
	}

	private static Vector2I[] BuildCornerTransportProbeOffsets(Vector2I centerPixel, Vector2I centroidPixel, int[] radii, int patchSize)
	{
		var offsets = new List<Vector2I> { Vector2I.Zero };
		var seen = new HashSet<(int X, int Y)> { (0, 0) };
		void AddOffset(int x, int y)
		{
			if (seen.Add((x, y)))
				offsets.Add(new Vector2I(x, y));
		}

		Vector2 radial = Vector2.Zero;
		if (centroidPixel.X >= 0 && centroidPixel.Y >= 0)
		{
			radial = new Vector2(centerPixel.X - centroidPixel.X, centerPixel.Y - centroidPixel.Y);
			if (radial.LengthSquared() > 1e-6f)
				radial = radial.Normalized();
		}
		Vector2 tangent = radial == Vector2.Zero ? Vector2.Zero : new Vector2(-radial.Y, radial.X);

		foreach (int rawRadius in radii)
		{
			int r = Math.Max(1, rawRadius);
			AddOffset(r, 0);
			AddOffset(-r, 0);
			AddOffset(0, r);
			AddOffset(0, -r);
			AddOffset(r, r);
			AddOffset(r, -r);
			AddOffset(-r, r);
			AddOffset(-r, -r);
			if (radial != Vector2.Zero)
			{
				int rx = Mathf.RoundToInt(radial.X * r);
				int ry = Mathf.RoundToInt(radial.Y * r);
				if (rx != 0 || ry != 0)
				{
					AddOffset(rx, ry);
					AddOffset(-rx, -ry);
				}
				int tx = Mathf.RoundToInt(tangent.X * r);
				int ty = Mathf.RoundToInt(tangent.Y * r);
				if (tx != 0 || ty != 0)
				{
					AddOffset(tx, ty);
					AddOffset(-tx, -ty);
				}
			}
		}

		if (patchSize >= 3)
		{
			int size = patchSize % 2 == 0 ? patchSize + 1 : patchSize;
			int half = Math.Min(32, size / 2);
			for (int y = -half; y <= half; y++)
			for (int x = -half; x <= half; x++)
				AddOffset(x, y);
		}
		return offsets.ToArray();
	}

	private static float[] ParseReferenceProbeStepLengths(string raw, float[] fallback)
	{
		var steps = new List<float>();
		foreach (string part in (raw ?? "").Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries))
		{
			if (float.TryParse(part, NumberStyles.Float, CultureInfo.InvariantCulture, out float step) && step > 0f)
				steps.Add(step);
		}
		if (steps.Count == 0)
			steps.AddRange(fallback);
		return steps.Distinct().ToArray();
	}

	private static Vector2I[] ParseCornerTransportProbeManualRois(string raw)
	{
		var rois = new List<Vector2I>();
		foreach (string item in (raw ?? "").Split(';', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries))
		{
			string[] parts = item.Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
			if (parts.Length != 2)
				continue;
			if (int.TryParse(parts[0], NumberStyles.Integer, CultureInfo.InvariantCulture, out int x) &&
				int.TryParse(parts[1], NumberStyles.Integer, CultureInfo.InvariantCulture, out int y))
			{
				rois.Add(new Vector2I(x, y));
			}
		}
		return rois.ToArray();
	}

	private static int ReferenceProbeOffsetRadius(Vector2I offset)
	{
		return Mathf.RoundToInt(Mathf.Sqrt(offset.X * offset.X + offset.Y * offset.Y));
	}

	private static string ClassifyReferenceProbeOffset(Vector2I offset)
	{
		if (offset.X == 0 && offset.Y == 0)
			return "center";
		if (offset.X == 0)
			return offset.Y > 0 ? "cardinal_south" : "cardinal_north";
		if (offset.Y == 0)
			return offset.X > 0 ? "cardinal_east" : "cardinal_west";
		if (offset.X > 0 && offset.Y > 0)
			return "diagonal_southeast";
		if (offset.X > 0 && offset.Y < 0)
			return "diagonal_northeast";
		if (offset.X < 0 && offset.Y > 0)
			return "diagonal_southwest";
		return "diagonal_northwest";
	}

	private static int[] ParseTransportCoherenceBasinRadii(string raw)
	{
		var radii = new List<int>();
		foreach (string part in (raw ?? "").Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries))
		{
			if (int.TryParse(part, NumberStyles.Integer, CultureInfo.InvariantCulture, out int r) && r > 0)
				radii.Add(Math.Min(128, r));
		}
		return radii.Count > 0 ? radii.ToArray() : new[] { 4, 8, 16 };
	}

	private static List<ReferenceProbeSample> SelectTransportCoherenceBasinCenters(List<ReferenceProbeSample> rows, int maxCenters, double epsilon, out int skippedDueToBudget)
	{
		var bestByPixel = new Dictionary<(string AnchorId, int X, int Y), ReferenceProbeSample>();
		foreach (ReferenceProbeSample row in rows)
		{
			if (row.SamplePhase != "anchor_probe")
				continue;
			bool candidate = row.DecisionRisk > epsilon || !row.MatchedReference || (Math.Abs(row.StepLength - 0.00625f) <= 1e-8f && row.DecisionRisk > epsilon);
			if (!candidate)
				continue;
			var key = (row.AnchorId, row.ProjectedX, row.ProjectedY);
			if (!bestByPixel.TryGetValue(key, out ReferenceProbeSample prior) || row.DecisionRisk > prior.DecisionRisk)
				bestByPixel[key] = row;
		}

		List<ReferenceProbeSample> candidates = bestByPixel.Values.ToList();
		candidates.Sort((a, b) => b.DecisionRisk.CompareTo(a.DecisionRisk));
		int take = Math.Min(Math.Max(0, maxCenters), candidates.Count);
		skippedDueToBudget = Math.Max(0, candidates.Count - take);
		if (take < candidates.Count)
			candidates.RemoveRange(take, candidates.Count - take);
		return candidates;
	}

	private static float FilmPixelDistance(Vector2I a, Vector2I b)
	{
		float dx = a.X - b.X;
		float dy = a.Y - b.Y;
		return Mathf.Sqrt(dx * dx + dy * dy);
	}

	private static bool TryProjectWorldToFilmPixel(Camera3D camera, Vector3 worldPosition, int filmWidth, int filmHeight, out Vector2I pixel)
	{
		pixel = new Vector2I(-1, -1);
		if (camera == null || !GodotObject.IsInstanceValid(camera) || camera.IsPositionBehind(worldPosition))
			return false;
		Vector2 viewportSize = camera.GetViewport()?.GetVisibleRect().Size ?? Vector2.Zero;
		if (viewportSize.X <= 0f || viewportSize.Y <= 0f)
			return false;
		Vector2 viewportPixel = camera.UnprojectPosition(worldPosition);
		int x = Mathf.FloorToInt(viewportPixel.X / viewportSize.X * Math.Max(1, filmWidth));
		int y = Mathf.FloorToInt(viewportPixel.Y / viewportSize.Y * Math.Max(1, filmHeight));
		if (x < 0 || y < 0 || x >= filmWidth || y >= filmHeight)
			return false;
		pixel = new Vector2I(x, y);
		return true;
	}

	private static Vector2 FilmPixelToViewportPixel(Camera3D camera, Vector2I filmPixel, int filmWidth, int filmHeight)
	{
		Vector2 viewportSize = camera.GetViewport()?.GetVisibleRect().Size ?? new Vector2(filmWidth, filmHeight);
		float x = (filmPixel.X + 0.5f) / Math.Max(1, filmWidth) * viewportSize.X;
		float y = (filmPixel.Y + 0.5f) / Math.Max(1, filmHeight) * viewportSize.Y;
		return new Vector2(x, y);
	}

	private static double ComputeReferenceDecisionRisk(in ReferenceProbeSample sample, in ReferenceProbeSample reference)
	{
		double risk = 0.0;
		risk += sample.Hit == reference.Hit ? 0.0 : 1.0;
		risk += sample.ColliderId == reference.ColliderId ? 0.0 : 1.0;
		risk += sample.DomainId == reference.DomainId ? 0.0 : 1.0;
		risk += sample.BoundaryEvents == reference.BoundaryEvents ? 0.0 : 1.0;
		risk += sample.PortalEvents == reference.PortalEvents ? 0.0 : 1.0;
		if (sample.Hit && reference.Hit)
		{
			float hitScale = Math.Max(1f, Math.Abs(reference.HitDistance));
			risk += Math.Abs(sample.HitDistance - reference.HitDistance) / hitScale;
			float normalDot = Mathf.Clamp(sample.Normal.Normalized().Dot(reference.Normal.Normalized()), -1f, 1f);
			risk += Math.Acos(normalDot) / Math.PI;
		}
		float pathScale = Math.Max(1f, reference.PathLength);
		risk += Math.Abs(sample.PathLength - reference.PathLength) / pathScale;
		return risk;
	}

	private static string ResolveRequiredReferencePrecisionLabel(List<ReferenceProbeSample> samples, in ReferenceProbeSample reference, double epsilon)
	{
		foreach (ReferenceProbeSample sample in samples)
		{
			if (ComputeReferenceDecisionRisk(sample, reference) <= epsilon)
				return sample.StepLength.ToString("0.######", CultureInfo.InvariantCulture);
		}
		return "reference";
	}

	private static int StableReferenceDomainId(string stableId)
	{
		unchecked
		{
			int hash = 23;
			foreach (char c in stableId ?? "")
				hash = (hash * 31) ^ c;
			return hash & 0x7fffffff;
		}
	}

	private static string BuildReferenceProbeCsv(List<ReferenceProbeSample> rows)
	{
		var sb = new StringBuilder(rows.Count * 160);
		sb.AppendLine("anchor_id,object_id,step_length,reference_step_length,projected_x,projected_y,projected_tile,object_centroid_projected_x,object_centroid_projected_y,radial_dist_from_object_centroid,radial_angle_from_object_centroid,nearest_anchor_kind,nearest_corner_dist,nearest_edge_dist,sample_phase,neighborhood_center_x,neighborhood_center_y,neighborhood_radius,neighborhood_direction,radial_offset_x,radial_offset_y,hit,collider_id,domain_id,boundary_events,portal_events,hit_distance,path_length,normal_x,normal_y,normal_z,decision_risk,matched_reference_decision,required_precision_label");
		foreach (ReferenceProbeSample row in rows)
		{
			sb.Append(JsonEscapeForArtifact(row.AnchorId)).Append(',')
				.Append(JsonEscapeForArtifact(row.ObjectId)).Append(',')
				.Append(FormatJsonFloatForArtifact(row.StepLength)).Append(',')
				.Append(FormatJsonFloatForArtifact(row.ReferenceStepLength)).Append(',')
				.Append(row.ProjectedX).Append(',')
				.Append(row.ProjectedY).Append(',')
				.Append(row.ProjectedTile).Append(',')
				.Append(row.ObjectCentroidProjectedX).Append(',')
				.Append(row.ObjectCentroidProjectedY).Append(',')
				.Append(FormatJsonFloatForArtifact(row.RadialDistFromObjectCentroid)).Append(',')
				.Append(FormatJsonFloatForArtifact(row.RadialAngleFromObjectCentroid)).Append(',')
				.Append(JsonEscapeForArtifact(row.NearestAnchorKind)).Append(',')
				.Append(FormatJsonFloatForArtifact(row.NearestCornerDist)).Append(',')
				.Append(FormatJsonFloatForArtifact(row.NearestEdgeDist)).Append(',')
				.Append(JsonEscapeForArtifact(row.SamplePhase)).Append(',')
				.Append(row.NeighborhoodCenterX).Append(',')
				.Append(row.NeighborhoodCenterY).Append(',')
				.Append(row.NeighborhoodRadius).Append(',')
				.Append(JsonEscapeForArtifact(row.NeighborhoodDirection)).Append(',')
				.Append(row.OffsetX).Append(',')
				.Append(row.OffsetY).Append(',')
				.Append(row.Hit ? "1" : "0").Append(',')
				.Append(row.ColliderId).Append(',')
				.Append(row.DomainId).Append(',')
				.Append(row.BoundaryEvents).Append(',')
				.Append(row.PortalEvents).Append(',')
				.Append(FormatJsonFloatForArtifact(row.HitDistance)).Append(',')
				.Append(FormatJsonFloatForArtifact(row.PathLength)).Append(',')
				.Append(FormatJsonFloatForArtifact(row.Normal.X)).Append(',')
				.Append(FormatJsonFloatForArtifact(row.Normal.Y)).Append(',')
				.Append(FormatJsonFloatForArtifact(row.Normal.Z)).Append(',')
				.Append(FormatJsonFloatForArtifact((float)row.DecisionRisk)).Append(',')
				.Append(row.MatchedReference ? "1" : "0").Append(',')
				.Append(JsonEscapeForArtifact(row.RequiredPrecisionLabel))
				.AppendLine();
		}
		return sb.ToString();
	}

	private static string BuildReferenceProbeJson(List<ReferenceProbeSample> rows, string fixtureName, string fingerprintVersion, float referenceStep, ReferenceProbeBudgetMetrics budget)
	{
		var sb = new StringBuilder(rows.Count * 180);
		sb.Append("{");
		sb.Append("\"fixture\":\"").Append(JsonEscapeForArtifact(fixtureName)).Append("\",");
		sb.Append("\"scene_fingerprint\":\"").Append(JsonEscapeForArtifact(fingerprintVersion)).Append("\",");
		sb.Append("\"reference_step_length\":").Append(FormatJsonFloatForArtifact(referenceStep)).Append(",");
